observe_group = typer.Typer(
    help="Local observation runtime: sources, enable/disable, status, recent, boundaries, health. Privacy-bounded; data stays on device.",
)


@observe_group.command("sources")
def observe_sources_cmd() -> None:
    """List observation sources with scope, consent, mode, redaction, retention, trust."""
    registry = get_observation_source_registry()
    for sid in list_source_ids():
        d = registry.get(sid)
        if not d:
            continue
        impl = "[green]yes[/green]" if d.implemented else "[dim]stub[/dim]"
        console.print(f"[bold]{sid}[/bold]  implemented={impl}")
        console.print(f"  display: {d.display_name}")
        scope = d.allowed_scope_description
        console.print(f"  scope: {scope[:80]}{'...' if len(scope) > 80 else ''}")
        console.print(f"  consent_required={d.consent_required}  mode={d.default_collection_mode.value}")
        red = d.redaction_rules
        console.print(f"  redaction: {red[:60]}{'...' if len(red) > 60 else ''}")
        trust = d.trust_notes
        console.print(f"  retention_days={d.retention_days}  trust: {trust[:50]}{'...' if len(trust) > 50 else ''}")
        console.print("")


@observe_group.command("enable")
def observe_enable_cmd(
    source: str = typer.Option(..., "--source", "-s", help="Source id: file, app, browser, terminal, calendar, teaching"),
    state_dir: str = typer.Option("data/local", "--state-dir", help="Dir containing observation_state.yaml"),
) -> None:
    """Enable an observation source (writes to data/local/observation_state.yaml)."""
    registry = get_observation_source_registry()
    if source not in registry:
        console.print(f"[red]unknown source: {source}[/red]. Use: {', '.join(list_source_ids())}")
        raise typer.Exit(1)
    enabled = enable_source(source, state_dir=Path(state_dir))
    console.print(f"[green]enabled {source}[/green]. enabled_sources={enabled}")


