@observe_group.command("status")
def observe_status_cmd(config: str = typer.Option("configs/settings.yaml", "--config", "-c")) -> None:
    """Show observation status: enabled sources, file roots, event log path."""
    settings = load_settings(config)
    paths_obj = settings.paths
    agent = settings.agent
    state_dir = Path(paths_obj.event_log_dir).parent if getattr(paths_obj, "event_log_dir", None) else Path("data/local")
