@observe_group.command("run")
def observe_run_cmd(config: str = typer.Option("configs/settings.yaml", "--config", "-c")) -> None:
    """
    Run local observation (file metadata only when file enabled). Writes to event log; updates personal graph if configured.
    """
    settings = load_settings(config)
    agent = settings.agent
    if not agent:
        console.print("[red]agent config missing; observation disabled[/red]")
        raise typer.Exit(1)
    state_dir = Path(settings.paths.event_log_dir).parent
    obs_enabled, allowed = effective_observation_config(
        agent.observation_enabled,
        agent.allowed_observation_sources,
        state_dir=state_dir,
    )
    if not obs_enabled:
        console.print("[yellow]observation disabled; use 'observe enable --source file' or set agent.observation_enabled[/yellow]")
        raise typer.Exit(0)
    if "file" not in allowed:
        console.print("[yellow]file not in allowed sources; add with 'observe enable --source file' or agent.allowed_observation_sources[/yellow]")
        raise typer.Exit(0)

    fo = agent.file_observer
    root_paths = (fo.root_paths if fo else []) or []
    if not root_paths:
        console.print("[yellow]no root_paths (agent.file_observer.root_paths); nothing to scan[/yellow]")
        raise typer.Exit(0)

    paths_obj = settings.paths
    log_dir = Path(paths_obj.event_log_dir)
    graph_path = Path(paths_obj.graph_store_path)
    roots = [Path(p).resolve() for p in root_paths if p]
    max_files = fo.max_files_per_scan if fo else 10_000
    exclude = set(fo.exclude_dirs) if fo else {".git", "__pycache__", "node_modules", ".venv"}
    allowed_ext = set(e.lstrip(".").lower() for e in (fo.allowed_extensions or [])) if fo else None
    if allowed_ext is not None and not allowed_ext:
        allowed_ext = None
    graph_update_enabled = fo.graph_update_enabled if fo else True

    events = collect_file_events(
        roots,
        max_files_per_scan=max_files,
        exclude_dirs=exclude,
        allowed_extensions=allowed_ext,
        device_id="",
        tier=agent.observation_tier or 1,
    )
    n_files = len(events)
    if not events:
        console.print("[dim]no file events collected[/dim]")
        raise typer.Exit(0)

    written_path = append_events(log_dir, events)
    console.print(f"[green]events written: {len(events)}[/green] -> {written_path}")

    nodes_delta = 0
    edges_delta = 0
    if graph_update_enabled and graph_path:
        nodes_delta, edges_delta = ingest_file_events(graph_path, events, root_paths=roots)
        console.print(f"[green]graph updated: {nodes_delta} nodes, {edges_delta} edges[/green] -> {graph_path}")

    console.print(
        f"[bold]observe summary:[/bold] files_observed={n_files} events_written={len(events)} "
        f"nodes_created_or_updated={nodes_delta} edges_created={edges_delta}"
    )


app.add_typer(observe_group, name="observe")


live_context_group = typer.Typer(
    help="Live work context: fuse observation + graph into current project/task/mode. Local-only; inspectable.",
)


@live_context_group.command("now")
def live_context_now_cmd(config: str = typer.Option("configs/settings.yaml", "--config", "-c")) -> None:
    """Compute and show current active work context; persist to state and detect transitions."""
    settings = load_settings(config)
    paths_obj = settings.paths
    event_log_dir = getattr(paths_obj, "event_log_dir", "data/local/event_log")
    graph_path = getattr(paths_obj, "graph_store_path", "data/local/work_graph.sqlite")
    root_paths: list[Path] = []
    if settings.agent and settings.agent.file_observer and settings.agent.file_observer.root_paths:
        root_paths = [Path(p).resolve() for p in settings.agent.file_observer.root_paths]
    ctx = fuse_active_context_from_sources(
        event_log_dir,
        graph_store_path=graph_path,
        root_paths=root_paths,
        max_events=200,
    )
    prev = get_live_context_state()
    transitions = detect_transitions(ctx, prev)
    for t in transitions:
        append_transition(t)
    save_live_context_state(ctx)
    console.print(f"[bold]context_id[/bold] {ctx.context_id}")
    console.print(f"  project: {ctx.inferred_project.label if ctx.inferred_project else '—'} (confidence={ctx.inferred_project.confidence if ctx.inferred_project else 0})")
    console.print(f"  work_mode: {ctx.work_mode.value}  activity_mode: {ctx.activity_mode.value}  focus_state: {ctx.focus_state.kind.value if ctx.focus_state else '—'}")
    console.print(f"  confidence: {ctx.overall_confidence}  stale: {ctx.is_stale}")
    if ctx.focus_target:
        console.print(f"  focus: {ctx.focus_target.display_name or ctx.focus_target.value}")
    if transitions:
        console.print(f"  [dim]transitions: {[t.kind.value for t in transitions]}[/dim]")


@live_context_group.command("explain")
def live_context_explain_cmd(config: str = typer.Option("configs/settings.yaml", "--config", "-c")) -> None:
    """Show current context with full evidence and source contributions."""
    settings = load_settings(config)
    paths_obj = settings.paths
    event_log_dir = getattr(paths_obj, "event_log_dir", "data/local/event_log")
    graph_path = getattr(paths_obj, "graph_store_path", "data/local/work_graph.sqlite")
    root_paths: list[Path] = []
    if settings.agent and settings.agent.file_observer and settings.agent.file_observer.root_paths:
        root_paths = [Path(p).resolve() for p in settings.agent.file_observer.root_paths]
    ctx = fuse_active_context_from_sources(
        event_log_dir,
        graph_store_path=graph_path,
        root_paths=root_paths,
        max_events=200,
    )
    console.print("[bold]Active work context[/bold]")
    console.print(f"  context_id: {ctx.context_id}  timestamp: {ctx.timestamp_utc}")
    console.print(f"  inferred_project: {ctx.inferred_project.model_dump() if ctx.inferred_project else None}")
    console.print(f"  inferred_task_family: {ctx.inferred_task_family.model_dump() if ctx.inferred_task_family else None}")
    console.print(f"  work_mode: {ctx.work_mode.value}  overall_confidence: {ctx.overall_confidence}")
    console.print(f"  activity_mode: {ctx.activity_mode.value}  focus_state: {ctx.focus_state.kind.value if ctx.focus_state else '—'}")
    console.print(f"  is_stale: {ctx.is_stale}  last_signal_utc: {ctx.last_signal_utc}")
    if ctx.activity_mode_reason:
        console.print("  [bold]activity_mode_reason:[/bold]")
        console.print(f"    {ctx.activity_mode_reason}")
    if ctx.focus_state_reason:
        console.print("  [bold]focus_state_reason:[/bold]")
        console.print(f"    {ctx.focus_state_reason}")
    console.print("  evidence_summary:")
    for e in ctx.evidence_summary:
        console.print(f"    - {e}")
    console.print("  source_contributions:")
    for c in ctx.source_contributions:
        console.print(f"    - {c.source}: weight={c.weight} {c.evidence_summary}")


@live_context_group.command("memory-explain")
def live_context_memory_explain_cmd(
    project_id: str = typer.Option("", "--project", "-p", help="Project id (default from current context)"),
    session_id: str = typer.Option("", "--session", "-s", help="Session id"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Explain memory context for live context: links and snippets for project/session. M43E–M43H."""
    from workflow_dataset.memory_fusion import explain_live_context_memory
    from workflow_dataset.live_context.state import get_live_context_state
    root = Path(repo).resolve() if repo else None
    if not project_id or not session_id:
        current = get_live_context_state(repo_root=root)
        if current and not project_id and current.inferred_project:
            project_id = current.inferred_project.project_id or getattr(current.inferred_project, "project_id", "")
        if current and not session_id:
            session_id = getattr(current, "session_hint", "") or ""
    expl = explain_live_context_memory(project_id=project_id, session_id=session_id, repo_root=root)
    if json_out:
        console.print(json.dumps(expl, indent=2))
        return
    console.print("[bold]Memory explain[/bold]")
    console.print(f"  project_id={expl.get('project_id')}  session_id={expl.get('session_id')}")
    console.print(f"  memory_links_to_project={expl.get('memory_links_to_project')}  memory_links_to_session={expl.get('memory_links_to_session')}")
    console.print(f"  snippets_returned={expl.get('snippets_returned')}")
    console.print(f"  {expl.get('explanation', '')}")


@live_context_group.command("recent")
def live_context_recent_cmd(
    limit: int = typer.Option(10, "--limit", "-n"),
    config: str = typer.Option("configs/settings.yaml", "--config", "-c"),
) -> None:
    """Show recent session transitions."""
    settings = load_settings(config)
    repo_root = getattr(settings.paths, "event_log_dir", "data/local/event_log")
    base = Path(repo_root).parent if repo_root else None
    transitions = get_recent_transitions(repo_root=base, limit=limit)
    for t in transitions:
        console.print(f"  {t.timestamp_utc}  {t.kind.value}  from={t.from_project or '—'}  to={t.to_project or '—'}")


@live_context_group.command("session-state")
def live_context_session_state_cmd(config: str = typer.Option("configs/settings.yaml", "--config", "-c")) -> None:
    """Show current persisted context and recent transitions (session state)."""
    settings = load_settings(config)
    repo_root = getattr(settings.paths, "event_log_dir", "data/local/event_log")
    base = Path(repo_root).parent if repo_root else None
    current = get_live_context_state(repo_root=base)
    if not current:
        console.print("[dim]No persisted context; run 'live-context now' first.[/dim]")
        return
    console.print("[bold]Current persisted context[/bold]")
    console.print(f"  project: {current.inferred_project.label if current.inferred_project else '—'}")
    console.print(f"  work_mode: {current.work_mode.value}  stale: {current.is_stale}")
    transitions = get_recent_transitions(repo_root=base, limit=5)
    console.print(f"  recent_transitions: {len(transitions)}")
    for t in transitions:
        console.print(f"    {t.kind.value} -> {t.to_project or '—'}")


