def _live_workflow_root(repo_root: str = "") -> Path | None:
    return Path(repo_root).resolve() if repo_root else None


@live_workflow_group.command("now")
def live_workflow_now_cmd(
    goal: str = typer.Option("", "--goal", "-g", help="Goal or routine id to drive the workflow"),
    routine_id: str = typer.Option("", "--routine", "-r", help="Routine id (alternative to --goal)"),
    bundle: str = typer.Option("", "--bundle", "-b", help="Workflow bundle id (reusable workflow)"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
    save: bool = typer.Option(True, "--save/--no-save", help="Persist as current run"),
) -> None:
    """Generate supervised live workflow from goal/routine/bundle; optionally save as current run."""
    from workflow_dataset.live_workflow.step_generator import generate_live_workflow_steps
    from workflow_dataset.live_workflow.state import save_live_workflow_run
    root = _live_workflow_root(repo_root)
    run = generate_live_workflow_steps(
        goal_text=goal,
        routine_id=routine_id,
        bundle_id=bundle,
        project_hint="",
        session_hint="",
        repo_root=root,
    )
    if save:
        save_live_workflow_run(run, repo_root=root)
    if json_out:
        console.print(run.model_dump_json(indent=2))
    else:
        console.print(f"[bold]Live workflow[/bold] run_id={run.run_id}  state={run.state.value}")
        console.print(f"  goal={run.goal_text or '(none)'}  plan_ref={run.plan_ref}  steps={len(run.steps)}")
        if run.blocked_step:
            console.print(f"  [yellow]blocked[/yellow] step={run.blocked_step.step_index}  reason={run.blocked_step.blocked_reason}")
        console.print(f"  escalation: {run.escalation_path_summary}")


@live_workflow_group.command("steps")
def live_workflow_steps_cmd(
    latest: bool = typer.Option(True, "--latest/--no-latest", help="Use latest saved run"),
    goal: str = typer.Option("", "--goal", "-g", help="If not --latest, generate from this goal"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Show step sequence for current or generated live workflow."""
    from workflow_dataset.live_workflow.step_generator import generate_live_workflow_steps
    from workflow_dataset.live_workflow.state import get_live_workflow_run
    root = _live_workflow_root(repo_root)
    run = None
    if latest:
        run = get_live_workflow_run(repo_root=root)
    if run is None and goal:
        run = generate_live_workflow_steps(goal_text=goal, repo_root=root)
    if run is None:
        console.print("[dim]No run. Use 'live-workflow now --goal <goal>' or pass --goal here.[/dim]")
        raise typer.Exit(0)
    if json_out:
        console.print(run.model_dump_json(indent=2))
    else:
        console.print(f"[bold]Steps[/bold] run_id={run.run_id}  current={run.current_step_index}  next={run.next_step_index}")
        for s in run.steps:
            mark = "->" if s.step_index == run.current_step_index else "  "
            console.print(f"  {mark} [{s.step_index}] {s.label}  tier={s.escalation_tier.value}")


@live_workflow_group.command("escalate")
def live_workflow_escalate_cmd(
    latest: bool = typer.Option(True, "--latest/--no-latest", help="Use latest saved run"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Show escalation handoff for current step (next tier)."""
    from workflow_dataset.live_workflow.state import get_live_workflow_run
    from workflow_dataset.live_workflow.escalation import next_escalation_tier, build_handoff_for_tier
    root = _live_workflow_root(repo_root)
    run = get_live_workflow_run(repo_root=root)
    if not run or not run.steps:
        console.print("[dim]No run or no steps. Run 'live-workflow now --goal <goal>' first.[/dim]")
        raise typer.Exit(0)
    idx = min(run.current_step_index, len(run.steps) - 1)
    step = run.steps[idx]
    next_tier = next_escalation_tier(run.current_escalation_tier)
    if not next_tier:
        console.print("[dim]Already at top escalation tier.[/dim]")
        raise typer.Exit(0)
    handoff = build_handoff_for_tier(next_tier, step, run)
    if json_out:
        import json
        console.print(json.dumps({"next_tier": next_tier.value, "handoff": handoff}, indent=2))
    else:
        console.print(f"[bold]Escalate[/bold] current_tier={run.current_escalation_tier.value} -> next_tier={next_tier.value}")
        console.print(f"  handoff_target={handoff.get('handoff_target')}  params={handoff.get('handoff_params', {})}")


@live_workflow_group.command("preview-next")
def live_workflow_preview_next_cmd(
    latest: bool = typer.Option(True, "--latest/--no-latest", help="Use latest saved run"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Preview next recommended supervised assist (current step + hint or next step)."""
    from workflow_dataset.live_workflow.state import get_live_workflow_run
    root = _live_workflow_root(repo_root)
    run = get_live_workflow_run(repo_root=root)
    if not run:
        console.print("[dim]No run. Use 'live-workflow now --goal <goal>' first.[/dim]")
        raise typer.Exit(0)
    current = run.steps[run.current_step_index] if run.steps and run.current_step_index < len(run.steps) else None
    next_step = run.steps[run.next_step_index] if run.next_step_index is not None and run.steps and run.next_step_index < len(run.steps) else None
    out = {
        "run_id": run.run_id,
        "state": run.state.value,
        "current_step": {"index": run.current_step_index, "label": current.label if current else None, "hint": current.hint_text if current else None},
        "next_step": {"index": run.next_step_index, "label": next_step.label if next_step else None} if next_step else None,
        "blocked": run.blocked_step.model_dump() if run.blocked_step else None,
        "recommended_assist": current.hint_text if current else "Add a goal to get steps.",
    }
    if json_out:
        import json
        console.print(json.dumps(out, indent=2))
    else:
        console.print("[bold]Preview next[/bold]")
        console.print(f"  run_id={run.run_id}  state={run.state.value}")
        console.print(f"  current: [{run.current_step_index}] {current.label if current else '—'}  hint={current.hint_text if current else '—'}")
        if next_step:
            console.print(f"  next: [{run.next_step_index}] {next_step.label}")
        if run.blocked_step:
            console.print(f"  [yellow]blocked[/yellow] {run.blocked_step.blocked_reason}")
        console.print(f"  recommended_assist: {out['recommended_assist']}")


@live_workflow_group.command("bundles")
def live_workflow_bundles_cmd(
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """List reusable workflow bundles (data/local/live_workflow/bundles/)."""
    from workflow_dataset.live_workflow.bundles import list_bundles
    root = _live_workflow_root(repo_root)
    bundles = list_bundles(repo_root=root)
    if json_out:
        import json
        console.print(json.dumps([b.model_dump() for b in bundles], indent=2))
    else:
        console.print("[bold]Workflow bundles[/bold]")
        for b in bundles:
            console.print(f"  {b.bundle_id}: {b.label}  goal_template={b.goal_template[:40] if b.goal_template else '—'}  alternates={len(b.alternate_goals)}")


@live_workflow_group.command("stall")
def live_workflow_stall_cmd(
    latest: bool = typer.Option(True, "--latest/--no-latest", help="Use latest saved run"),
    idle_minutes: float = typer.Option(10.0, "--idle-minutes", help="Idle threshold in minutes to consider stalled"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Check for stall and show recovery paths + alternate paths."""
    from workflow_dataset.live_workflow.state import get_live_workflow_run
    from workflow_dataset.live_workflow.stall import detect_stall, suggest_recovery_paths
    from workflow_dataset.live_workflow.models import AlternatePathRecommendation
    root = _live_workflow_root(repo_root)
    run = get_live_workflow_run(repo_root=root)
    if not run:
        console.print("[dim]No run. Use 'live-workflow now --goal <goal>' first.[/dim]")
        raise typer.Exit(0)
    idle_seconds = max(60.0, idle_minutes * 60.0)
    result = detect_stall(run, idle_threshold_seconds=idle_seconds)
    result.suggested_recovery_paths = suggest_recovery_paths(run, result, root)
    if run.alternate_path_recommendations:
        result.alternate_paths = [AlternatePathRecommendation.model_validate(a) for a in run.alternate_path_recommendations]
    if json_out:
        import json
        console.print(json.dumps(result.model_dump(), indent=2))
    else:
        console.print("[bold]Stall check[/bold]")
        console.print(f"  stalled={result.stalled}  idle_seconds={int(result.idle_seconds)}  threshold={int(idle_seconds)}s")
        console.print(f"  reason: {result.reason}")
        if result.suggested_recovery_paths:
            console.print("  [bold]Recovery paths:[/bold]")
            for p in result.suggested_recovery_paths:
                console.print(f"    - {p.action_label}: {p.reason[:60]}")
        if result.alternate_paths:
            console.print("  [bold]Alternate paths:[/bold]")
            for a in result.alternate_paths[:5]:
                console.print(f"    - {a.label}: {a.reason[:50]}")


@live_workflow_group.command("explain-escalation")
def live_workflow_explain_escalation_cmd(
    from_tier: str = typer.Option("hint_only", "--from", help="Current escalation tier"),
    to_tier: str = typer.Option("action_card_suggestion", "--to", help="Target escalation tier"),
    reason: str = typer.Option("user_requested", "--reason", help="Reason code: user_requested, stall_detected, blocked_step"),
    step_label: str = typer.Option("", "--step-label", help="Current step label for message"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Show operator-facing explanation of why escalation happened and what to do next."""
    from workflow_dataset.live_workflow.escalation import explain_escalation
    from workflow_dataset.live_workflow.models import EscalationTier
    try:
        ft = EscalationTier(from_tier)
        tt = EscalationTier(to_tier)
    except ValueError:
        console.print("[red]Invalid tier. Use: hint_only, action_card_suggestion, draft_handoff_prep, planner_goal_prefill, simulated_execution_handoff, review_approval_routing[/red]")
        raise typer.Exit(1)
    expl = explain_escalation(ft, tt, reason_code=reason, step_label=step_label)
    if json_out:
        console.print(expl.model_dump_json(indent=2))
    else:
        console.print("[bold]Why escalation happened[/bold]")
        console.print(f"  {expl.operator_message}")
        console.print(f"  [bold]Suggested action:[/bold] {expl.suggested_action}")


