@automations_group.command("list")
def automations_list_cmd(
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """List automation definitions (triggers and recurring workflows)."""
    from workflow_dataset.automations.store import list_trigger_ids, list_workflow_ids, get_trigger, get_workflow
    root = Path(repo_root).resolve() if repo_root else None
    tids = list_trigger_ids(repo_root=root)
    wids = list_workflow_ids(repo_root=root)
