@automations_group.command("guardrails")
def automations_guardrails_cmd(
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """List guardrail profiles and show active profile."""
    from workflow_dataset.automations.store import list_guardrail_profile_ids, get_guardrail_profile, get_active_guardrail_profile
    root = Path(repo_root).resolve() if repo_root else None
    pids = list_guardrail_profile_ids(repo_root=root)
