@operator_mode_group.command("status")
def operator_mode_status_cmd(
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Show operator mode status: pause state, revocation count, responsibilities/bundles counts."""
    from workflow_dataset.operator_mode import load_pause_state, load_suspension_revocation_state, list_responsibility_ids, list_bundle_ids
    root = Path(repo_root).resolve() if repo_root else None
    pause = load_pause_state(repo_root=root)
    state = load_suspension_revocation_state(repo_root=root)
    resp_ids = list_responsibility_ids(repo_root=root)
    bundle_ids = list_bundle_ids(repo_root=root)
    if json_out:
        import json
        console.print(json.dumps({
            "pause_kind": pause.kind.value,
            "pause_reason": pause.reason,
            "suspended_count": len(state.suspended_ids),
            "revoked_count": len(state.revoked_ids),
            "responsibilities_count": len(resp_ids),
            "bundles_count": len(bundle_ids),
        }, indent=2))
    else:
        console.print("[bold]Operator mode status[/bold]")
        console.print(f"  pause={pause.kind.value}  reason={pause.reason or '—'}")
        console.print(f"  suspended={len(state.suspended_ids)}  revoked={len(state.revoked_ids)}")
        console.print(f"  responsibilities={len(resp_ids)}  bundles={len(bundle_ids)}")


@operator_mode_group.command("bundles")
def operator_mode_bundles_cmd(
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    create: str = typer.Option("", "--create", "-c", help="Create bundle: --create bundle_id (use --label for name)"),
    label: str = typer.Option("", "--label", "-l", help="Label for new bundle"),
    add: str = typer.Option("", "--add", "-a", help="Add responsibility to bundle: --add resp_id (use bundle id as first arg or --bundle)"),
    bundle_id: str = typer.Option("", "--bundle", "-b", help="Bundle id for --add"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """List responsibility bundles; or create one (--create id --label Name); or add responsibility (--add resp_id --bundle id)."""
    from workflow_dataset.operator_mode import list_bundle_ids, get_bundle, create_bundle, add_responsibility_to_bundle
    root = Path(repo_root).resolve() if repo_root else None
    if create:
        b = create_bundle(create, label or create, repo_root=root)
        console.print(f"[green]Created bundle[/green] {b.bundle_id}" + (f"  label={b.label}" if b.label else ""))
        return
    if add:
        if not bundle_id:
            console.print("[red]Use --bundle <id> with --add[/red]")
            raise typer.Exit(1)
        bid = bundle_id
        b = add_responsibility_to_bundle(bid, add, repo_root=root)
        if b:
            console.print(f"[green]Added[/green] {add} to bundle {bid}")
        else:
            console.print(f"[red]Bundle not found: {bid}[/red]")
            raise typer.Exit(1)
        return
    ids = list_bundle_ids(repo_root=root)
    if json_out:
        import json
        console.print(json.dumps([get_bundle(i, root).model_dump() if get_bundle(i, root) else {"bundle_id": i} for i in ids], indent=2))
    else:
        console.print("[bold]Responsibility bundles[/bold]")
        for bid in ids:
            b = get_bundle(bid, root)
            console.print(f"  {bid}: {b.label if b else '—'}  responsibilities={len(b.responsibility_ids) if b else 0}")


@operator_mode_group.command("pause")
def operator_mode_pause_cmd(
    emergency: bool = typer.Option(False, "--emergency", "-e", help="Emergency pause: all work stops"),
    safe: bool = typer.Option(False, "--safe", "-s", help="Safe pause: only allowed responsibilities continue"),
    clear: bool = typer.Option(False, "--clear", "-c", help="Clear pause"),
    reason: str = typer.Option("", "--reason", "-r", help="Reason for pause"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Set emergency pause (all stop), safe pause, or clear pause."""
    from workflow_dataset.operator_mode import set_emergency_pause, set_safe_pause, clear_pause
    root = Path(repo_root).resolve() if repo_root else None
    if clear:
        s = clear_pause(repo_root=root)
        console.print("[green]Pause cleared.[/green]")
    elif emergency:
        s = set_emergency_pause(reason=reason, repo_root=root)
        console.print(f"[yellow]Emergency pause set.[/yellow]  reason={s.reason or '—'}")
    elif safe:
        s = set_safe_pause(reason=reason, repo_root=root)
        console.print(f"[yellow]Safe pause set.[/yellow]  reason={s.reason or '—'}")
    else:
        console.print("Use --emergency, --safe, or --clear")
        raise typer.Exit(1)
    if json_out:
        import json
        console.print(json.dumps(s.model_dump(), indent=2))


@operator_mode_group.command("revoke")
def operator_mode_revoke_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Responsibility id or bundle id to revoke"),
    bundle: bool = typer.Option(False, "--bundle", "-b", help="Revoke entire bundle"),
    reason: str = typer.Option("", "--reason", "-r", help="Reason for revocation"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Revoke a responsibility or a full bundle (--bundle)."""
    from workflow_dataset.operator_mode import revoke_responsibility, revoke_bundle
    root = Path(repo_root).resolve() if repo_root else None
    if bundle:
        rec = revoke_bundle(id, reason=reason, repo_root=root)
        if not rec:
            console.print(f"[red]Bundle not found or empty: {id}[/red]")
            raise typer.Exit(1)
        console.print(f"[yellow]Revoked bundle[/yellow] {id}  responsibilities={len(rec.revoked_responsibility_ids)}")
    else:
        rec = revoke_responsibility(id, reason=reason, repo_root=root)
        console.print(f"[yellow]Revoked responsibility[/yellow] {id}")
    if json_out:
        import json
        console.print(json.dumps(rec.model_dump(), indent=2))


