@continuity_confidence_group.command("status")
def continuity_confidence_status_cmd(
    bundle: str = typer.Option("latest", "--bundle", "-b", help="Bundle ref: latest or bundle_id"),
    repo_root: str = typer.Option("", "--repo-root"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Current post-restore confidence, downgraded warnings, operator-mode readiness."""
    from workflow_dataset.continuity_confidence import continuity_confidence_slice
    import json as _json
    root = Path(repo_root).resolve() if repo_root else None
    try:
        slice_data = continuity_confidence_slice(repo_root=root)
    except Exception as e:
        slice_data = {"error": str(e)}
    if json_out:
        console.print(_json.dumps(slice_data, indent=2))
        return
    if slice_data.get("error"):
        console.print("[red]" + slice_data["error"] + "[/red]")
        raise SystemExit(1)
    console.print("[bold]Continuity confidence[/bold]")
    console.print("  classification: " + str(slice_data.get("current_post_restore_confidence", "—")))
    console.print("  label: " + str(slice_data.get("current_post_restore_confidence_label", "—")))
    console.print("  score: " + str(slice_data.get("current_post_restore_confidence_score", "—")))
    console.print("  operator_mode_ready: " + str(slice_data.get("operator_mode_readiness_after_restore", False)))
    if slice_data.get("downgraded_runtime_profile_warnings"):
        console.print("  downgraded: " + "; ".join(slice_data["downgraded_runtime_profile_warnings"][:3]))
    console.print("  next_review: " + str(slice_data.get("next_recommended_post_restore_review", "")))


