queue_group = typer.Typer(
    help="Unified work queue: list, view by mode (focus|review|operator|wrap-up), summary. M36H.1.",
)
app.add_typer(queue_group, name="queue")


@queue_group.command("list")
def queue_list_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    limit: int = typer.Option(50, "--limit", "-n"),
) -> None:
    """List unified queue items (prioritized; from review_studio + automation_inbox)."""
    from workflow_dataset.unified_queue import build_unified_queue, rank_unified_queue
    root = Path(repo).resolve() if repo else None
    items = build_unified_queue(repo_root=root, limit=limit)
    items = rank_unified_queue(items, repo_root=root)
    if not items:
        console.print("[dim]No queue items. Review studio and automation inbox are empty.[/dim]")
        return
    console.print(f"[bold]Unified queue[/bold]  count={len(items)}")
