@queue_group.command("profile")
def queue_profile_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    mode: str = typer.Option("", "--mode", "-m", help="work_mode or profile_id: focus | review | operator | wrap_up | default"),
    json_out: bool = typer.Option(False, "--json", help="Output as JSON"),
) -> None:
    """Show calm queue profile (and noise ceiling) for current or given mode. M37H.1."""
    from workflow_dataset.signal_quality.attention import get_protected_focus
    from workflow_dataset.signal_quality.profiles import get_default_profiles, get_profile_for_role_mode, get_noise_ceiling_for
    root = Path(repo).resolve() if repo else None
    focus = get_protected_focus(root)
    work_mode = mode or focus.work_mode or "default"
    profile = get_profile_for_role_mode(work_mode, profile_id_override=mode or "")
    noise_ceiling, max_visible = get_noise_ceiling_for(work_mode)
    if json_out:
        out = {
            "work_mode": work_mode,
            "profile_id": profile.profile_id,
            "label": profile.label,
            "max_visible": profile.max_visible,
            "max_suggestions_per_hour": profile.max_suggestions_per_hour,
            "noise_ceiling": profile.noise_ceiling,
            "interrupt_threshold": profile.interrupt_threshold,
            "description": profile.description,
            "noise_ceiling_for_mode": noise_ceiling,
            "max_visible_for_mode": max_visible,
        }
        console.print(json.dumps(out, indent=2))
        return
    console.print(f"[bold]Calm queue profile[/bold]  mode={work_mode}  profile={profile.profile_id}  {profile.label}")
    console.print(f"  max_visible={profile.max_visible}  max_suggestions_per_hour={profile.max_suggestions_per_hour}")
    console.print(f"  noise_ceiling={profile.noise_ceiling}  interrupt_threshold={profile.interrupt_threshold}")
    console.print(f"  [dim]{profile.description}[/dim]")


