@gates_group.command("list")
def gates_list_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    status: str = typer.Option("", "--status", help="Filter: pending, approved, rejected, deferred"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List sensitive action gates."""
    from workflow_dataset.sensitive_gates import load_gates
    root = Path(repo).resolve() if repo else None
    gates = load_gates(repo_root=root)
    if status:
        gates = [g for g in gates if g.status == status]
    if json_out:
        import json
        console.print(json.dumps([g.to_dict() for g in gates], indent=2))
        return
    for g in gates:
        console.print(f"  {g.gate_id}  {g.action_kind}  {g.status}  {g.candidate.get('label', '')[:50]}")


@gates_group.command("show")
def gates_show_cmd(
    id: str = typer.Option(..., "--id", help="Gate ID"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show one gate by ID."""
    from workflow_dataset.sensitive_gates import get_gate
    root = Path(repo).resolve() if repo else None
    gate = get_gate(id, root)
    if not gate:
        console.print(f"[red]Gate not found: {id}[/red]")
        raise SystemExit(1)
    if json_out:
        import json
        console.print(json.dumps(gate.to_dict(), indent=2))
        return
    console.print(f"gate_id: {gate.gate_id}")
    console.print(f"action_kind: {gate.action_kind}  status: {gate.status}")
    console.print(f"label: {gate.candidate.get('label', '')}")
    if gate.review_rationale:
        console.print(f"decision: {gate.review_rationale.decision}  rationale: {gate.review_rationale.rationale[:80]}")


