@audit_group.command("summary")
def audit_summary_cmd(
    project: str = typer.Option("", "--project", "-p", help="Project ID for summary"),
    routine: str = typer.Option("", "--routine", help="Routine ID for summary"),
    tier: str = typer.Option("", "--tier", "-t", help="Authority tier ID for summary (e.g. commit_or_send_candidate)"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Audit summary by project, routine, or authority tier (M35L.1)."""
    from workflow_dataset.sensitive_gates import (
        build_audit_summary_by_project,
        build_audit_summary_by_routine,
        build_audit_summary_by_authority_tier,
    )
    root = Path(repo).resolve() if repo else None
    if project:
        summary = build_audit_summary_by_project(project, repo_root=root)
    elif routine:
        summary = build_audit_summary_by_routine(routine, repo_root=root)
    elif tier:
        summary = build_audit_summary_by_authority_tier(tier, repo_root=root)
    else:
        console.print("[red]Specify one of: --project, --routine, --tier[/red]")
        raise SystemExit(1)
    if json_out:
        import json
        console.print(json.dumps(summary.to_dict(), indent=2))
        return
    console.print(f"[bold]Audit summary[/bold]  scope={summary.scope}  value={summary.scope_value}")
    console.print(f"  total_entries={summary.total_entries}  approved={summary.approved_count}  rejected={summary.rejected_count}  deferred={summary.deferred_count}")
    console.print(f"  by_action_kind={summary.by_action_kind}  exec_success={summary.execution_success_count}  failed={summary.execution_failed_count}  blocked={summary.execution_blocked_count}  rollback={summary.rollback_count}")
    console.print(f"  generated_at={summary.generated_at_utc[:19]}")


