@state_group.command("maintenance-profiles")
def state_maintenance_profiles_cmd(
    profile_id: str = typer.Option("", "--profile", "-p", help="Show single profile by id (light | balanced | aggressive)"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List maintenance profiles (light, balanced, aggressive) or show one. M37L.1."""
    from workflow_dataset.state_durability.profiles import get_maintenance_profile, list_maintenance_profiles
    if profile_id:
        profile = get_maintenance_profile(profile_id)
        if json_out:
            import json
            console.print(json.dumps(profile.to_dict(), indent=2))
            return
        console.print("Profile: " + profile.label + " (" + profile.profile_id + ")")
        console.print("  " + (profile.description or ""))
        for p in profile.policies:
            console.print("  " + p.subsystem_id + ": retain_days=" + str(p.retain_days) + "  max_before_summarize=" + str(p.max_items_before_summarize))
        return
    profiles = list_maintenance_profiles()
    if json_out:
        import json
        console.print(json.dumps({"profiles": [pr.to_dict() for pr in profiles]}, indent=2))
        return
    console.print("Maintenance profiles:")
    for pr in profiles:
        console.print("  " + pr.profile_id + ": " + pr.label + " — " + (pr.description or "")[:55])


