@workflow_episodes_group.command("explain")
def workflow_episodes_explain_cmd(
    latest: bool = typer.Option(True, "--latest/--id", help="Use latest (current) episode"),
    id: str = typer.Option("", "--id", "-i", help="Episode id (if not --latest)"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Explain current or specified workflow episode (evidence, project, confidence)."""
    from workflow_dataset.workflow_episodes.store import get_current_episode, list_recent_episodes
    from workflow_dataset.workflow_episodes.explain import build_episode_explanation
    root = Path(repo_root).resolve() if repo_root else None
    episode = None
    if latest or not id:
        episode = get_current_episode(root)
    elif id:
        for e in list_recent_episodes(root, limit=100):
            if e.episode_id == id:
                episode = e
                break
    if not episode:
        console.print("[red]No episode found[/red]")
        raise typer.Exit(1)
    expl = build_episode_explanation(episode)
    if json_out:
        console.print(json.dumps(expl, indent=2))
    else:
        console.print(f"[bold]Episode {expl['episode_id']}[/bold]")
        console.print(f"  {expl['summary']}")
        console.print(f"  project: {expl['project']}  confidence: {expl['confidence']}")
        for ev in expl.get("evidence", [])[:10]:
            console.print(f"  evidence: {ev}")


@workflow_episodes_group.command("stage")
def workflow_episodes_stage_cmd(
    latest: bool = typer.Option(True, "--latest/--id", help="Use latest (current) episode"),
    id: str = typer.Option("", "--id", "-i", help="Episode id (if not --latest)"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Show workflow stage and evidence for current or specified episode."""
    from workflow_dataset.workflow_episodes.store import get_current_episode, list_recent_episodes
    from workflow_dataset.workflow_episodes.explain import build_stage_explanation, build_handoff_gaps_explanation
    root = Path(repo_root).resolve() if repo_root else None
    episode = None
    if latest or not id:
        episode = get_current_episode(root)
    elif id:
        for e in list_recent_episodes(root, limit=100):
            if e.episode_id == id:
                episode = e
                break
    if not episode:
        console.print("[red]No episode found[/red]")
        raise typer.Exit(1)
    stage_expl = build_stage_explanation(episode)
    gaps_expl = build_handoff_gaps_explanation(episode, repo_root=str(root) if root else None)
    if json_out:
        out = {"stage": stage_expl, "handoff_gaps": gaps_expl}
        from workflow_dataset.workflow_episodes.explain import build_advance_stall_explanation
        out["advance_stall"] = build_advance_stall_explanation(episode)
        out["episode_type"] = getattr(episode, "episode_type", "") or "unknown"
        out["episode_type_evidence"] = list(getattr(episode, "episode_type_evidence", []))
        console.print(json.dumps(out, indent=2))
    else:
        console.print(f"[bold]Stage[/bold] {stage_expl['stage']}")
        console.print(f"  {stage_expl['summary']}")
        ep_type = getattr(episode, "episode_type", "") or "unknown"
        console.print(f"  [bold]Episode type[/bold] {ep_type}")
        console.print("[bold]Handoff gaps[/bold]")
        for g in gaps_expl.get("gaps", []):
            console.print(f"  {g['kind']}: {g['summary']}")
            if g.get("suggested_action"):
                console.print(f"    -> {g['suggested_action']}")
        from workflow_dataset.workflow_episodes.explain import build_advance_stall_explanation
        adv = build_advance_stall_explanation(episode)
        if adv.get("why_advanced"):
            console.print("[bold]Why advanced[/bold]")
            for r in adv["why_advanced"]:
                console.print(f"  {r}")
        if adv.get("why_stalled"):
            console.print("[bold]Why stalled[/bold]")
            for r in adv["why_stalled"]:
                console.print(f"  {r}")


@workflow_episodes_group.command("transition-map")
def workflow_episodes_transition_map_cmd(
    latest: bool = typer.Option(True, "--latest/--id", help="Use latest (current) episode"),
    id: str = typer.Option("", "--id", "-i", help="Episode id (if not --latest)"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
    explain: bool = typer.Option(True, "--explain/--no-explain", help="Include advance/stall explanation"),
) -> None:
    """Show transition map for current stage and optional advance/stall explanation."""
    from workflow_dataset.workflow_episodes.store import get_current_episode, list_recent_episodes
    from workflow_dataset.workflow_episodes.explain import build_transition_map_output, build_advance_stall_explanation
    root = Path(repo_root).resolve() if repo_root else None
    episode = None
    if latest or not id:
        episode = get_current_episode(root)
    elif id:
        for e in list_recent_episodes(root, limit=100):
            if e.episode_id == id:
                episode = e
                break
    if not episode:
        console.print("[red]No episode found[/red]")
        raise typer.Exit(1)
    out = build_transition_map_output(episode)
    if explain:
        out["advance_stall"] = build_advance_stall_explanation(episode)
    if json_out:
        console.print(json.dumps(out, indent=2))
    else:
        console.print(f"[bold]Current stage[/bold] {out['current_stage']}")
        console.print(f"[bold]Episode type[/bold] {out['episode_type']}")
        console.print("[bold]Next stages[/bold]")
        for ns in out.get("next_stages", []):
            console.print(f"  -> {ns.get('to_stage')}: {ns.get('description', '')}")
        if explain and out.get("advance_stall"):
            adv = out["advance_stall"]
            if adv.get("why_advanced"):
                console.print("[bold]Why advanced[/bold]")
                for r in adv["why_advanced"]:
                    console.print(f"  {r}")
            if adv.get("why_stalled"):
                console.print("[bold]Why stalled[/bold]")
                for r in adv["why_stalled"]:
                    console.print(f"  {r}")


@app.command()
def suggest(config: str = typer.Option("configs/settings.yaml", "--config", "-c")) -> None:
    """
    Run the interpretation loop: load local events, infer routines, generate suggestions.
    Writes routines to the personal graph and suggestions to the local store.
    No actions are executed; suggestion-only.
    """
    settings = load_settings(config)
    paths_obj = settings.paths
    log_dir = Path(paths_obj.event_log_dir)
    graph_path = Path(paths_obj.graph_store_path)

    events = load_all_events(log_dir, source_filter="file", max_events=5000)
    if not events:
        console.print(
            "[dim]no file events in event log; run 'observe' first or add root_paths[/dim]")
        raise typer.Exit(0)

    root_paths: list[Path] = []
    if settings.agent and settings.agent.file_observer and settings.agent.file_observer.root_paths:
        root_paths = [Path(p).resolve()
                      for p in settings.agent.file_observer.root_paths]

    # Infer routines (deterministic heuristics)
    routines = detect_routines(
        events, root_paths=root_paths if root_paths else None)
    n_routines = len(routines)
    if routines:
        n_persisted = persist_routines(graph_path, routines)
        console.print(
            f"[green]routines inferred: {n_routines}[/green] (persisted {n_persisted} to graph)")
    else:
        console.print("[dim]no routines inferred from events[/dim]")

    # Generate and persist suggestions
    suggestions = generate_suggestions(routines)
    if suggestions:
        persist_suggestions(graph_path, suggestions)
        console.print(
            f"[green]suggestions generated: {len(suggestions)}[/green] -> {graph_path}")
        for s in suggestions[:5]:
            console.print(f"  [bold]{s.title}[/bold]")
            console.print(f"  [dim]{s.description}[/dim]")
    else:
        console.print(
            "[dim]no suggestions generated (need more routine evidence)[/dim]")

    # Summary
    pending = load_suggestions(graph_path, status_filter="pending", limit=100)
    console.print(
        f"[bold]suggest summary:[/bold] events_loaded={len(events)} routines={n_routines} suggestions={len(suggestions)} pending_total={len(pending)}")


