@demo_group.command("live-adapter-snapshot")
def demo_live_adapter_snapshot_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o"),
    timeout_sec: float = typer.Option(5.0, "--timeout", "-t", help="Per-source budget factor for global parallel wait."),
    presenter_fast: bool = typer.Option(
        False,
        "--presenter-fast",
        help="Skip slow text fetchers; merge cache. Also on if investor-demo presenter-mode is enabled.",
    ),
    no_cache_merge: bool = typer.Option(False, "--no-cache-merge", help="Do not merge last prefetch cache on timeout/error."),
    prefetch_after: bool = typer.Option(False, "--prefetch-after", help="After building, write result as last-good cache."),
) -> None:
    """M52: Timed parallel snapshot + adapter_meta (live vs stale_cache). For investor desktop prototype."""
    import json
    from workflow_dataset.live_desktop_adapter import (
        build_live_adapter_snapshot,
        RefreshPolicy,
        save_last_good_snapshot,
    )

    root = Path(repo_root).resolve() if repo_root else None
    pol = RefreshPolicy(
        timeout_seconds=timeout_sec,
        presenter_fast_path=presenter_fast,
        merge_last_good_cache=not no_cache_merge,
        skip_slow_text_fetchers=False,
    )
    snap = build_live_adapter_snapshot(repo_root=root, policy=pol)
    if prefetch_after:
        save_last_good_snapshot(snap, root)
    text = json.dumps(snap, indent=2, default=str)
    if output:
        Path(output).write_text(text, encoding="utf-8")
        console.print(f"[green]Wrote {output}[/green]")
    else:
        console.print(text)
    am = snap.get("adapter_meta") or {}
    import sys
    sys.stderr.write(
        f"adapter: live={sum(1 for v in (am.get('field_status') or {}).values() if v == 'live')} "
        f"stale_cache={sum(1 for v in (am.get('field_status') or {}).values() if v == 'stale_cache')} "
        f"presenter={am.get('presenter_mode_active')}\n"
    )


@demo_group.command("live-desktop-prefetch")
def demo_live_desktop_prefetch_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Also copy JSON to path (e.g. investor-prototype/public/)."),
    timeout_sec: float = typer.Option(30.0, "--timeout", "-t"),
) -> None:
    """M52: Full snapshot with generous timeout; writes data/local/live_desktop/last_good_snapshot.json for presenter demos."""
    import json
    import shutil
    from workflow_dataset.live_desktop_adapter import prefetch_and_cache_snapshot, cache_path

    root = Path(repo_root).resolve() if repo_root else None
    snap = prefetch_and_cache_snapshot(repo_root=root, timeout_seconds=timeout_sec)
    p = cache_path(root)
    console.print(f"[green]Prefetch cache:[/green] {p}")
    if output:
        Path(output).parent.mkdir(parents=True, exist_ok=True)
        shutil.copyfile(p, Path(output))
        console.print(f"[green]Copied to[/green] {output}")
    am = snap.get("adapter_meta") or {}
    console.print(f"[dim]sources_ok: {len(snap.get('sources_ok') or [])}  notes: {len(am.get('degraded_notes') or [])}[/dim]")


