@demo_group.command("launch")
def demo_launch_cmd(
    bundle_root: str = typer.Option("", "--bundle-root", "-b"),
) -> None:
    """Portable edge operator startup + suggested profile/playbook (M51D.1)."""
    from workflow_dataset.demo_usb import build_readiness_report
    from workflow_dataset.demo_usb.bundle_root import resolve_demo_bundle_root
    from workflow_dataset.demo_usb.profiles_playbooks import (
        suggest_profile_for_readiness,
        suggest_playbook_for_readiness,
        load_demo_bundle_profiles,
        load_usb_playbooks,
    )
    br = Path(bundle_root).resolve() if bundle_root else None
    try:
        root = br or resolve_demo_bundle_root(None)
    except ValueError as e:
        console.print(f"[red]{e}[/red]")
        raise typer.Exit(2)
    rep = build_readiness_report(root, explicit_bundle=br if bundle_root else None)
    pid = suggest_profile_for_readiness(rep)
    pbid = suggest_playbook_for_readiness(rep)
    profiles = load_demo_bundle_profiles(root)
    playbooks = load_usb_playbooks(root)
    prof = profiles.get(pid)
    console.print("[bold]Investor demo launch path[/bold] (local-only)\n")
    console.print(f"  cd {root}")
    console.print("  export PYTHONPATH=src  # if not pip-installed")
    console.print("  workflow-dataset demo bootstrap")
    console.print("  workflow-dataset demo readiness")
    console.print(f"  [dim]Suggested profile:[/dim] {pid}  [dim]playbook:[/dim] {pbid}")
    if prof:
        console.print(f"  → {prof.label}: {prof.summary[:100]}…" if len(prof.summary) > 100 else f"  → {prof.label}: {prof.summary}")
    console.print(f"  workflow-dataset demo playbook --id {pbid}")
    if rep.capability_level.value == "blocked":
        console.print("\n[yellow]Readiness BLOCKED — follow playbook usb_degraded_honest; do not promise full demo.[/yellow]")
        raise typer.Exit(1)
    console.print("  workflow-dataset package first-run")
    console.print("  workflow-dataset onboard bootstrap")
    console.print("  workflow-dataset demo onboarding start")
    console.print("\n[dim]Host manifest: ~/.workflow-demo-host/<bundle>/.workflow-demo/last_bootstrap.json[/dim]")


