def investor_demo_script_cmd(
    beat: int = typer.Option(0, "--beat", "-b", help="Show single beat 1–8 (0 = full script)"),
    json_out: bool = typer.Option(False, "--json"),
    repo: str = typer.Option("", "--repo", "-r"),
) -> None:
    """5-minute investor demo script: SHOW / RUN / SAY per stage + degraded lines."""
    from workflow_dataset.investor_demo import build_five_minute_demo_script, format_script_compact_text
    script = build_five_minute_demo_script()
    root = Path(repo).resolve() if repo else None
    if beat and 1 <= beat <= len(script.beats):
        b = script.beats[beat - 1]
        if json_out:
            import json
            console.print(json.dumps(b.to_dict(), indent=2))
            return
        console.print(f"[bold]Beat {beat}[/bold]  {b.stage_id}  ~{b.start_after_seconds}s in")
        console.print(f"  SHOW:  {b.show}")
        console.print(f"  RUN:   {b.click_or_run}")
        console.print(f"  SAY:   {b.say}")
        if b.if_degraded_say:
            console.print(f"  IF DEGRADED: {b.if_degraded_say}")
        return
    if json_out:
        import json
        console.print(json.dumps(script.to_dict(), indent=2))
        return
    console.print(format_script_compact_text(script))


