@investor_demo_cli.command("session")
def investor_demo_session_cmd(
    action: str = typer.Argument("start", help="start | stage"),
    repo: str = typer.Option("", "--repo", "-r"),
    vertical: str = typer.Option("", "--vertical", "-v"),
    role_pack: str = typer.Option("founder_operator", "--role-pack"),
    presenter: bool = typer.Option(False, "--presenter", help="Enable presenter mode when starting"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Start or advance investor demo narrative session."""
    from workflow_dataset.investor_demo import start_demo_session, advance_demo_stage, set_presenter_mode
    root = Path(repo).resolve() if repo else None
    if action == "start":
        sess = start_demo_session(repo_root=root, vertical_id=vertical, role_demo_pack_id=role_pack)
        if presenter:
            set_presenter_mode(True, repo_root=root)
        if json_out:
            import json
            console.print(json.dumps(sess.to_dict(), indent=2))
            return
        console.print(f"[bold]Session[/bold] {sess.session_id}  stage={sess.current_stage}")
        if sess.presenter_guidance:
            console.print(f"  {sess.presenter_guidance.headline}")
    elif action == "stage":
        sess = advance_demo_stage(repo_root=root)
        if not sess:
            console.print("[red]No session. Run: investor-demo session start[/red]")
            raise typer.Exit(1)
        if json_out:
            import json
            console.print(json.dumps(sess.to_dict(), indent=2))
            return
        if sess.completion.completed:
            console.print("[bold]Complete[/bold]  " + sess.completion.closing_summary)
        else:
            console.print(f"[bold]Stage[/bold] {sess.current_stage}")
            if sess.presenter_guidance:
                for t in sess.presenter_guidance.talking_points[:3]:
                    console.print(f"  • {t}")
    else:
        console.print("[red]action: start | stage[/red]")
        raise typer.Exit(2)


