# ----- M32E–M32H Just-in-time assist engine: now, queue, explain, accept, snooze, dismiss -----
@assist_group.command("now")
def assist_now(
    repo: str = typer.Option("", "--repo", "-r", help="Repo root (default: current)"),
    focus_safe: bool = typer.Option(False, "--focus-safe", help="Apply focus-safe suppression (low interrupt, high confidence only)"),
) -> None:
    """Generate suggestions from live context, apply policy (quiet hours, focus-safe, interruptibility), show queue."""
    from workflow_dataset.assist_engine.queue import run_now
    root = Path(repo).resolve() if repo else None
    suggestions = run_now(repo_root=root, focus_safe_active=focus_safe)
    if not suggestions:
        console.print("[dim]No suggestions right now. Try setting a goal or running routines.[/dim]")
        return
    console.print(f"[green]Queue: {len(suggestions)} suggestion(s)[/green]")
    for i, s in enumerate(suggestions[:10], 1):
        console.print(f"  {i}. [{s.suggestion_type}] {s.title[:60]}")
        console.print(f"     id={s.suggestion_id}  usefulness={s.usefulness_score:.2f}  confidence={s.confidence:.2f}")
    if len(suggestions) > 10:
        console.print(f"  ... and {len(suggestions) - 10} more. Use [bold]assist queue[/bold] to list all.")


@assist_group.command("queue")
def assist_queue(
    repo: str = typer.Option("", "--repo", "-r", help="Repo root"),
    limit: int = typer.Option(30, "--limit", "-n"),
    status: str = typer.Option("pending", "--status", "-s", help="pending | snoozed | accepted | dismissed | held_back"),
) -> None:
    """List reviewable suggestion queue (or held_back by policy), sorted by usefulness and confidence."""
    from workflow_dataset.assist_engine.queue import get_queue
    root = Path(repo).resolve() if repo else None
    items = get_queue(repo_root=root, status_filter=status, limit=limit, include_snoozed=(status == "snoozed"))
    if not items:
        console.print(f"[dim]No suggestions with status={status}.[/dim]")
        return
    console.print(f"[Assist queue] status={status}  count={len(items)}")
    for i, s in enumerate(items, 1):
        console.print(f"  {i}. [{s.suggestion_id}] {s.suggestion_type}: {s.title[:50]}")
        console.print(f"     usefulness={s.usefulness_score:.2f}  confidence={s.confidence:.2f}  interrupt={s.interruptiveness_score:.2f}")


@assist_group.command("explain-suggestion")
def assist_explain_suggestion(
    id: str = typer.Option(..., "--id", "-i", help="Suggestion ID (e.g. sug_...)"),
    repo: str = typer.Option("", "--repo", "-r", help="Repo root"),
) -> None:
    """Explain a JIT suggestion by id: reason, triggering context, evidence."""
    from workflow_dataset.assist_engine.explain import explain_suggestion
    root = Path(repo).resolve() if repo else None
    ex = explain_suggestion(id, repo_root=root)
    if not ex:
        console.print(f"[red]Suggestion not found: {id}[/red]")
        raise typer.Exit(1)
    console.print(f"[bold]{ex.get('title', '')}[/bold]")
    console.print(f"Type: {ex.get('suggestion_type', '')}  ID: {ex.get('suggestion_id', '')}")
    r = ex.get("reason", {})
    console.print(f"Reason: {r.get('title', '')}")
    console.print(r.get("description", ""))
    if r.get("evidence"):
        console.print("Evidence: " + " | ".join(r.get("evidence", [])[:5]))
    tc = ex.get("triggering_context", {})
    console.print(f"Context: {tc.get('source', '')} — {tc.get('summary', '')}")
    console.print(f"Required action: {ex.get('required_operator_action', '')}")


