@assist_group.command("policy-status")
def assist_policy_status(
    repo: str = typer.Option("", "--repo", "-r", help="Repo root"),
) -> None:
    """Show current assist policy: quiet hours, focus-safe, interruptibility rules (M32H.1)."""
    from workflow_dataset.assist_engine.policy import load_policy
    from workflow_dataset.assist_engine.store import get_assist_engine_root
    root = Path(repo).resolve() if repo else None
    policy = load_policy(repo_root=root)
    config_path = get_assist_engine_root(root) / "policy.yaml"
    console.print(f"[Assist policy] config={config_path}  exists={config_path.exists()}")
    console.print(f"  quiet_hours: {len(policy.quiet_hours)} window(s)")
    for w in policy.quiet_hours[:5]:
        console.print(f"    - {w.start_utc}–{w.end_utc}  {w.description or '(no label)'}")
    fs = policy.focus_safe
    console.print(f"  focus_safe: enabled={fs.enabled}  max_interrupt={fs.max_interruptiveness}  min_confidence={fs.min_confidence}")
    console.print(f"  interruptibility_rules: {len(policy.interruptibility_rules)} rule(s)")
    for r in policy.interruptibility_rules[:5]:
        console.print(f"    - work_mode={r.work_mode or '*'}, project={r.project_id or '*'}, allow={r.allow_suggestions}")


@assist_group.command("signal-report")
def assist_signal_report(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json", help="Output as JSON"),
) -> None:
    """Signal quality report for assist: calmness, suppressed count, focus protection. M37."""
    from workflow_dataset.assist_engine.queue import run_now
    from workflow_dataset.signal_quality.attention import get_protected_focus
    from workflow_dataset.signal_quality.quieting import apply_assist_quieting
    from workflow_dataset.signal_quality.reports import build_quality_report
    root = Path(repo).resolve() if repo else None
    suggestions = run_now(repo_root=root, max_new=15)
    focus = get_protected_focus(root)
    visible, suppressed = apply_assist_quieting(suggestions, focus=focus)
    report = build_quality_report(
        repo_root=root,
        queue_items=suggestions,
        suppressed=suppressed,
        top_high_signal_id=visible[0].suggestion_id if visible else "",
    )
    if json_out:
        console.print(json.dumps(report, indent=2))
        return
    console.print(f"[bold]Assist signal quality[/bold]  calmness={report['calmness_score']}  noise={report['noise_level']}")
    console.print(f"  suggestions={report['queue_item_count']}  suppressed={report['suppressed_count']}  focus_protected={report['focus_protected_active']}")


