# ----- M24D Activation executor: request, preview, execute, disable, history -----
@capabilities_external_group.command("request")
def capabilities_external_request(
    source: str = typer.Option(..., "--source", "-s", help="Source id (e.g. ollama_qwen2.5-coder, openclaw)"),
    action: str = typer.Option("enable", "--action", "-a", help="Action: install, enable, disable, remove, verify"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
) -> None:
    """Create an activation request for a source. Use preview then execute to apply."""
    from workflow_dataset.external_capability.executor import create_activation_request
    from workflow_dataset.external_capability.activation_store import save_request
    from workflow_dataset.external_capability.report import format_activation_request
    root = Path(repo_root).resolve() if repo_root else None
    req = create_activation_request(source, action=action, repo_root=root)
    if not req:
        console.print(f"[red]Source '{source}' not found.[/red]")
        raise typer.Exit(1)
    save_request(req, root)
