# ----- M31E–M31H Personal work graph + routines + patterns -----
personal_group = typer.Typer(
    help="Personal work graph: status, ingest, routines, patterns, explain. Local-first; no cloud.",
)
app.add_typer(personal_group, name="personal")


@personal_group.command("graph")
def personal_graph_cmd(
    subcommand: str = typer.Argument("status", help="status | ingest | explain"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    source: str = typer.Option("recent", "--source", "-s", help="Event source: recent (from log) | file | app"),
    node: str = typer.Option("", "--node", "-n", help="Node id for explain"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Personal graph: status (default), ingest (from event log), or explain --node <id>."""
    root = Path(repo_root).resolve() if repo_root else None
    if subcommand == "status":
        from workflow_dataset.personal.graph_reports import graph_status
        st = graph_status(repo_root=root)
        if json_out:
            console.print(json.dumps(st, indent=2))
        else:
            console.print("[bold]Personal work graph[/bold]")
            console.print(f"  path: {st.get('graph_path')}  exists={st.get('exists')}")
            console.print(f"  nodes: {st.get('nodes_total')}  edges: {st.get('edges_total')}")
            console.print(f"  routines: {st.get('routines_count')}  projects: {st.get('projects_count')}  tools: {st.get('tool_apps_count')}")
    elif subcommand == "ingest":
        from workflow_dataset.personal.graph_builder import build_graph_from_recent_events
        from workflow_dataset.settings import load_settings
        if root:
            store_path = root / "data/local/work_graph.sqlite"
            log_dir = root / "data/local/events"
            roots = []
        else:
            try:
                s = load_settings("configs/settings.yaml")
                store_path = Path(getattr(getattr(s, "paths", None), "graph_store_path", "data/local/work_graph.sqlite"))
                log_dir = Path(getattr(getattr(s, "paths", None), "event_log_dir", "data/local/events"))
                roots = [Path(p).resolve() for p in (getattr(getattr(s, "agent", None), "file_observer", None) or {}).get("root_paths", []) or []]
            except Exception:
                store_path = Path("data/local/work_graph.sqlite")
                log_dir = Path("data/local/events")
                roots = []
        src_filter = None if source == "recent" else (source if source in ("file", "app") else None)
        result = build_graph_from_recent_events(store_path, log_dir, root_paths=roots or None, source_filter=src_filter)
        if json_out:
            console.print(json.dumps(result, indent=2))
        else:
            console.print(f"[green]Ingest: {result.get('nodes_created_or_updated')} nodes, {result.get('edges_created')} edges[/green]")
    elif subcommand == "explain" and node:
        from workflow_dataset.personal.graph_reports import explain_node
        ex = explain_node(node, repo_root=root)
        if json_out:
            console.print(json.dumps(ex, indent=2))
        else:
            if ex.get("error"):
                console.print(f"[red]{ex.get('error')}[/red]")
            else:
                console.print(f"[bold]Node {ex.get('node_id')}[/bold]  type={ex.get('node_type')}  label={ex.get('label')}")
                console.print(f"  source={ex.get('source')}  confidence={ex.get('confidence')}  events={ex.get('source_event_count')}")
                for e in ex.get("out_edges", [])[:15]:
                    console.print(f"  -> {e['to_id']} ({e['relation_type']})")
                for e in ex.get("in_edges", [])[:15]:
                    console.print(f"  <- {e['from_id']} ({e['relation_type']})")
    else:
        console.print("Use: personal graph status | personal graph ingest | personal graph explain --node <id>")


