@action_cards_group.command("accept")
def action_cards_accept_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Card id"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
) -> None:
    """Accept a card (enable execute). Does not execute."""
    from workflow_dataset.action_cards.store import load_card, save_card
    from workflow_dataset.action_cards.models import CardState
    from workflow_dataset.utils.dates import utc_now_iso
    root = Path(repo_root).resolve() if repo_root else None
    card = load_card(id, root)
    if not card:
        console.print(f"[red]Card not found: {id}[/red]")
        raise typer.Exit(1)
    card.state = CardState.ACCEPTED
    card.updated_utc = utc_now_iso()
    save_card(card, root)
    console.print(f"[green]Accepted: {id}[/green]. Run 'action-cards execute --id {id}' to run handoff.")


@action_cards_group.command("dismiss")
def action_cards_dismiss_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Card id"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
) -> None:
    """Dismiss a card (no execution)."""
    from workflow_dataset.action_cards.store import load_card, update_card_state
    from workflow_dataset.action_cards.models import CardState
    from workflow_dataset.utils.dates import utc_now_iso
    root = Path(repo_root).resolve() if repo_root else None
    if not load_card(id, root):
        console.print(f"[red]Card not found: {id}[/red]")
        raise typer.Exit(1)
    update_card_state(id, CardState.DISMISSED, repo_root=root, updated_utc=utc_now_iso())
    console.print(f"[green]Dismissed: {id}[/green]")


@action_cards_group.command("preview")
def action_cards_preview_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Card id"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Preview what executing the card would do."""
    from workflow_dataset.action_cards.store import load_card
    from workflow_dataset.action_cards.preview import build_preview
    root = Path(repo_root).resolve() if repo_root else None
    card = load_card(id, root)
    if not card:
        console.print(f"[red]Card not found: {id}[/red]")
        raise typer.Exit(1)
    preview = build_preview(card)
    if json_out:
        console.print(json.dumps(preview.to_dict(), indent=2))
    else:
        console.print("[bold]Preview[/bold]")
        console.print(f"  {preview.summary}")
        console.print(f"  What would happen: {preview.what_would_happen}")
        console.print(f"  Trust: {preview.trust_note}")
        if preview.command_hint:
            console.print(f"  Command: {preview.command_hint}")


@action_cards_group.command("execute")
def action_cards_execute_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Card id"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Execute the card handoff (one-click safe handoff)."""
    from workflow_dataset.action_cards.handoff import execute_handoff
    root = Path(repo_root).resolve() if repo_root else None
    result = execute_handoff(id, repo_root=root)
    if json_out:
        console.print(json.dumps(result, indent=2))
    elif not result.get("ok"):
        console.print(f"[red]{result.get('error', 'failed')}[/red]")
        if result.get("blocked_reason"):
            console.print(f"  {result['blocked_reason']}")
        raise typer.Exit(1)
    else:
        console.print(f"[green]Handoff executed: {result.get('message', '')}[/green]")
        if result.get("queue_id"):
            console.print(f"  queue_id={result['queue_id']}")
        if result.get("plan_id"):
            console.print(f"  plan_id={result['plan_id']}")


@action_cards_group.command("refresh")
def action_cards_refresh_cmd(
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """Build new cards from suggestions/routines/copilot and save (merge with existing)."""
    from workflow_dataset.action_cards.builder import suggestion_to_cards
    from workflow_dataset.action_cards.store import load_all_cards, save_card
    root = Path(repo_root).resolve() if repo_root else None
    existing_ids = {c.card_id for c in load_all_cards(root)}
    new_cards = suggestion_to_cards(repo_root=root, limit=30)
    added = 0
    for c in new_cards:
        if c.card_id not in existing_ids:
            save_card(c, root)
            existing_ids.add(c.card_id)
            added += 1
    if json_out:
        console.print(json.dumps({"added": added, "total_new_candidates": len(new_cards)}, indent=2))
    else:
        console.print(f"[green]Refresh: {added} new cards added[/green] (from {len(new_cards)} candidates)")


# ----- M32L.1 Micro-assistance bundles -----
@action_cards_group.command("bundles")
def action_cards_bundles_cmd(
    subcommand: str = typer.Argument("list", help="list | show | create | add-card | remove-card"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    id: str = typer.Option("", "--id", "-i", help="Bundle id (for show / add-card / remove-card)"),
    name: str = typer.Option("", "--name", "-n", help="Bundle name (for create)"),
    moment: str = typer.Option("", "--moment", "-m", help="Moment: resume_work | blocked_review | end_of_day_wrap | document_handoff"),
    card_id: str = typer.Option("", "--card-id", "-c", help="Card id (for add-card / remove-card)"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """List, show, create bundles; add-card / remove-card to bundle."""
    from workflow_dataset.action_cards.bundles import load_all_bundles, load_bundle, save_bundle, list_bundles_by_moment, add_card_to_bundle, remove_card_from_bundle
    from workflow_dataset.action_cards.models import MicroAssistanceBundle
    from workflow_dataset.utils.dates import utc_now_iso
    from workflow_dataset.utils.hashes import stable_id
    root = Path(repo_root).resolve() if repo_root else None
    if subcommand == "list":
        bundles = list_bundles_by_moment(moment, root) if moment else load_all_bundles(root)
        if json_out:
            console.print(json.dumps([b.to_dict() for b in bundles], indent=2))
        else:
            console.print("[bold]Bundles[/bold]" + (f" (moment={moment})" if moment else ""))
            for b in bundles:
                console.print(f"  {b.bundle_id}: {b.name}  moment={b.moment_kind}  cards={len(b.card_ids)}")
    elif subcommand == "show" and id:
        b = load_bundle(id, root)
        if not b:
            console.print(f"[red]Bundle not found: {id}[/red]")
            raise typer.Exit(1)
        if json_out:
            console.print(json.dumps(b.to_dict(), indent=2))
        else:
            console.print(f"[bold]{b.name}[/bold]  {b.bundle_id}  moment={b.moment_kind}")
            console.print(f"  {b.description[:200]}" if b.description else "")
            console.print("  card_ids: " + ", ".join(b.card_ids[:15]))
    elif subcommand == "create":
        if not name or not moment:
            console.print("[red]Use --name and --moment for create[/red]")
            raise typer.Exit(1)
        bundle_id = stable_id("bundle", moment, utc_now_iso(), prefix="bundle")
        b = MicroAssistanceBundle(bundle_id=bundle_id, name=name, moment_kind=moment, created_utc=utc_now_iso(), updated_utc=utc_now_iso())
        save_bundle(b, root)
        if json_out:
            console.print(json.dumps(b.to_dict(), indent=2))
        else:
            console.print(f"[green]Created bundle {bundle_id}[/green]")
    elif subcommand == "add-card" and id and card_id:
        ok = add_card_to_bundle(id, card_id, root)
        if json_out:
            console.print(json.dumps({"ok": ok, "bundle_id": id, "card_id": card_id}, indent=2))
        else:
            console.print(f"[green]Added card {card_id} to bundle {id}[/green]" if ok else f"[red]Bundle not found: {id}[/red]")
    elif subcommand == "remove-card" and id and card_id:
        ok = remove_card_from_bundle(id, card_id, root)
        if json_out:
            console.print(json.dumps({"ok": ok, "bundle_id": id, "card_id": card_id}, indent=2))
        else:
            console.print(f"[green]Removed card {card_id} from bundle {id}[/green]" if ok else f"[red]Bundle not found: {id}[/red]")
    else:
        console.print("Use: action-cards bundles list | show --id <id> | create --name X --moment Y | add-card --id B --card-id C | remove-card --id B --card-id C")


@action_cards_group.command("review-paths")
def action_cards_review_paths_cmd(
    subcommand: str = typer.Argument("list", help="list | show | create | apply"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    id: str = typer.Option("", "--id", "-i", help="Path id (for show / apply)"),
    moment: str = typer.Option("", "--moment", "-m", help="Moment (for list / create)"),
    name: str = typer.Option("", "--name", "-n", help="Path name (for create)"),
    filter_state: str = typer.Option("", "--filter-state", help="Filter by card state (for create)"),
    action: str = typer.Option("list_only", "--action", "-a", help="list_only | preview_first | execute_in_order | open_studio"),
    limit: int = typer.Option(10, "--limit", "-l", help="Max cards (for create)"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """List, show, create, or apply fast review paths."""
    from workflow_dataset.action_cards.review_paths import load_all_review_paths, load_review_path, apply_path, save_review_path
    from workflow_dataset.action_cards.models import FastReviewPath
    from workflow_dataset.utils.dates import utc_now_iso
    from workflow_dataset.utils.hashes import stable_id
    root = Path(repo_root).resolve() if repo_root else None
    if subcommand == "list":
        paths = load_all_review_paths(root)
        if moment:
            paths = [p for p in paths if p.moment_kind == moment]
        if json_out:
            console.print(json.dumps([p.to_dict() for p in paths], indent=2))
        else:
            console.print("[bold]Review paths[/bold]" + (f" (moment={moment})" if moment else ""))
            for p in paths:
                console.print(f"  {p.path_id}: {p.name}  action={p.action}  limit={p.limit}")
    elif subcommand == "show" and id:
        p = load_review_path(id, root)
        if not p:
            console.print(f"[red]Path not found: {id}[/red]")
            raise typer.Exit(1)
        if json_out:
            console.print(json.dumps(p.to_dict(), indent=2))
        else:
            console.print(f"[bold]{p.name}[/bold]  {p.path_id}  moment={p.moment_kind}")
            console.print(f"  filter: state={p.filter_state or 'any'}  action={p.action}  limit={p.limit}")
    elif subcommand == "create":
        if not name or not moment:
            console.print("[red]Use --name and --moment for create[/red]")
            raise typer.Exit(1)
        path_id = stable_id("path", moment, utc_now_iso(), prefix="path")
        p = FastReviewPath(path_id=path_id, name=name, moment_kind=moment, filter_state=filter_state, action=action, limit=limit, created_utc=utc_now_iso(), updated_utc=utc_now_iso())
        save_review_path(p, root)
        if json_out:
            console.print(json.dumps(p.to_dict(), indent=2))
        else:
            console.print(f"[green]Created review path {path_id}[/green]")
    elif subcommand == "apply" and id:
        cards = apply_path(id, root)
        if json_out:
            console.print(json.dumps([c.to_dict() for c in cards], indent=2))
        else:
            console.print(f"[bold]Applied path {id}[/bold]: {len(cards)} cards")
            for c in cards[:15]:
                console.print(f"  {c.card_id}: {c.title[:50]}  {c.state.value}")
    else:
        console.print("Use: action-cards review-paths list | show --id <id> | create --name X --moment Y | apply --id <path_id>")


@action_cards_group.command("flows")
def action_cards_flows_cmd(
    subcommand: str = typer.Argument("list", help="list | show | create | run"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    id: str = typer.Option("", "--id", "-i", help="Flow id (for show)"),
    moment: str = typer.Option("", "--moment", "-m", help="Moment (for create / run)"),
    label: str = typer.Option("", "--label", "-l", help="Flow label (for create)"),
    bundle_id: str = typer.Option("", "--bundle-id", "-b", help="Bundle id (for create)"),
    review_path_id: str = typer.Option("", "--review-path-id", "-p", help="Review path id (for create)"),
    json_out: bool = typer.Option(False, "--json", help="Output JSON"),
) -> None:
    """List, show, create flows; run flow for a user moment."""
    from workflow_dataset.action_cards.flows import load_all_flows, load_flow, get_flow_for_moment, run_flow, save_flow
    from workflow_dataset.action_cards.models import GroupedCardFlow
    from workflow_dataset.utils.dates import utc_now_iso
    from workflow_dataset.utils.hashes import stable_id
    root = Path(repo_root).resolve() if repo_root else None
    if subcommand == "list":
        flows = load_all_flows(root)
        if json_out:
            console.print(json.dumps([f.to_dict() for f in flows], indent=2))
        else:
            console.print("[bold]Grouped card flows[/bold]")
            for f in flows:
                console.print(f"  {f.flow_id}: {f.label}  moment={f.moment_kind}  bundle={f.bundle_id or '—'}  path={f.review_path_id or '—'}")
    elif subcommand == "show" and id:
        f = load_flow(id, root)
        if not f:
            console.print(f"[red]Flow not found: {id}[/red]")
            raise typer.Exit(1)
        if json_out:
            console.print(json.dumps(f.to_dict(), indent=2))
        else:
            console.print(f"[bold]{f.label}[/bold]  {f.flow_id}  moment={f.moment_kind}")
            console.print(f"  bundle_id={f.bundle_id}  review_path_id={f.review_path_id}")
    elif subcommand == "create":
        if not moment or not label:
            console.print("[red]Use --moment and --label for create[/red]")
            raise typer.Exit(1)
        flow_id = stable_id("flow", moment, utc_now_iso(), prefix="flow")
        f = GroupedCardFlow(flow_id=flow_id, moment_kind=moment, label=label, bundle_id=bundle_id, review_path_id=review_path_id, created_utc=utc_now_iso(), updated_utc=utc_now_iso())
        save_flow(f, root)
        if json_out:
            console.print(json.dumps(f.to_dict(), indent=2))
        else:
            console.print(f"[green]Created flow {flow_id}[/green]")
    elif subcommand == "run" and moment:
        result = run_flow(moment, root)
        if json_out:
            console.print(json.dumps(result, indent=2))
        elif not result.get("ok"):
            console.print(f"[red]{result.get('error')}[/red]  moment={moment}")
            raise typer.Exit(1)
        else:
            console.print(f"[green]Flow: {result.get('label')}[/green]  cards={result.get('cards_count', 0)}")
            for c in result.get("cards", [])[:10]:
                console.print(f"  {c.get('card_id')}: {c.get('title', '')[:50]}")
    else:
        console.print("Use: action-cards flows list | show --id <id> | create --moment M --label L [--bundle-id] [--review-path-id] | run --moment <moment>")


