@projects_group.command("add-goal")
def projects_add_goal(
    id_arg: str = typer.Option(..., "--id", "-i", help="Project id"),
    goal_id: str = typer.Option(..., "--goal-id", "-g", help="Goal id"),
    title: str = typer.Option("", "--title", "-t"),
    order: int = typer.Option(None, "--order", "-o", help="Priority order (lower = higher)"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Add a goal to the project goal stack."""
    from workflow_dataset.project_case import add_goal
    root = Path(repo_root).resolve() if repo_root else None
    goal = add_goal(id_arg, goal_id, title=title, order=order, repo_root=root)
    if not goal:
        console.print("[red]Project not found.[/red]")
        raise typer.Exit(1)
    console.print(f"[green]Added goal: {goal.goal_id}[/green]  Goals: workflow-dataset projects goals --id {id_arg}")


@projects_group.command("attach-session")
def projects_attach_session(
    id_arg: str = typer.Option(..., "--id", "-i", help="Project id"),
    session: str = typer.Option(..., "--session", "-s", help="Session id (e.g. latest or session_id)"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Attach a session to the project."""
    from workflow_dataset.project_case import attach_session
    from workflow_dataset.session import load_current_session_id, load_session
    root = Path(repo_root).resolve() if repo_root else None
    session_id = load_current_session_id(root) if session.strip().lower() == "latest" else session.strip()
    if session.strip().lower() == "latest" and not session_id:
        console.print("[red]No current session. Start a session first.[/red]")
        raise typer.Exit(1)
    if attach_session(id_arg, session_id, repo_root=root):
        console.print(f"[green]Attached session {session_id} to project {id_arg}[/green]")
    else:
        console.print("[red]Project not found.[/red]")
        raise typer.Exit(1)


