@skills_group.command("list")
def skills_list(
    status: str = typer.Option("", "--status", "-s", help="draft | accepted | rejected (empty = all)"),
    limit: int = typer.Option(50, "--limit", "-n"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """List taught skills. Use --status draft|accepted|rejected to filter."""
    from workflow_dataset.teaching.skill_store import list_skills
    root = Path(repo_root).resolve() if repo_root else None
    st = status.strip() or None
    skills = list_skills(status=st, repo_root=root, limit=limit)
    if not skills:
        console.print("[dim]No skills found. Create with: skills draft-from-demo --id <task_id>[/dim]")
        return
    for s in skills:
        console.print(f"  {s.skill_id}  status={s.status}  source={s.source_type}  source_ref={s.source_reference_id or '—'}")


