@skills_group.command("review")
def skills_review(
    id: str = typer.Option(..., "--id", "-i", help="Skill id to show for review"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Show skill draft for operator review (normalized steps, source, status). Use accept/reject to change status."""
    from workflow_dataset.teaching.skill_store import load_skill
    root = Path(repo_root).resolve() if repo_root else None
    skill = load_skill(id, root)
    if not skill:
        console.print("[red]Skill not found.[/red]")
        raise typer.Exit(1)
    console.print(Panel(
        f"skill_id: {skill.skill_id}\nstatus: {skill.status}\nsource: {skill.source_type} ref={skill.source_reference_id}\n"
        f"goal_family: {skill.goal_family or '—'}  task_family: {skill.task_family or '—'}\n"
        f"trust_readiness: {skill.trust_readiness_status}  simulate_or_trusted: {skill.simulate_only_or_trusted_real}\n"
        f"pack_associations: {skill.pack_associations or []}\noperator_notes: {skill.operator_notes or '—'}\n"
        f"normalized_steps: {len(skill.normalized_steps)} steps",
        title=f"Skill: {skill.skill_id}",
        border_style="dim",
    ))
    console.print("[dim]To accept: workflow-dataset skills accept --id " + id + " [--trusted-real][/dim]")
    console.print("[dim]To reject: workflow-dataset skills reject --id " + id + "[/dim]")


@skills_group.command("accept")
def skills_accept(
    id: str = typer.Option(..., "--id", "-i", help="Skill id to accept"),
    trusted_real: bool = typer.Option(False, "--trusted-real", help="Mark as trusted_real_candidate (default: simulate_only)"),
    notes: str = typer.Option("", "--notes", "-n"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Accept a draft skill. Optionally mark as trusted_real_candidate; default is simulate_only."""
    from workflow_dataset.teaching.review import accept_skill
    root = Path(repo_root).resolve() if repo_root else None
    sim_or_trusted = "trusted_real_candidate" if trusted_real else "simulate_only"
    skill = accept_skill(id, operator_notes=notes, simulate_only_or_trusted_real=sim_or_trusted, repo_root=root)
    if not skill:
        console.print("[red]Skill not found.[/red]")
        raise typer.Exit(1)
    console.print(f"[green]Accepted: {skill.skill_id}[/green]  simulate_only_or_trusted_real={skill.simulate_only_or_trusted_real}")


