# ----- M27I–M27L Progress + Replan -----
progress_group = typer.Typer(
    help="Impact / progress board: board, project. Local, evidence-based.",
)
app.add_typer(progress_group, name="progress")

replan_group = typer.Typer(
    help="Triggered replanning: recommend, diff, accept. No auto-replan.",
)
app.add_typer(replan_group, name="replan")


@progress_group.command("board")
def progress_board_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Write board to file"),
) -> None:
    """Impact / progress board: active projects, health, stalled vs advancing, replan needed, blockers, next intervention."""
    from workflow_dataset.progress.board import format_progress_board
    root = Path(repo_root).resolve() if repo_root else None
    report = format_progress_board(repo_root=root)
    if output:
        Path(output).write_text(report, encoding="utf-8")
        console.print(f"[green]Wrote: {output}[/green]")
    else:
        console.print(report)


@progress_group.command("project")
def progress_project_cmd(
    id_arg: str = typer.Option(..., "--id", "-i", help="Project id (e.g. default, founder_case_alpha)"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Show progress and health for one project."""
    from workflow_dataset.progress.board import build_progress_board
    root = Path(repo_root).resolve() if repo_root else None
    board = build_progress_board(repo_root=root)
    health = board.get("project_health", {}).get(id_arg, "unknown")
    stalled = id_arg in board.get("stalled_projects", [])
    replan = id_arg in board.get("replan_needed_projects", [])
    console.print(f"Project: {id_arg}  health={health}  stalled={stalled}  replan_needed={replan}")


@progress_group.command("recovery")
def progress_recovery_cmd(
    project: str = typer.Option("default", "--project", "-p", help="Project id for stalled recovery"),
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Write recovery report to file"),
) -> None:
    """M27L.1: Stalled-project recovery — matched intervention playbook, operator intervention, agent next step, escalation/defer."""
    from workflow_dataset.progress.recovery import build_stalled_recovery, format_stalled_recovery
    root = Path(repo_root).resolve() if repo_root else None
    recovery = build_stalled_recovery(project_id=project, repo_root=root)
    report = format_stalled_recovery(recovery)
    if output:
        Path(output).write_text(report, encoding="utf-8")
        console.print(f"[green]Wrote: {output}[/green]")
    else:
        console.print(report)


@progress_group.command("playbooks")
def progress_playbooks_cmd() -> None:
    """List intervention playbook ids and titles."""
    from workflow_dataset.progress.playbooks import list_playbooks
    for pb in list_playbooks():
        console.print(f"  {pb.playbook_id}: {pb.title}")


@replan_group.command("recommend")
def replan_recommend_cmd(
    project: str = typer.Option("default", "--project", "-p", help="Project id"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Recommend whether to replan; show reason and signals. Saves signals for board."""
    from workflow_dataset.progress.models import ReplanSignal
    from workflow_dataset.progress.store import save_replan_signals
    from workflow_dataset.progress.recommendation import recommend_replan, explain_replan
    root = Path(repo_root).resolve() if repo_root else None
    rec = recommend_replan(project_id=project, repo_root=root)
    signals = [ReplanSignal.from_dict(s) for s in rec.get("signals", [])]
    if signals:
        save_replan_signals(signals, root)
    console.print(f"Recommended: {rec.get('recommended', False)}")
    console.print(explain_replan(rec.get("signals", [])))
    if rec.get("prior_plan_id"):
        console.print(f"Prior plan: {rec['prior_plan_id']}")
    if rec.get("current_plan_id"):
        console.print(f"Current plan: {rec['current_plan_id']}")


@replan_group.command("diff")
def replan_diff_cmd(
    project: str = typer.Option("default", "--project", "-p", help="Project id"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Compare prior plan vs current plan; show changed steps/blockers/checkpoints."""
    from workflow_dataset.progress.store import load_prior_plan
    from workflow_dataset.planner.store import load_latest_plan
    from workflow_dataset.progress.recommendation import compare_plans, format_plan_diff
    root = Path(repo_root).resolve() if repo_root else None
    prior = load_prior_plan(project, root)
    current = load_latest_plan(root)
    if not prior:
        console.print("[yellow]No prior plan stored. Run replan accept to store current as prior.[/yellow]")
        return
    if not current:
        console.print("[yellow]No current plan. Compile a plan first.[/yellow]")
        return
    diff = compare_plans(prior, current)
    console.print(format_plan_diff(diff))


@replan_group.command("accept")
def replan_accept_cmd(
    project: str = typer.Option("default", "--project", "-p", help="Project id"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Store current plan as prior baseline (accept replan). Does not auto-execute."""
    from workflow_dataset.planner.store import load_latest_plan
    from workflow_dataset.progress.store import save_prior_plan
    root = Path(repo_root).resolve() if repo_root else None
    current = load_latest_plan(root)
    if not current:
        console.print("[red]No current plan to accept. Compile a plan first.[/red]")
        raise typer.Exit(1)
    save_prior_plan(project, current.to_dict(), root)
    console.print(f"[green]Stored current plan as prior for project: {project}[/green]")


