@portfolio_group.command("rank")
def portfolio_rank_cmd(repo_root: str = typer.Option("", "--repo-root")) -> None:
    """Show ranked active projects with composite score and tier."""
    from workflow_dataset.portfolio.cli import cmd_rank
    root = Path(repo_root).resolve() if repo_root else None
    ranked = cmd_rank(repo_root=root)
    if not ranked:
        console.print("[dim]No active projects to rank.[/dim]")
        return
    for r in ranked:
        pid, tier = r.get("project_id", ""), r.get("tier", "")
        idx, score, blocker = r.get("rank_index", 0), r.get("composite_score", 0), (r.get("blocker") or {}).get("level", "")
        console.print(f"  #{idx}  {pid}  tier={tier}  score={score:.2f}  blocker={blocker}")


