@defaults_group.command("show")
def defaults_show_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
    json_out: bool = typer.Option(False, "--json", help="Output as JSON"),
) -> None:
    """Show active default experience profile, simplified modes, default-visible surfaces (M37)."""
    from workflow_dataset.default_experience.store import get_active_default_profile_id
    from workflow_dataset.default_experience.profiles import get_profile, list_profile_ids
    from workflow_dataset.default_experience.modes import get_simplified_mode_mapping, internal_state_to_user_mode
    from workflow_dataset.default_experience.surfaces import default_visible_surface_ids, surfaces_hidden_by_default
    from workflow_dataset.workday.store import load_workday_state
    root = Path(repo_root).resolve() if repo_root else None
    profile_id = get_active_default_profile_id(repo_root=root)
    profile = get_profile(profile_id) if profile_id else None
    mapping = get_simplified_mode_mapping()
    mode_ids = [m["mode_id"] for m in mapping]
    default_visible = default_visible_surface_ids()
    hidden = surfaces_hidden_by_default()
    record = load_workday_state(root)
    user_mode = internal_state_to_user_mode(record.state) if record.state else "start"
    if json_out:
        import json
        console.print(json.dumps({
            "active_profile_id": profile_id,
            "profile": profile.to_dict() if profile else None,
            "simplified_modes": mode_ids,
            "current_user_mode": user_mode,
            "default_visible_surfaces": default_visible,
            "surfaces_hidden_by_default_count": len(hidden),
        }))
    else:
        console.print(f"Active profile: {profile_id or 'calm_default'}")
        if profile:
            console.print(f"  Label: {profile.label}; first command: {profile.recommended_first_command or '—'}")
        console.print("Simplified modes: " + ", ".join(mode_ids))
        console.print(f"Current user mode: {user_mode}")
        console.print("Default-visible surfaces: " + ", ".join(default_visible[:15]) + (" ..." if len(default_visible) > 15 else ""))
        console.print(f"Surfaces hidden by default: {len(hidden)}")


