@lanes_group.command("create")
def lanes_create_cmd(
    project: str = typer.Option(..., "--project", "-p", help="Project id (e.g. founder_case_alpha)"),
    goal: str = typer.Option(..., "--goal", "-g", help="Goal id (e.g. g_123)"),
    scope: str = typer.Option("default", "--scope", help="Scope id for lane (e.g. extract_only)"),
    bundle: str = typer.Option("", "--bundle", "-b", help="Use reusable bundle (e.g. extract_only, summarize_only)"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Create a bounded worker lane with a delegated subplan for the given project and goal. Use --bundle for common work types."""
    from workflow_dataset.lanes import create_delegated_subplan, gather_subplan_context, save_lane
    from workflow_dataset.lanes.models import WorkerLane, LanePermissions, LANE_STATUS_OPEN
    from workflow_dataset.lanes.bundles import ensure_default_bundles, load_bundle
    try:
        from workflow_dataset.utils.dates import utc_now_iso
    except Exception:
        from datetime import datetime, timezone
        def utc_now_iso() -> str:
            return datetime.now(timezone.utc).isoformat()
    try:
        from workflow_dataset.utils.hashes import stable_id
    except Exception:
        import hashlib
        def stable_id(*parts: str, prefix: str = "") -> str:
            return prefix + hashlib.sha256("".join(str(p) for p in parts).encode()).hexdigest()[:16]
    root = Path(repo_root).resolve() if repo_root else None
    ensure_default_bundles(root)
    scope_id = bundle if bundle else scope
    ctx = gather_subplan_context(project_id=project, goal_id=goal, repo_root=root)
    subplan = create_delegated_subplan(
        project_id=project,
        goal_id=goal,
        goal_text=ctx.get("goal_text", ""),
        scope_id=scope_id,
        plan=ctx.get("plan"),
        bundle_id=bundle,
        repo_root=root,
    )
    lane_id = stable_id("lane", project, goal, scope_id, utc_now_iso(), prefix="")[:20]
    perms = LanePermissions()
    bundle_id_used = ""
    if bundle:
        b = load_bundle(bundle, root)
        if b:
            perms = b.default_permissions
            bundle_id_used = bundle
    lane = WorkerLane(
        lane_id=lane_id,
        project_id=project,
        goal_id=goal,
        scope=subplan.scope,
        permissions=perms,
        status=LANE_STATUS_OPEN,
        subplan=subplan,
        created_at=utc_now_iso(),
        updated_at=utc_now_iso(),
        bundle_id=bundle_id_used,
    )
    save_lane(lane, root)
    console.print(f"[green]Created lane: {lane_id}[/green]  project={project}  goal={goal}  scope={scope_id}" + (f"  bundle={bundle}" if bundle else ""))


@lanes_group.command("status")
def lanes_status_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Lane id"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Show status and summary for one worker lane."""
    from workflow_dataset.lanes.store import load_lane
    root = Path(repo_root).resolve() if repo_root else None
    lane = load_lane(id, root)
    if not lane:
        console.print(f"[red]Lane not found: {id}[/red]")
        raise typer.Exit(1)
    console.print(f"lane_id: {lane.lane_id}")
    console.print(f"project_id: {lane.project_id}  goal_id: {lane.goal_id}")
    console.print(f"status: {lane.status}  scope: {lane.scope.scope_id}")
    if lane.subplan:
        console.print(f"subplan: {lane.subplan.subplan_id}  steps: {len(lane.subplan.steps)}")
    if lane.failure:
        console.print(f"blocked: {lane.failure.reason}")
    console.print(f"artifacts: {len(lane.artifacts)}")
    if lane.trust_summary or lane.readiness_status:
        from workflow_dataset.lanes.execution import format_lane_trust_readiness
        console.print(format_lane_trust_readiness(lane))


