production_runbook_group = typer.Typer(
    help="Production runbook for chosen vertical: operating checklist, daily review, recovery/support paths.",
)
app.add_typer(production_runbook_group, name="production-runbook")


@production_runbook_group.command("show")
def production_runbook_show_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
    vertical_id: str = typer.Option("", "--vertical", "-v", help="Vertical id (default: active vertical)"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show production runbook for the chosen (or specified) vertical."""
    from workflow_dataset.production_launch import get_production_runbook
    from workflow_dataset.vertical_selection import get_active_vertical_id
    root = Path(repo_root).resolve() if repo_root else None
    vid = vertical_id or (get_active_vertical_id(root) if root else get_active_vertical_id())
    runbook = get_production_runbook(vid, root)
    if json_out:
        import json
        console.print(json.dumps(runbook.to_dict(), indent=2))
        return
    console.print(Panel(runbook.label, title="Production runbook"))
    console.print(runbook.description or "")
    console.print("\n[bold]Operating checklist[/bold]")
    for c in runbook.operating_checklist:
        console.print(f"  [{('required' if c.required else 'optional')}] {c.label}: {c.command_or_ref}")
    console.print("\n[bold]Daily operating review[/bold]")
    for d in runbook.daily_operating_review:
        console.print(f"  {d.frequency}: {d.label} — {d.command_or_ref}")
    console.print("\n[bold]Recovery / escalation paths[/bold]")
    for r in runbook.recovery_paths:
        console.print(f"  {r.path_id}: {r.label} — {r.first_step_command}")
    console.print("\n[bold]Support paths[/bold]")
    for s in runbook.support_paths:
        console.print(f"  {s.path_id}: {s.label} — {s.command_or_ref}")
    console.print("\n[bold]Trusted routine review steps[/bold]")
    for t in runbook.trusted_routine_review_steps:
        console.print(f"  {t.when}: {t.label} — {t.command_or_ref}")


@production_runbook_group.command("review-cycle")
def production_runbook_review_cycle_cmd(
    action: str = typer.Argument("show", help="show | record"),
    repo_root: str = typer.Option("", "--repo-root"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Production review cycle: show current snapshot or record to review_cycles.json."""
    from workflow_dataset.production_launch import (
        build_production_review_cycle,
        record_review_cycle,
        list_review_cycles,
    )
    root = Path(repo_root).resolve() if repo_root else None
    if action == "record":
        path = record_review_cycle(root)
        console.print(f"[green]Recorded review cycle to {path}[/green]")
        return
    data = build_production_review_cycle(root)
    if json_out:
        import json
        console.print(json.dumps(data, indent=2))
        return
    cy = data["cycle"]
    console.print(f"[bold]Production review cycle[/bold]  {cy.get('at_iso', '—')}  guidance={cy.get('guidance_snapshot', '—')}")
    console.print(cy.get("summary", ""))
    if cy.get("findings"):
        console.print("Findings:")
        for f in cy["findings"]:
            console.print(f"  - {f}")
    console.print("Recommended actions:", ", ".join(cy.get("recommended_actions", [])[:5]))
    cycles = list_review_cycles(root, limit=5)
    console.print(f"\nRecorded cycles: {len(cycles)} (use review-cycle record to save this snapshot)")


@production_runbook_group.command("sustained-use")
def production_runbook_sustained_use_cmd(
    action: str = typer.Argument("checkpoint", help="checkpoint | report"),
    kind: str = typer.Option("auto", "--kind", "-k", help="session_5 | session_10 | day_7 | auto"),
    record: bool = typer.Option(False, "--record", "-r", help="Persist checkpoint to sustained_use_checkpoints.json"),
    repo_root: str = typer.Option("", "--repo-root"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Sustained-use checkpoint or report. checkpoint=build (optionally record); report=full checkpoint + guidance."""
    from workflow_dataset.production_launch import (
        build_sustained_use_checkpoint,
        record_sustained_use_checkpoint,
        list_sustained_use_checkpoints,
    )
    root = Path(repo_root).resolve() if repo_root else None
    if action == "report":
        data = build_sustained_use_checkpoint(root, kind=kind)
        if json_out:
            import json
            console.print(json.dumps(data, indent=2))
            return
        cp = data["checkpoint"]
        console.print(f"[bold]Sustained-use checkpoint[/bold]  kind={cp.get('kind')}  criteria_met={cp.get('criteria_met')}  guidance={cp.get('guidance')}")
        console.print(cp.get("report_summary", ""))
        console.print("Context:", cp.get("sessions_or_days_context", {}))
        console.print("Recommended actions:", data.get("post_deployment_guidance", {}).get("recommended_actions", [])[:5])
        console.print("Next:", data.get("next_recommended", ""))
        return
    data = build_sustained_use_checkpoint(root, kind=kind)
    if record:
        path = record_sustained_use_checkpoint(root, kind=kind)
        console.print(f"[green]Recorded to {path}[/green]")
    if json_out:
        import json
        console.print(json.dumps(data, indent=2))
        return
    cp = data["checkpoint"]
    console.print(f"[bold]Sustained-use checkpoint[/bold]  kind={cp.get('kind')}  criteria_met={cp.get('criteria_met')}  guidance={cp.get('guidance')}")
    console.print(cp.get("report_summary", ""))
    console.print(f"Recorded checkpoints: {len(list_sustained_use_checkpoints(root))}  (use --record to save)")


