@production_gates_group.command("evaluate")
def production_gates_evaluate_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Evaluate all production release gates. Pass/fail and detail per gate."""
    from workflow_dataset.production_launch import evaluate_production_gates
    root = Path(repo_root).resolve() if repo_root else None
    results = evaluate_production_gates(root)
