production_cut_group = typer.Typer(
    help="Production cut: final vertical lock, frozen scope, included/excluded/quarantined surfaces. M40A–M40D.",
)
app.add_typer(production_cut_group, name="production-cut")


@production_cut_group.command("show")
def production_cut_show_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show active production cut (vertical, frozen scope, defaults)."""
    from workflow_dataset.production_cut import get_active_cut
    root = Path(repo).resolve() if repo else None
    cut = get_active_cut(root)
    if not cut:
        console.print("[yellow]No active production cut. Use: workflow-dataset production-cut lock --id <vertical_id>[/yellow]")
        raise SystemExit(0)
    if json_out:
        console.print(json.dumps(cut.to_dict(), indent=2))
        return
    console.print(f"[bold]Production cut[/bold]  {cut.cut_id}  ({cut.label})")
    console.print(f"  vertical={cut.vertical_id}  frozen_at={cut.frozen_at_utc}")
    console.print(f"  included={len(cut.included_surface_ids)}  excluded={len(cut.excluded_surface_ids)}  quarantined={len(cut.quarantined_surface_ids)}")
    if cut.chosen_vertical:
        console.print("  reason: " + (cut.chosen_vertical.selection_reason or "")[:120])
    if cut.supported_workflows:
        console.print("  workflows: " + ", ".join(cut.supported_workflows.workflow_ids[:6]))
    if cut.default_profile:
        console.print(f"  default_workday={cut.default_profile.workday_preset_id}  default_experience={cut.default_profile.default_experience_profile_id}")
    if cut.required_trust:
        console.print(f"  trust_preset={cut.required_trust.trust_preset_id}")


@production_cut_group.command("lock")
def production_cut_lock_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Vertical id to lock as production cut (e.g. founder_operator_core)"),
    cut_id: str = typer.Option("", "--cut-id", help="Cut id (default: <vertical_id>_primary)"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Lock production cut for vertical: set active cut, active vertical, active pack; freeze scope."""
    from workflow_dataset.production_cut import lock_production_cut
    root = Path(repo).resolve() if repo else None
    cut = lock_production_cut(id, cut_id=cut_id or None, repo_root=str(root) if root else None)
    if not cut:
        console.print(f"[red]Could not lock production cut for vertical: {id}. Check vertical and pack exist.[/red]")
        raise SystemExit(1)
    if json_out:
        console.print(json.dumps(cut.to_dict(), indent=2))
        return
    console.print(f"[green]Production cut locked[/green]  {cut.cut_id}  vertical={cut.vertical_id}")
    console.print("  Next: workflow-dataset production-cut scope  |  production-cut surfaces")


@production_cut_group.command("scope")
def production_cut_scope_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show frozen-scope report for active production cut (included / excluded / quarantined)."""
    from workflow_dataset.production_cut import get_active_cut, build_frozen_scope_report
    root = Path(repo).resolve() if repo else None
    cut = get_active_cut(root)
    report = build_frozen_scope_report(cut=cut, repo_root=str(root) if root else None)
    if report.get("error"):
        console.print("[yellow]" + report["error"] + "[/yellow]")
        raise SystemExit(0)
    if json_out:
        console.print(json.dumps(report, indent=2))
        return
    console.print(f"[bold]Frozen scope[/bold]  vertical={report.get('vertical_id')}  included={report.get('included_count')}  excluded={report.get('excluded_count')}  quarantined={report.get('quarantined_count')}")
    if report.get("top_scope_risk"):
        console.print("  risk: " + report["top_scope_risk"])
    console.print("\n[dim]Included (default-visible):[/dim] " + ", ".join(e.get("surface_id", "") for e in report.get("included", [])[:12]))
    console.print("[dim]Quarantined (experimental):[/dim] " + ", ".join(e.get("surface_id", "") for e in report.get("quarantined", [])[:8]))


@production_cut_group.command("explain")
def production_cut_explain_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Explain active production cut: why vertical chosen, what's in/out, defaults."""
    from workflow_dataset.production_cut import get_active_cut, explain_production_cut
    root = Path(repo).resolve() if repo else None
    cut = get_active_cut(root)
    if not cut:
        console.print("[yellow]No active production cut.[/yellow]")
        raise SystemExit(0)
    out = explain_production_cut(cut)
    if json_out:
        console.print(json.dumps(out, indent=2))
        return
    console.print(f"[bold]{out.get('label')}[/bold]  {out.get('cut_id')}")
    console.print("  " + (out.get("selection_reason") or "")[:200])
    console.print(f"  included={out.get('included_count')}  excluded={out.get('excluded_count')}  quarantined={out.get('quarantined_count')}")
    console.print("  workflows: " + ", ".join(out.get("primary_workflow_ids", [])[:6]))
    console.print(f"  default_workday={out.get('default_workday')}  default_experience={out.get('default_experience')}  trust={out.get('trust_preset')}")


@production_cut_group.command("surfaces")
def production_cut_surfaces_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List included, excluded, and quarantined surfaces for active production cut."""
    from workflow_dataset.production_cut import get_active_cut, build_surfaces_classification
    root = Path(repo).resolve() if repo else None
    cut = get_active_cut(root)
    classification = build_surfaces_classification(cut=cut, repo_root=str(root) if root else None)
    if json_out:
        console.print(json.dumps(classification, indent=2))
        return
    console.print("[bold]Included (default-visible)[/bold]")
    for e in classification.get("included", [])[:20]:
        console.print(f"  {e.get('surface_id')}  {e.get('label')}  level={e.get('policy_level')}")
    console.print("\n[bold]Excluded[/bold]")
    for e in classification.get("excluded", [])[:15]:
        console.print(f"  {e.get('surface_id')}  {e.get('label')}  reason={e.get('reason')}")
    console.print("\n[bold]Quarantined (experimental)[/bold]")
    for e in classification.get("quarantined", [])[:15]:
        console.print(f"  {e.get('surface_id')}  {e.get('label')}  reveal={e.get('reveal_rule')}")


