@v1_contract_group.command("stable-pack")
def v1_contract_stable_pack_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Stable v1 communication pack: safe to rely on vs exploratory. M50D.1."""
    from workflow_dataset.v1_contract import build_stable_v1_communication_pack
    root = Path(repo_root).resolve() if repo_root else None
    pack = build_stable_v1_communication_pack(repo_root=root)
    if json_out:
        console.print(json.dumps(pack.to_dict(), indent=2))
        return
    console.print(pack.headline)
    console.print("  " + pack.stable_surfaces_summary)
    console.print("  " + pack.stable_workflows_summary)
    console.print("  Support: " + pack.support_commitment_one_liner)
    console.print("  Exploratory: " + pack.exploratory_summary_one_liner)
    for s in pack.safe_to_rely_on[:10]:
        console.print("  [green]•[/green] %s: %s" % (s.label, s.one_liner))
    if len(pack.safe_to_rely_on) > 10:
        console.print("  ... and %d more safe" % (len(pack.safe_to_rely_on) - 10))
    for d in pack.do_not_rely_on[:10]:
        console.print("  [yellow]•[/yellow] %s: %s" % (d.label, d.one_liner))
    if len(pack.do_not_rely_on) > 10:
        console.print("  ... and %d more do-not-rely-on" % (len(pack.do_not_rely_on) - 10))


