# ----- M48A–M48D Governance: role model, scope-bound authority, check, explain -----
governance_group = typer.Typer(
    help="Governance: roles, scope-bound authority, check action, explain authority. M48A–M48D.",
)
app.add_typer(governance_group, name="governance")


@governance_group.command("roles")
def governance_roles_cmd(
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List defined human roles (operator, reviewer, approver, maintainer, observer, support_reviewer)."""
    from workflow_dataset.governance import list_roles
    roles = list_roles()
    if json_out:
        console.print(json.dumps([r.to_dict() for r in roles], indent=2))
        return
    for r in roles:
        console.print(f"  {r.role_id}  {r.label}  tier={r.default_authority_tier_id}  review={r.may_review}  approve={r.may_approve}")


@governance_group.command("role")
def governance_role_cmd(
    id_arg: str = typer.Option(..., "--id", "-i", help="Role id (operator, reviewer, approver, maintainer, observer, support_reviewer)"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show role definition and effective surfaces/actions."""
    from workflow_dataset.governance import get_role
    role = get_role(id_arg)
    if role is None:
        console.print(f"[yellow]Unknown role: {id_arg}. Use: workflow-dataset governance roles[/yellow]")
        return
    if json_out:
        console.print(json.dumps(role.to_dict(), indent=2))
        return
    console.print(f"[bold]{role.label}[/bold]  {role.role_id}  {role.description}")
    console.print(f"  tier={role.default_authority_tier_id}  may_review={role.may_review}  may_approve={role.may_approve}  may_execute={role.may_execute}")
    console.print("  allowed_surfaces: " + ", ".join(role.allowed_surface_ids[:10]) or "—")
    console.print("  forbidden_surfaces: " + ", ".join(role.forbidden_surface_ids[:8]) or "—")
    console.print("  allowed_actions: " + ", ".join(role.allowed_action_classes[:8]) or "—")


@governance_group.command("check")
def governance_check_cmd(
    role_id: str = typer.Option(..., "--role", "-r", help="Role id"),
    action: str = typer.Option(..., "--action", "-a", help="Action class (e.g. execute_simulate, commit_or_send, queued_execute)"),
    surface: str = typer.Option("", "--surface", "-s", help="Optional surface id"),
    scope: str = typer.Option("", "--scope", help="Scope hint: product_wide, vertical, project:<id>, review_domain:<id>"),
    repo: str = typer.Option("", "--repo"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Check whether role may perform action (and optionally on surface)."""
    from workflow_dataset.governance import can_role_perform_action
    root = Path(repo).resolve() if repo else None
    result = can_role_perform_action(role_id, action, scope or None, surface or None, root)
    if json_out:
        console.print(json.dumps(result.to_dict(), indent=2))
        return
    if result.allowed:
        console.print(f"[green]Allowed[/green]  role={role_id}  action={action}  scope={result.binding_scope}")
        console.print(f"  {result.reason}")
    else:
        console.print(f"[red]Blocked[/red]  role={role_id}  action={action}")
        console.print(f"  {result.reason}")
        if result.required_review:
            console.print("  required_review=True")
        if result.required_approval:
            console.print("  required_approval=True")
        if result.escalation_path:
            console.print(f"  escalate: {result.escalation_path.to_role_id} — {result.escalation_path.description}")


@governance_group.command("explain")
def governance_explain_cmd(
    role_id: str = typer.Option(..., "--role", "-r", help="Role id"),
    surface: str = typer.Option("", "--surface", "-s", help="Surface id to explain"),
    action: str = typer.Option("", "--action", "-a", help="Action class to explain"),
    scope: str = typer.Option("", "--scope", help="Scope hint"),
    repo: str = typer.Option("", "--repo"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Explain authority for role: allowed/blocked surfaces and actions, review/override, escalation."""
    from workflow_dataset.governance import explain_authority
    root = Path(repo).resolve() if repo else None
    expl = explain_authority(role_id, surface or None, action or None, scope or None, root)
    if expl is None:
        console.print("[yellow]No explanation available.[/yellow]")
        return
    if json_out:
        console.print(json.dumps(expl.to_dict(), indent=2))
        return
    console.print(f"[bold]{expl.summary}[/bold]")
    console.print(f"  scope: {expl.scope_context}")
    if expl.allowed_surfaces:
        console.print("  allowed_surfaces: " + ", ".join(expl.allowed_surfaces[:8]))
    if expl.blocked_surfaces:
        console.print("  blocked_surfaces: " + ", ".join(expl.blocked_surfaces[:8]))
    if expl.required_review:
        console.print("  required_review: " + expl.required_review)
    if expl.override_required:
        console.print("  override_required: " + expl.override_required)
    if expl.escalation_path:
        console.print("  escalation: " + expl.escalation_path)


@governance_group.command("preset")
def governance_preset_cmd(
    action: str = typer.Argument("show", help="show | list | set"),
    preset_id: str = typer.Option("", "--preset", "-p", help="Preset id for set: solo_operator, supervised_team, production_maintainer"),
    repo: str = typer.Option("", "--repo"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show active governance preset, list presets, or set active preset. M48D.1."""
    from workflow_dataset.governance.presets import get_active_preset, list_presets, set_active_preset, get_preset
    root = Path(repo).resolve() if repo else None
    if action == "set" and preset_id:
        p = get_preset(preset_id)
        if not p:
            console.print(f"[red]Unknown preset: {preset_id}. Use: solo_operator | supervised_team | production_maintainer[/red]")
            raise SystemExit(1)
        path = set_active_preset(preset_id, root)
        console.print(f"[green]Active preset set to[/green] {preset_id}  (saved to {path})")
        return
    if action == "list":
        presets = list_presets()
        if json_out:
            console.print(json.dumps([x.to_dict() for x in presets], indent=2))
            return
        for p in presets:
            console.print(f"  {p.preset_id}  {p.label}  primary_role={p.primary_role_id}  trust={p.trust_preset_id}")
        return
    active = get_active_preset(root)
    if json_out:
        console.print(json.dumps(active.to_dict() if active else {}, indent=2))
        return
    if active is None:
        console.print("[dim]No active preset (default: solo_operator). Use: governance preset set --preset <id>[/dim]")
        return
    from workflow_dataset.governance.reports import format_governance_preset_report
    console.print(format_governance_preset_report(root))


@governance_group.command("scope-templates")
def governance_scope_templates_cmd(
    action: str = typer.Argument("list", help="list | show"),
    template_id: str = typer.Option("", "--id", "-i", help="Template id for show: solo_vertical, team_vertical_project, production_single_vertical"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List or show scope templates for common deployment patterns. M48D.1."""
    from workflow_dataset.governance.scope_templates import list_scope_templates, get_scope_template
    if action == "show" and template_id:
        t = get_scope_template(template_id)
        if not t:
            console.print(f"[yellow]Unknown template: {template_id}. Use: governance scope-templates list[/yellow]")
            return
        if json_out:
            console.print(json.dumps(t.to_dict(), indent=2))
            return
        console.print(f"[bold]{t.label}[/bold]  id={t.template_id}  pattern={t.deployment_pattern}")
        console.print(f"  {t.description}")
        console.print("  scope_levels: " + ", ".join(t.scope_levels))
        console.print("  default_scope_hint: " + t.default_scope_hint)
        return
    templates = list_scope_templates()
    if json_out:
        console.print(json.dumps([x.to_dict() for x in templates], indent=2))
        return
    for t in templates:
        console.print(f"  {t.template_id}  {t.label}  pattern={t.deployment_pattern}  default_scope={t.default_scope_hint}")


