    console.print("  pause: min_blockers=%s min_failed_gates=%s" % (th.min_blockers_pause, th.min_failed_gates_pause))
    console.print("  watch: use_when_weak_evidence=%s use_when_warnings_in_band=%s" % (th.use_watch_when_weak_evidence, th.use_watch_when_warnings_in_band))


