@quality_guidance_group.command("explain")
def guidance_explain_cmd(
    id_arg: str = typer.Argument(..., help="Guide id (e.g. guide_next_...)"),
    repo_root: str = typer.Option("", "--repo-root"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Explain a guidance item by id (from latest guidance set)."""
    from workflow_dataset.quality_guidance.store import get_guidance_by_id, list_latest_guide_ids
    from workflow_dataset.quality_guidance.guidance import (
        next_best_action_guidance,
        review_needed_guidance,
        blocked_state_guidance,
        resume_guidance,
        operator_routine_guidance,
        support_recovery_guidance,
    )
    from workflow_dataset.quality_guidance.store import save_latest_guidance
    root = Path(repo_root).resolve() if repo_root else None
    items = []
    for fn in [next_best_action_guidance, review_needed_guidance, blocked_state_guidance, resume_guidance, operator_routine_guidance, support_recovery_guidance]:
        try:
            g = fn(root)
            if g:
                items.append(g)
        except Exception:
            pass
    if items:
        save_latest_guidance(items, root)
    g = get_guidance_by_id(id_arg, root)
    if not g:
        console.print(f"No guidance with id '{id_arg}'. Latest ids: {', '.join(list_latest_guide_ids(root))[:200]}")
        return
    if json_out:
        import json
        console.print(json.dumps(g, indent=2))
        return
    console.print(f"[bold]{g.get('summary', '')}[/bold]  id={g.get('guide_id', '')}")
    console.print(g.get("rationale", ""))
    console.print("  Evidence:", ", ".join(g.get("evidence_refs", [])))


