@app.command("production-readiness")
def production_readiness_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Aggregate production readiness: release readiness + production gates + launch decision recommendation."""
    from workflow_dataset.release_readiness import format_release_readiness_report
    from workflow_dataset.production_launch import evaluate_production_gates, build_launch_decision_pack
    root = Path(repo_root).resolve() if repo_root else None
    console.print(format_release_readiness_report(root))
    console.print("")
    results = evaluate_production_gates(root)
    passed = sum(1 for r in results if r.passed)
    console.print(f"[bold]Production gates[/bold]  {passed}/{len(results)} passed")
    pack = build_launch_decision_pack(root)
    console.print(f"[bold]Launch decision[/bold]: {pack.get('recommended_decision', 'pause')} — {pack.get('explain', '')[:120]}")


