@memory_group.command("ingest")
def memory_ingest_cmd(
    content: str = typer.Option("", "--content", "-c", help="Raw content to ingest"),
    session_id: str = typer.Option("", "--session", "-s"),
    source: str = typer.Option("manual", "--source"),
    repo: str = typer.Option("", "--repo", "-r"),
    synthesize: bool = typer.Option(False, "--synthesize"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Ingest raw memory item(s). Pass --content once or multiple times. M43A–M43D."""
    from workflow_dataset.memory_substrate import ingest as memory_ingest
    from workflow_dataset.memory_substrate.models import MemoryItem
    from workflow_dataset.utils.dates import utc_now_iso
    from workflow_dataset.utils.hashes import stable_id
    root = Path(repo).resolve() if repo else None
    if not content.strip():
        console.print("[yellow]Provide at least one --content[/yellow]")
        raise typer.Exit(1)
    item = MemoryItem(
        item_id=stable_id("item", content[:100], session_id, utc_now_iso(), prefix="mi_"),
        content=content.strip(),
        source=source,
        source_ref="",
        timestamp_utc=utc_now_iso(),
        session_id=session_id,
    )
    units = memory_ingest([item], repo_root=root, synthesize=synthesize)
    if json_out:
        console.print(json.dumps([u.to_dict() for u in units], indent=2))
        return
    console.print(f"[green]Ingested[/green] {len(units)} unit(s)")
    for u in units:
        console.print(f"  {u.unit_id}  {u.lossless_restatement[:60]}..." if len(u.lossless_restatement) > 60 else f"  {u.unit_id}  {u.lossless_restatement}")


@memory_group.command("retrieve")
def memory_retrieve_cmd(
    query: str = typer.Option("", "--query", "-q", help="Search query"),
    session_id: str = typer.Option("", "--session", "-s", help="Filter by session"),
    source: str = typer.Option("", "--source", help="Filter by source"),
    top_k: int = typer.Option(20, "--top-k", "-n"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Retrieve memory units by query and optional filters. M43A–M43D."""
    from workflow_dataset.memory_substrate import retrieve_units
    from workflow_dataset.memory_substrate.models import RetrievalIntent
    root = Path(repo).resolve() if repo else None
    intent = RetrievalIntent(
        query=query,
        top_k=top_k,
        session_id=session_id or None,
        source=source or None,
    )
    units = retrieve_units(intent, repo_root=root)
    if json_out:
        console.print(json.dumps([u.to_dict() for u in units], indent=2))
        return
    console.print(f"[bold]Retrieved[/bold] {len(units)} unit(s)")
    for u in units:
        console.print(f"  {u.unit_id}  {u.lossless_restatement[:70]}..." if len(u.lossless_restatement) > 70 else f"  {u.unit_id}  {u.lossless_restatement}")


@memory_group.command("explain")
def memory_explain_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Explain memory substrate: what it stores, how retrieval works, backends. M43A–M43D."""
    from workflow_dataset.memory_substrate.store import get_status, get_backends
    root = Path(repo).resolve() if repo else None
    status = get_status(repo_root=root)
    backends = get_backends(repo_root=root)
    explain = {
        "what": "Durable local memory backbone: compressed units (restatement + keywords + metadata), linked to sessions.",
        "storage": "SQLite under data/local/memory_substrate/; optional in-memory backend for tests.",
        "retrieval": "Hybrid: keyword match + structured filter by session/source; optional semantic when vector backend added.",
        "backends": backends,
        "status": status,
        "cli_commands": [
            "workflow-dataset memory status",
            "workflow-dataset memory backends",
            "workflow-dataset memory ingest --content '...' [--session S]",
            "workflow-dataset memory retrieve --query '...' [--session S] [--source src]",
            "workflow-dataset memory explain",
        ],
    }
    if json_out:
        console.print(json.dumps(explain, indent=2))
        return
    console.print("[bold]Memory substrate explain[/bold]")
    console.print(f"  {explain['what']}")
    console.print(f"  storage: {explain['storage']}")
    console.print(f"  retrieval: {explain['retrieval']}")
    console.print("  cli_commands:")
    for cmd in explain["cli_commands"]:
        console.print(f"    {cmd}")


