@memory_os_group.command("retrieve")
def memory_os_retrieve_cmd(
    intent: str = typer.Option("recall_context", "--intent", "-i", help="Intent: recall_context, recall_similar_case, recall_blocker, recall_pattern, recall_decision_rationale, recall_review_history"),
    scope: str = typer.Option("project", "--scope", "-s", help="Scope surface: project, session, episode, continuity, operator, learning, cursor"),
    id: str = typer.Option("", "--id", help="Entity id (project_id, session_id, or episode_id)"),
    project_id: str = typer.Option("", "--project-id", "-p"),
    session_id: str = typer.Option("", "--session-id"),
    query: str = typer.Option("", "--query", "-q"),
    top_k: int = typer.Option(10, "--top-k", "-n"),
    profile: str = typer.Option("", "--profile", help="Retrieval profile: conservative, continuity_heavy, operator_heavy, coding_heavy. M44D.1."),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Retrieve memory by intent and scope. Use --profile for conservative/continuity_heavy/operator_heavy/coding_heavy. Use --id for entity or --project-id/--session-id."""
    from workflow_dataset.memory_os import memory_os_retrieve
    from workflow_dataset.memory_os.models import RetrievalScope, RetrievalIntentOS
    root = Path(repo).resolve() if repo else None
    entity_id = id or project_id or session_id
    scope_obj = RetrievalScope(
        project_id=project_id or (entity_id if scope == "project" else ""),
        session_id=session_id or (entity_id if scope == "session" else ""),
        episode_id=entity_id if scope == "episode" else "",
        entity_type=scope,
        entity_id=entity_id,
    )
    intent_obj = RetrievalIntentOS(intent=intent, query=query, top_k=top_k)
    profile_id = profile if profile.strip() else None
    items, retrieval_id, explanation = memory_os_retrieve(scope, scope_obj, intent_obj, repo_root=root, profile_id=profile_id)
    if json_out:
        console.print(json.dumps({
            "retrieval_id": retrieval_id,
            "items": items,
            "explanation": explanation.to_dict(),
        }, indent=2))
        return
    console.print(f"[bold]Retrieval[/bold] {retrieval_id}")
    console.print(f"  intent={intent}  scope={scope}  count={len(items)}")
    if explanation.profile_used and explanation.profile_reason:
        console.print(f"  profile: {explanation.profile_used} — {explanation.profile_reason[:70]}{'...' if len(explanation.profile_reason) > 70 else ''}")
    for it in items[:15]:
        console.print(f"  [dim]{it.get('memory_id', '')}[/dim]  [{it.get('tier', '')}]  {(it.get('text') or '')[:70]}...")
    if explanation.weak_memory_warnings:
        console.print(f"  [yellow]Weak memory warnings: {len(explanation.weak_memory_warnings)}[/yellow]")


@memory_os_group.command("explain")
def memory_os_explain_cmd(
    id: str = typer.Argument("", help="Retrieval id (e.g. memret_...) or leave empty to run a sample retrieve"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Explain why memory was retrieved. Run a sample retrieve and show reason, evidence, confidence, weak warnings."""
    from workflow_dataset.memory_os import memory_os_retrieve
    from workflow_dataset.memory_os.explain import build_explanation
    from workflow_dataset.memory_os.models import RetrievalScope, RetrievalIntentOS
    root = Path(repo).resolve() if repo else None
    try:
        scope_obj = RetrievalScope(entity_type="session", entity_id="")
        intent_obj = RetrievalIntentOS(intent="recall_context", top_k=5)
        _, retrieval_id, explanation = memory_os_retrieve("session", scope_obj, intent_obj, repo_root=root)
        rid = id or retrieval_id
        expl = build_explanation(rid, explanation, include_evidence=True, include_weak=True)
    except Exception as e:
        expl = {"retrieval_id": id or "—", "reason": f"Sample failed: {e}", "confidence": 0}
    if json_out:
        console.print(json.dumps(expl, indent=2))
        return
    console.print(f"[bold]Explanation[/bold] {expl.get('retrieval_id', id)}")
    console.print(f"  reason: {expl.get('reason', '')}")
    console.print(f"  confidence: {expl.get('confidence', 0)}")
    if expl.get("profile_used") and expl.get("profile_reason"):
        console.print(f"  profile: {expl['profile_used']} — {expl['profile_reason']}")
    elif expl.get("profile_used"):
        console.print(f"  profile: {expl['profile_used']}")
    if expl.get("weak_memory_warnings"):
        console.print(f"  weak_warnings: {len(expl['weak_memory_warnings'])}")


