@shadow_runs_group.command("policy-list")
def shadow_runs_policy_list_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List confidence policies by loop type (built-in and any overlay)."""
    from workflow_dataset.shadow_execution.policies import BUILTIN_POLICIES, get_policy_for_loop_type
    root = Path(repo).resolve() if repo else None
    out = [p.to_dict() for p in BUILTIN_POLICIES]
    try:
        from workflow_dataset.shadow_execution.policy_store import load_policies
        overlay = load_policies(repo_root=root)
        for o in overlay:
            if not any(x.get("policy_id") == o.get("policy_id") for x in out):
                out.append(o)
    except Exception:
        pass
    if json_out:
        console.print(json.dumps(out, indent=2))
        return
    console.print("[bold]Confidence policies[/bold]")
    for p in out:
        console.print(f"  {p.get('policy_id')}  loop_type={p.get('loop_type')}  min_loop_conf={p.get('min_loop_confidence_for_bounded_real')}")


