@memory_curation_group.command("status")
def memory_curation_status_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Memory curation status: summaries, compression/forgetting candidates, review-required, archives."""
    from workflow_dataset.memory_curation.report import status as curation_status
    root = Path(repo).resolve() if repo else None
    st = curation_status(repo_root=root)
    if json_out:
        console.print(json.dumps(st, indent=2))
        return
    console.print("[bold]Memory curation status[/bold]")
    console.print(f"  summaries: {st['summaries_count']}  compression_candidates: {st['compression_candidates_count']} (applied: {st['compression_applied_count']})")
    console.print(f"  forgetting_candidates: {st['forgetting_candidates_count']} (applied: {st['forgetting_applied_count']})")
    console.print(f"  review_required: {st['review_required_count']} (pending: {st['review_required_pending_count']})")
    console.print(f"  archives: {st['archives_count']}")
    console.print(f"  curation_dir: {st['curation_dir']}")


@memory_curation_group.command("summarize")
def memory_curation_summarize_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    dry_run: bool = typer.Option(True, "--dry-run/--no-dry-run", help="Only build candidates; do not apply"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Build compression candidates and optionally apply summarization (session rollups)."""
    from workflow_dataset.memory_curation.summarization import build_compression_candidates_from_sessions
    from workflow_dataset.memory_curation.store import load_compression_candidates, save_compression_candidates, append_summary
    from workflow_dataset.memory_curation.models import SummarizedMemoryUnit
    root = Path(repo).resolve() if repo else None
    candidates = build_compression_candidates_from_sessions(repo_root=root, limit=20)
    existing = load_compression_candidates(repo_root=root)
    existing_ids = {c.candidate_id for c in existing}
    new = [c for c in candidates if c.candidate_id not in existing_ids]
    for c in new:
        existing.append(c)
    if not dry_run and new:
        save_compression_candidates(existing, repo_root=root)
        for c in new[:5]:
            summary = SummarizedMemoryUnit(
                summary_id="sum_" + c.candidate_id.replace("comp_", ""),
                summary_text=f"Session rollup: {len(c.unit_ids)} items from sessions {c.session_ids}",
                source_unit_ids=c.unit_ids,
                source_session_ids=c.session_ids,
                source_kind="session_history",
                created_at_utc=c.created_at_utc,
                keyword_tags=[],
            )
            append_summary(summary, repo_root=root)
    out = {"candidates_found": len(candidates), "new_candidates": len(new), "dry_run": dry_run}
    if json_out:
        console.print(json.dumps(out, indent=2))
        return
    console.print("[bold]Summarize[/bold]")
    console.print(f"  candidates_found: {out['candidates_found']}  new: {out['new_candidates']}  dry_run: {dry_run}")


@memory_curation_group.command("retention")
def memory_curation_retention_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show retention policies: short/medium/long/protected."""
    from workflow_dataset.memory_curation.retention import get_default_policies
    root = Path(repo).resolve() if repo else None
    policies = get_default_policies()
    if json_out:
        console.print(json.dumps([p.to_dict() for p in policies], indent=2))
        return
    console.print("[bold]Retention policies[/bold]")
    for p in policies:
        console.print(f"  {p.policy_id}: {p.label}  tier={p.retention_tier}  max_age_days={p.max_age_days}  protected={p.protected}")
        console.print(f"    {p.description}")


@memory_curation_group.command("forgetting-candidates")
def memory_curation_forgetting_candidates_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    generate: bool = typer.Option(False, "--generate", "-g", help="Regenerate from outcome history and save"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List forgetting candidates (and review-required). Use --generate to (re)build from retention policy."""
    from workflow_dataset.memory_curation.store import (
        load_forgetting_candidates,
        load_review_required,
        save_forgetting_candidates,
        save_review_required,
    )
    from workflow_dataset.memory_curation.forgetting import generate_forgetting_candidates
    from workflow_dataset.outcomes.store import load_outcome_history
    root = Path(repo).resolve() if repo else None
    if generate:
        history = load_outcome_history(repo_root=root, limit=300)
        unit_entries = [
            {
                "unit_id": e.get("session_id", "") + "_" + str(e.get("timestamp", "")),
                "created_at_utc": e.get("timestamp", ""),
                "retention_tier": "medium_term",
                "source": e.get("session_id", "default"),
            }
            for e in history
        ]
        candidates, review = generate_forgetting_candidates(unit_entries, repo_root=root)
        save_forgetting_candidates(candidates, repo_root=root)
        save_review_required(review, repo_root=root)
    forget = load_forgetting_candidates(repo_root=root)
    review = load_review_required(repo_root=root)
    if json_out:
        console.print(json.dumps({
            "forgetting_candidates": [c.to_dict() for c in forget],
            "review_required": [r.to_dict() for r in review],
        }, indent=2))
        return
    console.print("[bold]Forgetting candidates[/bold]")
    for c in forget:
        console.print(f"  {c.candidate_id}  reason={c.reason}  review_required={c.review_required}  applied={c.applied}  units={c.unit_ids[:3]}...")
    console.print("[bold]Review-required[/bold]")
    for r in review:
        if not r.reviewed:
            console.print(f"  {r.candidate_id}  forgetting={r.forgetting_candidate_id}  reason={r.reason}  approved={r.approved_for_forget}")


