# ----- M45A–M45D Adaptive execution: plans, show, explain, step, stop -----
adaptive_execution_group = typer.Typer(
    help="Adaptive execution: bounded multi-step plans, loops, step progression, stop/escalation. M45A–M45D.",
)
app.add_typer(adaptive_execution_group, name="adaptive-execution")


@adaptive_execution_group.command("plans")
def adaptive_execution_plans_cmd(
    goal: str = typer.Option("", "--goal", "-g", help="Generate a plan for this goal"),
    max_steps: int = typer.Option(20, "--max-steps", "-n"),
    profile: str = typer.Option("", "--profile", "-p", help="Execution profile: conservative, balanced, operator_heavy, review_heavy. M45D.1."),
    template: str = typer.Option("", "--template", "-t", help="Loop template: weekly_summary, approval_sweep, resume_continuity, single_job_run. M45D.1."),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List active loops or generate a new plan from a goal. Use --profile and --template for execution profile and loop template. M45D.1."""
    from workflow_dataset.adaptive_execution import list_active_loops, generate_loop_from_goal, save_loop
    root = Path(repo).resolve() if repo else None
    if goal or template:
        loop = generate_loop_from_goal(
            goal or "",
            max_steps=max_steps,
            repo_root=root,
            profile_id=profile or "",
            template_id=template or "",
        )
        save_loop(loop, root)
        if json_out:
            console.print(json.dumps(loop.to_dict(), indent=2))
            return
        console.print(f"[bold]Created loop[/bold] {loop.loop_id}  plan={loop.plan_id}  status={loop.status}  max_steps={loop.max_steps}")
        if loop.profile_id:
            console.print(f"  profile: {loop.profile_id}")
        if loop.template_id:
            console.print(f"  template: {loop.template_id}")
        console.print(f"  goal: {loop.plan.goal_text[:60] if loop.plan else ''}...")
        return
    loops = list_active_loops(repo_root=root, limit=20)
    if json_out:
        console.print(json.dumps(loops, indent=2))
        return
    console.print("[bold]Adaptive execution loops[/bold]")
    for L in loops:
        console.print(f"  {L.get('loop_id')}  status={L.get('status')}  step={L.get('current_step_index')}  branch={L.get('current_branch_id')}")


