@supervision_group.command("summary")
def supervision_summary_cmd(
    id: str = typer.Option(..., "--id", "-i"),
    preset: str = typer.Option("", "--preset", "-p", help="Override preset for this summary"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Operator-facing summary: when to continue, intervene, or terminate; suggested playbook."""
    from workflow_dataset.supervisory_control.summaries import build_operator_summary
    root = Path(repo).resolve() if repo else None
    s = build_operator_summary(id, repo_root=root, preset_id=preset or None)
    if json_out:
        console.print(json.dumps(s.to_dict(), indent=2))
        return
    console.print(f"[bold]Operator summary[/bold] loop={s.loop_id}  preset={s.preset_id}")
    if s.suggested_playbook_label:
        console.print(f"  Suggested playbook: {s.suggested_playbook_label}")
    console.print("[bold]Continue[/bold]")
    console.print(f"  {s.continue_recommendation[:80]}..." if len(s.continue_recommendation) > 80 else f"  {s.continue_recommendation}")
    console.print("[bold]Intervene[/bold]")
    console.print(f"  {s.intervene_recommendation[:80]}..." if len(s.intervene_recommendation) > 80 else f"  {s.intervene_recommendation}")
    console.print("[bold]Terminate[/bold]")
    console.print(f"  {s.terminate_recommendation[:80]}..." if len(s.terminate_recommendation) > 80 else f"  {s.terminate_recommendation}")


