@health_group.command("long-run")
def health_long_run_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    window: str = typer.Option("rolling_7", "--window", "-w", help="daily | weekly | rolling_7 | rolling_30 | rolling_long_run"),
    threshold_profile: str = typer.Option("balanced", "--threshold-profile", "-p", help="conservative | balanced | production_strict"),
    write: bool = typer.Option(False, "--write", help="Persist snapshot to data/local/long_run_health"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Build and show long-run deployment health snapshot."""
    from workflow_dataset.long_run_health import build_deployment_health_snapshot, save_snapshot, format_long_run_report
    root = Path(repo).resolve() if repo else None
    snapshot = build_deployment_health_snapshot(window_kind=window, repo_root=root, threshold_profile_id=threshold_profile)
