@health_group.command("explain")
def health_explain_cmd(
    id_arg: str = typer.Option(..., "--id", "-i", help="Drift id (e.g. drift_xxx) or snapshot id (health_xxx) to explain"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Explain a drift signal or snapshot alert state (includes short 'why' summary)."""
    from workflow_dataset.long_run_health import load_drift_signal, load_snapshot, build_deployment_health_snapshot, format_alert_explanation, format_drift_report
    root = Path(repo).resolve() if repo else None
    if (id_arg or "").startswith("drift_"):
        d = load_drift_signal(id_arg, repo_root=root)
        if not d:
            console.print(f"[yellow]Drift signal not found: {id_arg}[/yellow]")
            raise typer.Exit(1)
        if json_out:
            console.print(json.dumps(d.to_dict(), indent=2))
            return
        console.print(format_drift_report([d], title="Drift " + id_arg))
        return
    snap = load_snapshot(id_arg, repo_root=root)
    if not snap:
        snap = build_deployment_health_snapshot(repo_root=root)
    if not snap.alert_explanation:
        console.print("[dim]No alert explanation in snapshot.[/dim]")
        raise typer.Exit(0)
    if json_out:
        console.print(json.dumps(snap.alert_explanation.to_dict(), indent=2))
        return
    console.print(format_alert_explanation(snap.alert_explanation))


