@triage_group.command("list")
def triage_list_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    cohort: str = typer.Option("", "--cohort", "-c", help="Filter by cohort_id"),
    status: str = typer.Option("", "--status", "-s", help="Filter by triage status: new | investigated | reproduced | mitigated | blocked | resolved"),
    limit: int = typer.Option(50, "--limit", "-n"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List triage issues (optionally by cohort and status)."""
    from workflow_dataset.triage.store import list_issues
    root = Path(repo).resolve() if repo else None
    issues = list_issues(repo_root=root, cohort_id=cohort or "", status=status or "", limit=limit)
    if json_out:
        console.print(json.dumps([i.model_dump() for i in issues], indent=2))
        return
    console.print(f"[bold]Triage issues[/bold]  count={len(issues)}  cohort={cohort or '(all)'}  status={status or '(all)'}")
    for i in issues:
        console.print(f"  {i.issue_id}  [{i.triage_status.value}] {i.severity}  {(i.summary or '')[:50]}")


@triage_group.command("show")
def triage_show_cmd(
    id: str = typer.Option(..., "--id", "-i"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show one issue by id."""
    from workflow_dataset.triage.store import load_issue
    root = Path(repo).resolve() if repo else None
    issue = load_issue(id, repo_root=root)
    if not issue:
        console.print(f"[red]Issue not found: {id}[/red]")
        raise typer.Exit(1)
    if json_out:
        console.print(issue.model_dump_json(indent=2))
        return
    console.print(f"[bold]{issue.issue_id}[/bold]  status={issue.triage_status.value}  severity={issue.severity}")
    console.print(f"  summary: {issue.summary}")
    console.print(f"  cohort={issue.cohort_id}  evidence_ids={issue.evidence_ids}")
    if issue.supportability:
        console.print(f"  supportability: {issue.supportability.summary}")
    if issue.cohort_impact:
        console.print(f"  cohort_impact: {issue.cohort_impact.summary}")
    if issue.reproducibility_note:
        console.print(f"  reproducibility: {issue.reproducibility_note.steps_summary}")


@triage_group.command("classify")
def triage_classify_cmd(
    id: str = typer.Option(..., "--id", "-i"),
    repo: str = typer.Option("", "--repo", "-r"),
    severity: str = typer.Option("", "--severity", "-s", help="critical | high | medium | low"),
    impact_scope: str = typer.Option("", "--impact-scope", help="cohort | project | user | subsystem"),
    reproducibility: str = typer.Option("", "--reproducibility", help="yes | no | partial | unknown"),
    supported_surface: bool = typer.Option(False, "--supported-surface"),
    experimental_surface: bool = typer.Option(False, "--experimental-surface"),
    recovery_exists: bool = typer.Option(False, "--recovery-exists"),
    trust_violation: bool = typer.Option(False, "--trust-violation"),
    session_count: int = typer.Option(0, "--session-count"),
) -> None:
    """Classify an issue (severity, scope, supportability, cohort impact)."""
    from workflow_dataset.triage.store import load_issue, save_issue
    from workflow_dataset.triage.classification import apply_classification
    root = Path(repo).resolve() if repo else None
    issue = load_issue(id, repo_root=root)
    if not issue:
        console.print(f"[red]Issue not found: {id}[/red]")
        raise typer.Exit(1)
    apply_classification(
        issue,
        severity=severity or "",
        impact_scope=impact_scope or "",
        reproducibility=reproducibility or "",
        supported_surface=supported_surface,
        experimental_surface=experimental_surface,
        recovery_exists=recovery_exists,
        trust_violation=trust_violation,
        session_count_affected=session_count,
    )
    save_issue(issue, repo_root=root)
    console.print(f"[green]Classified[/green] {id}  severity={issue.severity}  impact_scope={issue.impact_scope}")


@triage_group.command("reproduce")
def triage_reproduce_cmd(
    id: str = typer.Option(..., "--id", "-i"),
    repo: str = typer.Option("", "--repo", "-r"),
    steps: str = typer.Option("", "--steps", "-s", help="Steps summary or comma-separated steps"),
) -> None:
    """Mark issue as reproduced and attach reproduction steps."""
    from workflow_dataset.triage.loop import mark_reproduced
    root = Path(repo).resolve() if repo else None
    steps_detail = [x.strip() for x in steps.split(",")] if steps else []
    updated = mark_reproduced(id, steps_summary=steps[:500] if steps else "", steps_detail=steps_detail, repo_root=root)
    if not updated:
        console.print(f"[red]Issue not found: {id}[/red]")
        raise typer.Exit(1)
    console.print(f"[green]Marked reproduced[/green] {id}")


@triage_group.command("resolve")
def triage_resolve_cmd(
    id: str = typer.Option(..., "--id", "-i"),
    repo: str = typer.Option("", "--repo", "-r"),
) -> None:
    """Mark issue as resolved."""
    from workflow_dataset.triage.store import update_triage_status
    from workflow_dataset.triage.models import TriageStatus
    root = Path(repo).resolve() if repo else None
    updated = update_triage_status(id, TriageStatus.RESOLVED, repo_root=root)
    if not updated:
        console.print(f"[red]Issue not found: {id}[/red]")
        raise typer.Exit(1)
    console.print(f"[green]Resolved[/green] {id}")


