@adaptation_group.command("boundary-check")
def adaptation_boundary_check_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Adaptation candidate id"),
    cohort: str = typer.Option("", "--cohort", "-c", help="Cohort id (default: candidate's cohort)"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Run boundary check for a candidate: supported/experimental/blocked, safe_for_cohort, must_quarantine."""
    from workflow_dataset.safe_adaptation import load_candidate, evaluate_boundary_check
    root = Path(repo).resolve() if repo else None
