@learning_lab_group.command("memory-slices")
def learning_lab_memory_slices_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    scope: str = typer.Option("", "--scope", "-s", help="Filter: production_safe | experimental"),
    limit: int = typer.Option(30, "--limit", "-n"),
    create_from: str = typer.Option("", "--create-from", help="Create experiment from this memory_slice_id (e.g. mem_exp_xxx, mem_cand_xxx, mem_corrections_recent)"),
    profile: str = typer.Option("", "--profile", "-p"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List memory-backed slices for learning-lab experiments; optionally create experiment from a memory slice. M43."""
    from workflow_dataset.learning_lab.memory_slices import list_memory_slices_for_learning, create_experiment_from_memory_slice
    root = Path(repo).resolve() if repo else None
    if create_from:
        exp = create_experiment_from_memory_slice(create_from, profile_id=profile or "", repo_root=root)
        if not exp:
            console.print(f"[red]Failed to create experiment from memory slice: {create_from}[/red]")
            raise typer.Exit(1)
        if json_out:
            console.print(json.dumps(exp.to_dict(), indent=2))
            return
        console.print(f"[green]Created experiment[/green] {exp.experiment_id}  from memory slice {create_from}")
        return
    slices = list_memory_slices_for_learning(repo_root=root, scope=scope or "", limit=limit)
    if json_out:
        console.print(json.dumps([s.to_dict() for s in slices], indent=2))
        return
    console.print(f"[bold]Memory-backed slices[/bold]  count={len(slices)}  scope={scope or '(all)'}")
    for s in slices:
        console.print(f"  {s.memory_slice_id}  [{s.scope}] {s.description[:50]}  evidence={s.evidence_count}  corrections={s.correction_count}")


