@cohort_group.command("apply")
def cohort_apply_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Cohort profile id to set as active"),
    repo: str = typer.Option("", "--repo", "-r"),
) -> None:
    """Set active cohort profile (does not auto-apply workday/experience; use defaults apply or day preset set)."""
    from workflow_dataset.cohort.profiles import get_cohort_profile
    from workflow_dataset.cohort.store import set_active_cohort_id
    from workflow_dataset.cohort.bindings import apply_cohort_defaults
    root = Path(repo).resolve() if repo else None
    p = get_cohort_profile(id)
    if not p:
        console.print(f"[red]Cohort not found: {id}[/red]")
        raise SystemExit(1)
    set_active_cohort_id(p.cohort_id, repo_root=root)
    console.print(f"[green]Active cohort set to: {p.cohort_id} ({p.label})[/green]")
    defaults = apply_cohort_defaults(p.cohort_id)
    if "error" not in defaults:
        console.print(f"  Recommended: workday preset={defaults.get('default_workday_preset_id', '')}  experience={defaults.get('default_experience_profile_id', '')}")
        console.print(f"  Next: workflow-dataset day preset set --id {defaults.get('default_workday_preset_id', '')}  ;  workflow-dataset defaults apply {defaults.get('default_experience_profile_id', '')}")


@cohort_group.command("explain")
def cohort_explain_cmd(
    surface: str = typer.Option("", "--surface", "-s", help="Surface id to explain (e.g. operator_mode, mission_control)"),
    id: str = typer.Option("", "--id", "-i", help="Cohort id (default: active cohort)"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Explain surface support for cohort, or explain cohort scope (use --surface for surface, or --id only for cohort)."""
    from workflow_dataset.cohort.store import get_active_cohort_id
    from workflow_dataset.cohort.explain import explain_surface, explain_cohort
    root = Path(repo).resolve() if repo else None
    cohort_id = (id or "").strip() or get_active_cohort_id(root)
    if surface:
        out = explain_surface(surface, cohort_id or "careful_first_user")
        if json_out:
            console.print(json.dumps(out, indent=2))
            return
        console.print(f"{out['surface_id']}  cohort={out['cohort_id']}  level={out['support_level']}")
        console.print(f"  {out['reason']}")
        if out.get("command_hint"):
            console.print(f"  command: {out['command_hint']}")
    else:
        if not cohort_id:
            console.print("[yellow]No active cohort; use --id <cohort_id> or cohort apply --id <cohort_id>[/yellow]")
            cohort_id = "careful_first_user"
        out = explain_cohort(cohort_id)
        if out.get("error"):
            console.print(f"[red]{out['error']}[/red]")
            raise SystemExit(1)
        if json_out:
            console.print(json.dumps(out, indent=2))
            return
        console.print(f"{out['cohort_id']}  {out['label']}")
        console.print(f"  supported={out['supported_count']}  experimental={out['experimental_count']}  blocked={out['blocked_count']}")
        console.print(f"  allowed_automation_scope={out.get('allowed_automation_scope', '')}  required_readiness={out.get('required_readiness', '')}")


@cohort_group.command("gates")
def cohort_gates_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Cohort profile id"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List readiness gates for cohort and optionally evaluate them (M38D.1)."""
    from workflow_dataset.cohort.profiles import get_cohort_profile
    from workflow_dataset.cohort.gates import get_gates_for_cohort, evaluate_gates
    root = Path(repo).resolve() if repo else None
    p = get_cohort_profile(id)
    if not p:
        console.print(f"[red]Cohort not found: {id}[/red]")
        raise SystemExit(1)
    gates = get_gates_for_cohort(id)
    if json_out:
        results = evaluate_gates(id, root)
        console.print(json.dumps({"cohort_id": id, "gates_count": len(gates), "results": results}, indent=2))
        return
    console.print(f"[bold]Readiness gates[/bold]  cohort={id}  count={len(gates)}")
    if not gates:
        console.print("  (no gates; cohort has required_readiness=any)")
        return
    results = evaluate_gates(id, root)
    for r in results:
        status = "[green]pass[/green]" if r.get("passed") else "[red]fail[/red]"
        console.print(f"  {r.get('gate_id', '')}  {status}  {r.get('message', '')[:60]}")


@cohort_group.command("transitions")
def cohort_transitions_cmd(
    id: str = typer.Option("", "--id", "-i", help="Cohort profile id (default: active)"),
    direction: str = typer.Option("", "--direction", "-d", help="escalation | downgrade"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List escalation/downgrade paths for cohort (M38D.1)."""
    from workflow_dataset.cohort.store import get_active_cohort_id
    from workflow_dataset.cohort.profiles import get_cohort_profile
    from workflow_dataset.cohort.transitions import get_transitions_for_cohort
    root = Path(repo).resolve() if repo else None
    cohort_id = (id or "").strip() or get_active_cohort_id(root)
    if not cohort_id:
        cohort_id = "careful_first_user"
    direction_filter = (direction or "").strip().lower() or None
    transitions = get_transitions_for_cohort(cohort_id, direction=direction_filter)
    if json_out:
        console.print(json.dumps([t.to_dict() for t in transitions], indent=2))
        return
    p = get_cohort_profile(cohort_id)
    console.print(f"[bold]Cohort transitions[/bold]  cohort={cohort_id}  {p.label if p else ''}  direction={direction_filter or 'all'}")
    for t in transitions:
        console.print(f"  {t.from_cohort_id} -> {t.to_cohort_id}  [{t.direction}]  trigger={t.trigger}")
        console.print(f"    {t.criteria_hint[:70]}")


@cohort_group.command("recommend")
def cohort_recommend_cmd(
    id: str = typer.Option("", "--id", "-i", help="Cohort profile id (default: active)"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Recommend cohort transition based on current state: triage, release readiness, gates (M38D.1)."""
    from workflow_dataset.cohort.store import get_active_cohort_id
    from workflow_dataset.cohort.transitions import get_recommended_transition
    root = Path(repo).resolve() if repo else None
    cohort_id = (id or "").strip() or get_active_cohort_id(root)
    rec = get_recommended_transition(cohort_id or "", root)
    if json_out:
        console.print(json.dumps(rec if rec else {}, indent=2))
        return
    if not rec:
        console.print("[dim]No transition recommended; current cohort and state are OK.[/dim]")
        return
    console.print(f"[bold]Recommended transition[/bold]  {rec.get('direction', '')} -> {rec.get('suggested_cohort_id', '')}")
    console.print(f"  reason: {rec.get('reason', '')}")
    console.print(f"  trigger: {rec.get('trigger', '')}")
    console.print(f"  To apply: workflow-dataset cohort apply --id {rec.get('suggested_cohort_id', '')}")


@cohort_group.command("health")
def cohort_health_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    cohort: str = typer.Option("", "--cohort", "-c", help="Cohort id (default: all)"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Cohort health summary: open issues, highest severity, clusters, recommended mitigation."""
    from workflow_dataset.triage.health import build_cohort_health_summary
    root = Path(repo).resolve() if repo else None
    report = build_cohort_health_summary(repo_root=root, cohort_id=cohort or "")
    if json_out:
        console.print(json.dumps(report, indent=2))
        return
    console.print(f"[bold]Cohort health[/bold]  cohort={report['cohort_id']}")
    console.print(f"  open_issues={report['open_issue_count']}  total={report['total_issue_count']}  evidence={report['evidence_count']}")
    console.print(f"  highest_severity={report['highest_severity']}  unresolved_supported_surface={report['unresolved_supported_surface_count']}")
    console.print(f"  recommended_mitigation: {report['recommended_mitigation']}")
    if report.get("recommended_downgrade"):
        console.print("  [yellow]recommended_downgrade=True[/yellow]")
    if report.get("operator_do_now"):
        console.print(f"  operator_do_now: {report['operator_do_now']}")
    if report.get("open_issue_count", 0) > 0 and (report.get("link_support") or report.get("link_recovery") or report.get("link_readiness")):
        console.print("  [dim]Next: support → " + str(report.get("link_support", "")) + "  recovery → " + str(report.get("link_recovery", "")) + "  readiness → " + str(report.get("link_readiness", "")) + "[/dim]")


