@verticals_group.command("show")
def verticals_show_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Vertical id (e.g. founder_operator_core, analyst_core)"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show one vertical candidate (scores, core workflows, surfaces)."""
    from workflow_dataset.vertical_selection import explain_vertical
    root = Path(repo).resolve() if repo else None
    out = explain_vertical(id, root)
    if out.get("error"):
        console.print(f"[red]{out['error']}[/red]")
        raise SystemExit(1)
    if json_out:
        console.print(json.dumps(out, indent=2))
        return
    console.print(f"[bold]{out.get('vertical_id')}[/bold]  {out.get('label')}  rank={out.get('rank')}")
    console.print(f"  evidence={out.get('evidence_score')}  readiness={out.get('readiness_score')}  burden={out.get('support_burden_score')}")
    console.print("  strength: " + str(out.get("strength_reason", ""))[:60])
    console.print("  weakness: " + str(out.get("weakness_reason", ""))[:60])
    console.print("  core_workflows: " + ", ".join(out.get("core_workflow_ids", [])[:5]))
    console.print("  required_surfaces: " + ", ".join(out.get("required_surface_ids", [])[:8]))


