    console.print("  allowed: " + str(report["allowed_count"]) + "  " + ", ".join(report["allowed_surfaces"][:8]))
    console.print("  discouraged: " + str(report["discouraged_count"]))
    console.print("  blocked: " + str(report["blocked_count"]) + "  " + ", ".join(report["blocked_surfaces"][:5]))
