def _normalize_launch_kit_id(id: str) -> str:
    if not id:
        return ""
    return id if id.endswith("_launch") else f"{id}_launch"


@launch_kit_group.command("list")
def launch_kit_list_cmd(
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List vertical launch kit ids (from curated packs with playbooks)."""
    from workflow_dataset.vertical_launch import list_launch_kits
    kits = list_launch_kits()
    if json_out:
        console.print(json.dumps([k.to_dict() for k in kits], indent=2))
        return
    console.print("[bold]Vertical launch kits[/bold]")
    for k in kits:
        console.print(f"  {k.launch_kit_id}  {k.label}")


@launch_kit_group.command("show")
def launch_kit_show_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Launch kit id (e.g. founder_operator_launch or founder_operator_core)"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show one vertical launch kit (setup, path, proofs, operator playbook)."""
    from workflow_dataset.vertical_launch import build_launch_kit_for_vertical
    kid = _normalize_launch_kit_id(id)
    pack_id = kid.replace("_launch", "") if kid else id
    kit = build_launch_kit_for_vertical(pack_id)
    if kit.launch_kit_id != kid and not id.endswith("_launch"):
        kit = build_launch_kit_for_vertical(id)
    if json_out:
        console.print(json.dumps(kit.to_dict(), indent=2))
        return
    console.print(f"[bold]{kit.label}[/bold]  ({kit.launch_kit_id})")
    console.print(f"  {kit.description}")
    console.print(f"  curated_pack_id={kit.curated_pack_id}  entry_point={kit.first_run_path.entry_point}")
    console.print("  setup: " + str([i.get("id") for i in kit.required_setup.items]))
    console.print("  proofs: " + str([m.proof_id for m in kit.success_proof_metrics[:5]]) + "...")


@launch_kit_group.command("start")
def launch_kit_start_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Launch kit id"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Start a vertical launch (set active launch kit and active pack; record launch_started_at)."""
    from workflow_dataset.vertical_launch import build_launch_kit_for_vertical, set_active_launch
    from workflow_dataset.vertical_packs import set_active_pack
    kid = _normalize_launch_kit_id(id)
    pack_id = kid.replace("_launch", "") if kid else id
    kit = build_launch_kit_for_vertical(pack_id)
    root = Path(repo).resolve() if repo else None
    set_active_launch(kit.launch_kit_id, kit.curated_pack_id, repo_root=root)
    set_active_pack(kit.curated_pack_id, repo_root=root)
    if json_out:
        console.print(json.dumps({"launch_kit_id": kit.launch_kit_id, "curated_pack_id": kit.curated_pack_id, "started": True}, indent=2))
        return
    console.print(f"[green]Launch started[/green]  {kit.launch_kit_id}  pack={kit.curated_pack_id}")
    console.print("  Next: workflow-dataset success-proof report --id " + kit.launch_kit_id)
    console.print("  First-value: workflow-dataset vertical-packs first-value --id " + kit.curated_pack_id)


