@rollout_review_group.command("record")
def rollout_review_record_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Launch kit id or curated pack id"),
    decision: str = typer.Option(..., "--decision", "-d", help="continue | narrow | pause | expand"),
    rationale: str = typer.Option("", "--rationale", "-r"),
    repo: str = typer.Option("", "--repo"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Record a rollout decision for a vertical (continue / narrow / pause / expand)."""
    from workflow_dataset.vertical_launch.store import save_rollout_decision
    from workflow_dataset.vertical_launch.models import ROLLOUT_CONTINUE, ROLLOUT_NARROW, ROLLOUT_PAUSE, ROLLOUT_EXPAND
    kid = id if id.endswith("_launch") else (id + "_launch" if id else "")
    pack_id = kid.replace("_launch", "") if kid else id
    if decision not in (ROLLOUT_CONTINUE, ROLLOUT_NARROW, ROLLOUT_PAUSE, ROLLOUT_EXPAND):
        console.print(f"[red]Invalid decision: {decision}. Use continue, narrow, pause, or expand.[/red]")
        raise typer.Exit(1)
    root = Path(repo).resolve() if repo else None
    path = save_rollout_decision(pack_id, kid or pack_id + "_launch", decision, rationale=rationale, repo_root=root)
    if json_out:
        console.print(json.dumps({"recorded": True, "vertical_id": pack_id, "decision": decision, "path": str(path)}, indent=2))
        return
    console.print(f"[green]Recorded[/green]  {pack_id}  decision={decision}")


