def vertical_packs_show_cmd(
    id: str = typer.Option(..., "--id", "-i"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show one curated vertical pack (definition, paths, trust, surfaces)."""
    from workflow_dataset.vertical_packs import get_curated_pack
    pack = get_curated_pack(id)
    if not pack:
        console.print(f"[red]Pack not found: {id}[/red]")
        raise typer.Exit(1)
    if json_out:
        console.print(json.dumps(pack.to_dict(), indent=2))
        return
    console.print(f"[bold]{pack.name}[/bold]  ({pack.pack_id})")
    console.print(f"  {pack.description}")
    console.print(f"  value_pack_id={pack.value_pack_id}  workday_preset={pack.workday_preset_id}  experience_profile={pack.default_experience_profile_id}")
    console.print(f"  trust_preset={pack.trust_review_posture.trust_preset_id}  review_gates={pack.trust_review_posture.review_gates_default}")
    if pack.core_workflow_path:
        console.print(f"  core_workflow: {pack.core_workflow_path.label}  workflows={pack.core_workflow_path.workflow_ids}")
    if pack.first_value_path:
        console.print(f"  first_value_path: {pack.first_value_path.path_id}  entry={pack.first_value_path.entry_point}  steps={len(pack.first_value_path.steps)}")
    console.print(f"  required_surfaces: {pack.required_surfaces.required_surface_ids}")


@vertical_packs_group.command("apply")
def vertical_packs_apply_cmd(
    id: str = typer.Option(..., "--id", "-i"),
    repo: str = typer.Option("", "--repo", "-r"),
    dry_run: bool = typer.Option(False, "--dry-run"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Apply curated vertical defaults (set active pack; show recommended commands). Does not change trust/approval."""
    from workflow_dataset.vertical_packs import apply_vertical_defaults
    root = Path(repo).resolve() if repo else None
    result = apply_vertical_defaults(id, repo_root=root, dry_run=dry_run)
    if result.get("error"):
        console.print(f"[red]{result['error']}[/red]")
        raise typer.Exit(1)
    if json_out:
        console.print(json.dumps(result, indent=2))
        return
    console.print(f"[green]Applied[/green] pack={result.get('pack_id')}  dry_run={dry_run}")
    for cmd in result.get("applied_commands", []):
        console.print(f"  [dim]{cmd}[/dim]")


@vertical_packs_group.command("first-value")
def vertical_packs_first_value_cmd(
    id: str = typer.Option(..., "--id", "-i"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show first-value path for a curated pack (entry, steps, milestones, failure points)."""
    from workflow_dataset.vertical_packs import get_curated_pack
    pack = get_curated_pack(id)
    if not pack or not pack.first_value_path:
        console.print(f"[red]Pack or first-value path not found: {id}[/red]")
        raise typer.Exit(1)
    path = pack.first_value_path
    if json_out:
        console.print(json.dumps(path.to_dict(), indent=2))
        return
    console.print(f"[bold]{path.label}[/bold]  path_id={path.path_id}")
    console.print(f"  entry_point: {path.entry_point}")
    for s in path.steps:
        console.print(f"  {s.step_number}. {s.title}  [dim]{s.command}[/dim]")
    console.print("  milestones: " + ", ".join(m.milestone_id for m in path.milestones))
    if path.common_failure_points:
        console.print("  common_failure_points: " + str(len(path.common_failure_points)))


@vertical_packs_group.command("progress")
def vertical_packs_progress_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show first-value path progress: active pack, next milestone, blocked step, suggested command."""
    from workflow_dataset.vertical_packs import build_milestone_progress_output
    root = Path(repo).resolve() if repo else None
    out = build_milestone_progress_output(repo_root=root)
    if json_out:
        console.print(json.dumps(out, indent=2))
        return
    console.print("[bold]Vertical path progress[/bold]")
    console.print(f"  active_pack={out.get('active_curated_pack_id') or '(none)'}  path={out.get('path_id') or '(none)'}")
    console.print(f"  next_milestone={out.get('next_milestone_label') or out.get('next_milestone_id') or '(none)'}")
    console.print(f"  reached={out.get('reached_milestone_ids', [])}")
    if out.get("blocked_step_index"):
        console.print(f"  [yellow]blocked_step_index={out['blocked_step_index']}[/yellow]")
    console.print(f"  suggested: {out.get('suggested_next_command', '')}")
    if out.get("operator_guidance_when_stalled"):
        og = out["operator_guidance_when_stalled"]
        console.print("[bold]Operator guidance (path stalled):[/bold] " + str(og.get("guidance", "")))
        for c in og.get("commands", [])[:5]:
            console.print(f"  [dim]{c}[/dim]")


@vertical_packs_group.command("playbook")
def vertical_packs_playbook_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Curated pack id"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show vertical playbook: common failure points, recovery paths, operator guidance when path stalls. M39H.1."""
    from workflow_dataset.vertical_packs import get_playbook_for_vertical
    playbook = get_playbook_for_vertical(id)
    if not playbook:
        console.print(f"[red]No playbook for vertical: {id}[/red]")
        raise typer.Exit(1)
    if json_out:
        console.print(json.dumps(playbook.to_dict(), indent=2))
        return
    console.print(f"[bold]{playbook.label}[/bold]  ({playbook.playbook_id})")
    console.print(f"  {playbook.description}")
    console.print("  failure_entries: " + str(len(playbook.failure_entries)))
    for e in playbook.failure_entries:
        console.print(f"    step {e.step_index}: {e.symptom}  → {e.recovery_path_id}")
    console.print("  recovery_paths: " + str(len(playbook.recovery_paths)))
    console.print("  operator_guidance_stalled: " + (playbook.operator_guidance_stalled[:60] + "..." if len(playbook.operator_guidance_stalled) > 60 else playbook.operator_guidance_stalled))


@vertical_packs_group.command("recovery")
def vertical_packs_recovery_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Curated pack id"),
    step: int = typer.Option(..., "--step", "-s", help="Step index where path is blocked (1-based)"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show recovery path and operator guidance for a blocked step. M39H.1."""
    from workflow_dataset.vertical_packs import get_operator_guidance_when_stalled
    out = get_operator_guidance_when_stalled(id, step)
    if json_out:
        console.print(json.dumps(out, indent=2))
        return
    console.print("[bold]Operator guidance (path stalled at step " + str(step) + ")[/bold]")
    console.print("  " + out.get("guidance", ""))
    console.print("  commands:")
    for c in out.get("commands", []):
        console.print(f"    [dim]{c}[/dim]")
    fe = out.get("failure_entry", {})
    if fe:
        console.print("  failure_entry: symptom=" + str(fe.get("symptom", "")) + "  remediation=" + str(fe.get("remediation_hint", "")))
    rp = out.get("recovery_path")
    if rp:
        console.print("  recovery_path: " + rp.get("label", "") + "  target_milestone=" + rp.get("target_milestone_id", ""))
        for s in rp.get("steps", []):
            console.print(f"    {s.get('step_order')}. {s.get('label', '')}  [dim]{s.get('command', '')}[/dim]")


