# ----- M40E–M40H Production deployment bundle -----
deploy_bundle_group = typer.Typer(
    help="Production deployment bundle: show, build, validate, upgrade-path, recovery-report. M40.",
)
app.add_typer(deploy_bundle_group, name="deploy-bundle")


@deploy_bundle_group.command("show")
def deploy_bundle_show_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show active deployment bundle or default (founder_operator_prod)."""
    from workflow_dataset.deploy_bundle import get_active_bundle, get_deployment_bundle
    root = Path(repo).resolve() if repo else None
    active = get_active_bundle(repo_root=root)
    bundle_id = active.get("active_bundle_id", "") or "founder_operator_prod"
    bundle = get_deployment_bundle(bundle_id)
    if not bundle:
        console.print(f"[red]Bundle not found: {bundle_id}[/red]")
        raise typer.Exit(1)
    if json_out:
        console.print(json.dumps(bundle.to_dict(), indent=2))
        return
    console.print(f"[bold]{bundle.name}[/bold]  ({bundle.bundle_id})  active={bool(active.get('active_bundle_id'))}")
    console.print(f"  {bundle.description}")
    console.print(f"  curated_pack={bundle.curated_pack_id}  upgrade_readiness=see upgrade-path  rollback=see recovery-report")


@deploy_bundle_group.command("build")
def deploy_bundle_build_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Bundle id (e.g. founder_operator_prod)"),
    repo: str = typer.Option("", "--repo", "-r"),
    set_active: bool = typer.Option(True, "--set-active/--no-set-active"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Build and write bundle manifest; optionally set as active bundle."""
    from workflow_dataset.deploy_bundle import get_deployment_bundle, write_bundle_manifest, set_active_bundle
    root = Path(repo).resolve() if repo else None
    bundle = get_deployment_bundle(id)
    if not bundle:
        console.print(f"[red]Bundle not found: {id}[/red]")
        raise typer.Exit(1)
    try:
        path = write_bundle_manifest(id, repo_root=root)
        if set_active:
            set_active_bundle(id, repo_root=root)
        if json_out:
            console.print(json.dumps({"bundle_id": id, "manifest_path": str(path), "active": set_active}, indent=2))
        else:
            console.print(f"[green]Built[/green] {id}  manifest={path}  active={set_active}")
    except ValueError as e:
        console.print(f"[red]{e}[/red]")
        raise typer.Exit(1)


@deploy_bundle_group.command("validate")
def deploy_bundle_validate_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    id: str = typer.Option("", "--id", "-i", help="Bundle id (default: active or founder_operator_prod)"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Validate deployment bundle against current repo (install check, readiness, curated pack)."""
    from workflow_dataset.deploy_bundle import get_active_bundle, validate_bundle
    root = Path(repo).resolve() if repo else None
    bundle_id = id or get_active_bundle(repo_root=root).get("active_bundle_id", "") or "founder_operator_prod"
    result = validate_bundle(bundle_id, repo_root=root)
    if json_out:
        console.print(json.dumps(result.to_dict(), indent=2))
        return
    console.print(f"[bold]Validation[/bold]  bundle={result.bundle_id}  passed={result.passed}  ready={result.ready}")
    for e in result.errors:
        console.print(f"  [red]error: {e}[/red]")
    for w in result.warnings:
        console.print(f"  [yellow]warning: {w}[/yellow]")


@deploy_bundle_group.command("upgrade-path")
def deploy_bundle_upgrade_path_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    id: str = typer.Option("", "--id", "-i", help="Bundle id"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show supported upgrade path and current/target version status."""
    from workflow_dataset.deploy_bundle import get_active_bundle, get_supported_upgrade_path
    root = Path(repo).resolve() if repo else None
    bundle_id = id or get_active_bundle(repo_root=root).get("active_bundle_id", "") or "founder_operator_prod"
    out = get_supported_upgrade_path(bundle_id, repo_root=root)
    if json_out:
        console.print(json.dumps(out, indent=2))
        return
    if out.get("error"):
        console.print(f"[red]{out['error']}[/red]")
        raise typer.Exit(1)
    console.print(f"[bold]Upgrade path[/bold]  bundle={out['bundle_id']}  current={out.get('current_version')}  target={out.get('target_version')}")
    console.print(f"  can_proceed={out.get('can_proceed')}  supported_from={out.get('supported_upgrade_path', {}).get('from_version_min')}  to={out.get('supported_upgrade_path', {}).get('to_version_max')}")
    for r in out.get("blocked_reasons", []):
        console.print(f"  [red]blocked: {r}[/red]")
    for w in out.get("warnings", []):
        console.print(f"  [yellow]{w}[/yellow]")


@deploy_bundle_group.command("recovery-report")
def deploy_bundle_recovery_report_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    id: str = typer.Option("", "--id", "-i", help="Bundle id"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show recovery posture and rollback readiness for deployment bundle."""
    from workflow_dataset.deploy_bundle import get_active_bundle, build_recovery_report, get_rollback_readiness
    root = Path(repo).resolve() if repo else None
    bundle_id = id or get_active_bundle(repo_root=root).get("active_bundle_id", "") or "founder_operator_prod"
    report = build_recovery_report(bundle_id, repo_root=root)
    rollback = get_rollback_readiness(bundle_id, repo_root=root)
    if json_out:
        console.print(json.dumps({"recovery_report": report, "rollback_readiness": rollback}, indent=2))
        return
    if report.get("error"):
        console.print(f"[red]{report['error']}[/red]")
        raise typer.Exit(1)
    console.print("[bold]Recovery posture[/bold]  " + report.get("degraded_startup_guidance", "")[:80] + "...")
    console.print("  vertical_playbook: " + report.get("vertical_playbook_recovery_ref", ""))
    console.print("  applicable_cases: " + str(len(report.get("applicable_recovery_cases", []))))
    console.print("[bold]Rollback readiness[/bold]  ready=" + str(rollback.get("ready")) + "  latest_checkpoint=" + str(rollback.get("latest_checkpoint_id", "")))


@deploy_bundle_group.command("profiles")
def deploy_bundle_profiles_cmd(
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List deployment profiles (demo, internal_production_like, careful_production_cut). M40H.1."""
    from workflow_dataset.deploy_bundle import list_deployment_profile_ids, get_deployment_profile
    ids = list_deployment_profile_ids()
    if json_out:
        console.print(json.dumps([get_deployment_profile(i).to_dict() if get_deployment_profile(i) else {} for i in ids], indent=2))
        return
    console.print("[bold]Deployment profiles[/bold]")
    for i in ids:
        p = get_deployment_profile(i)
        console.print(f"  {i}  {p.name if p else ''}")


@deploy_bundle_group.command("profile")
def deploy_bundle_profile_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Profile id (demo, internal_production_like, careful_production_cut)"),
    set_active: bool = typer.Option(False, "--set", help="Set as active deployment profile"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show deployment profile; optionally set as active. M40H.1."""
    from workflow_dataset.deploy_bundle import get_deployment_profile, set_deployment_profile
    root = Path(repo).resolve() if repo else None
    p = get_deployment_profile(id)
    if not p:
        console.print(f"[red]Profile not found: {id}[/red]")
        raise typer.Exit(1)
    if set_active:
        set_deployment_profile(id, repo_root=root)
    if json_out:
        console.print(json.dumps(p.to_dict(), indent=2))
        return
    console.print(f"[bold]{p.name}[/bold]  ({p.profile_id})")
    console.print(f"  {p.description}")
    console.print(f"  pause_guidance: {p.pause_guidance[:70]}..." if len(p.pause_guidance) > 70 else f"  pause_guidance: {p.pause_guidance}")
    console.print(f"  repair_guidance: {p.repair_guidance[:70]}..." if len(p.repair_guidance) > 70 else f"  repair_guidance: {p.repair_guidance}")
    if set_active:
        console.print("[green]Set as active profile.[/green]")


@deploy_bundle_group.command("maintenance-mode")
def deploy_bundle_maintenance_mode_cmd(
    report: bool = typer.Option(True, "--report/--no-report", help="Show maintenance report (default)"),
    set_mode: str = typer.Option("", "--set", "-s", help="Set active maintenance mode (upgrade, recovery, audit_review, safe_pause, or empty to clear)"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show maintenance mode report (pause/repair guidance); optionally set active mode. M40H.1."""
    from workflow_dataset.deploy_bundle import build_maintenance_mode_report, set_maintenance_mode, get_maintenance_mode
    root = Path(repo).resolve() if repo else None
    if set_mode is not None and set_mode != "":
        m = get_maintenance_mode(set_mode)
        if not m and set_mode:
            console.print(f"[red]Unknown maintenance mode: {set_mode}[/red]")
            raise typer.Exit(1)
        set_maintenance_mode(set_mode, repo_root=root)
        if not report:
            console.print(f"[green]Maintenance mode set to: {set_mode or '(cleared)'}[/green]")
            return
    r = build_maintenance_mode_report(repo_root=root)
    if json_out:
        console.print(json.dumps(r.to_dict(), indent=2))
        return
    console.print("[bold]Maintenance report[/bold]")
    console.print(f"  active_profile={r.active_profile_id}  active_mode={r.active_maintenance_mode_id or '(none)'}")
    console.print(f"  should_pause={r.should_pause}  should_repair={r.should_repair}")
    if r.pause_reason:
        console.print(f"  pause_reason: {r.pause_reason[:80]}...")
    if r.repair_reason:
        console.print(f"  repair_reason: {r.repair_reason}")
    console.print(f"  operator_guidance: {r.operator_guidance_summary[:100]}..." if len(r.operator_guidance_summary or "") > 100 else f"  operator_guidance: {r.operator_guidance_summary}")
    for a in (r.recommended_actions or [])[:5]:
        console.print(f"  [dim]{a}[/dim]")


