    if not d:
        console.print("[dim]No task defaults for this scope. Runtime policy applies.[/dim]")
        return
    console.print("[bold]Task defaults[/bold] (task=%s workflow=%s) from pack %s" % (d.task_id or "(any)", d.workflow_id or "(any)", d.pack_id))
    console.print("  preferred_adapter:", d.preferred_adapter or "(none)")
    console.print("  preferred_model_class:", d.preferred_model_class or "(none)")
    console.print("  preferred_output_mode:", d.preferred_output_mode or "(none)")
