@recipe_runs_group.command("list")
def recipe_runs_list(
    repo_root: str = typer.Option("", "--repo-root"),
    limit: int = typer.Option(50, "--limit", "-n"),
) -> None:
    """List recipe/provisioning runs (newest first)."""
    from workflow_dataset.specialization.recipe_runs_storage import list_runs
    from workflow_dataset.provisioning.report import format_recipe_run_report
    root = Path(repo_root).resolve() if repo_root else None
    runs = list_runs(repo_root=root, limit=limit)
    console.print(format_recipe_run_report(runs, title="Recipe runs"))


@recipe_group.command("run")
def recipe_run_cmd(
    id_arg: str = typer.Option(..., "--id", "-i", help="Value pack id or recipe alias e.g. founder_ops_recipe"),
    repo_root: str = typer.Option("", "--repo-root"),
    dry_run: bool = typer.Option(False, "--dry-run", help="Preview only; do not write"),
    no_strict: bool = typer.Option(False, "--no-strict", help="Run even if prerequisites missing (not recommended)"),
) -> None:
    """Run local provisioning for a value pack (or recipe alias). Records a recipe run. No auto-download/train."""
    from workflow_dataset.provisioning.runner import run_provisioning, resolve_pack_id
    from workflow_dataset.provisioning.report import format_provisioning_result
    pack_id = resolve_pack_id(id_arg)
    root = Path(repo_root).resolve() if repo_root else None
    result = run_provisioning(pack_id, repo_root=root, dry_run=dry_run, strict_prerequisites=not no_strict)
    console.print(format_provisioning_result(result))
    if not result.get("success"):
        raise typer.Exit(1)


@recipe_group.command("preview")
def recipe_preview(
    id_arg: str = typer.Option(..., "--id", "-i", help="Value pack id or recipe alias e.g. founder_ops_recipe"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Preview provisioning: prerequisites, recipe, and what would be done. No side effects."""
    from workflow_dataset.provisioning.runner import check_prerequisites, resolve_pack_id
    from workflow_dataset.specialization.recipe_builder import build_recipe_for_domain_pack
    from workflow_dataset.value_packs.registry import get_value_pack
    pack_id = resolve_pack_id(id_arg)
    root = Path(repo_root).resolve() if repo_root else None
    pack = get_value_pack(pack_id)
    if not pack:
        console.print(f"[red]Pack not found: {pack_id}[/red]")
        raise typer.Exit(1)
    missing, _ = check_prerequisites(value_pack_id=pack_id, repo_root=root)
    recipe = build_recipe_for_domain_pack(pack.domain_pack_id, repo_root=str(root)) if pack.domain_pack_id else None
    console.print(f"[bold]Preview: {pack_id}[/bold] — {pack.name}")
    console.print(f"  Domain pack: {pack.domain_pack_id}  Recipe: {recipe.recipe_id if recipe else '—'}")
    if missing:
        console.print("  [yellow]Missing prerequisites:[/yellow]")
        for m in missing:
            console.print(f"    - {m}")
    else:
        console.print("  [green]Prerequisites: OK[/green]")
    console.print("  Would: prepare sample assets, write provisioning manifest, stage specialization dirs")


@recipe_group.command("report")
def recipe_report(
    latest: bool = typer.Option(False, "--latest", "-l", help="Show only latest run"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Show recipe run report (latest run if --latest)."""
    from workflow_dataset.specialization.recipe_runs_storage import list_runs, get_run
    from workflow_dataset.provisioning.report import format_recipe_run, format_recipe_run_report
    root = Path(repo_root).resolve() if repo_root else None
    if latest:
        runs = list_runs(repo_root=root, limit=1)
        if not runs:
            console.print("No runs found.")
            return
        console.print(format_recipe_run(runs[0]))
    else:
        runs = list_runs(repo_root=root, limit=20)
        console.print(format_recipe_run_report(runs, title="Recipe runs report"))


