@models_benchmark_group.command("promote")
def models_promote_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Candidate/run id to promote"),
    scope: str = typer.Option("experimental", "--scope", "-s", help="experimental | limited_cohort | production_safe"),
    reason: str = typer.Option("", "--reason", "-r"),
    scorecard_id: str = typer.Option("", "--scorecard-id"),
    repo: str = typer.Option("", "--repo"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Promote candidate: experimental_only, limited_cohort, or production_safe. Explicit decision."""
    from workflow_dataset.benchmark_board import promote_experimental, promote_limited_cohort, promote_production_safe
    root = Path(repo).resolve() if repo else None
    if scope == "production_safe":
        out = promote_production_safe(id, reason=reason, scorecard_id=scorecard_id, repo_root=root)
    elif scope == "limited_cohort":
        out = promote_limited_cohort(id, reason=reason, scorecard_id=scorecard_id, repo_root=root)
    else:
        out = promote_experimental(id, reason=reason, scorecard_id=scorecard_id, repo_root=root)
    if json_out:
        console.print(json.dumps(out, indent=2))
        return
    console.print(f"[green]Promoted[/green] {id}  scope={out.get('scope', scope)}")


