@models_benchmark_group.command("list")
def models_list_cmd(
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """List local model registry entries (capability catalog). M42A."""
    from workflow_dataset.runtime_mesh.model_catalog import load_model_catalog
    root = Path(repo).resolve() if repo else None
    catalog = load_model_catalog(root)
    if json_out:
        out = [{"model_id": m.model_id, "backend_family": m.backend_family, "capability_classes": m.capability_classes, "task_families": m.task_families, "production_safe": m.production_safe} for m in catalog]
        console.print(json.dumps(out, indent=2))
        return
    console.print("[bold]Local model registry[/bold]  count=" + str(len(catalog)))
    for m in catalog[:30]:
        console.print(f"  {m.model_id}  backend={m.backend_family}  task_families={m.task_families or m.capability_classes}  production_safe={m.production_safe}")


@models_benchmark_group.command("show")
def models_show_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Model id (e.g. llama3.2, local/small)"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Show one model registry entry. M42A."""
    from workflow_dataset.runtime_mesh.model_catalog import get_model_info
    from workflow_dataset.runtime_mesh.policy import compatibility_for_model
    root = Path(repo).resolve() if repo else None
    m = get_model_info(id, root)
    if not m:
        console.print("[red]Model not found: " + id + "[/red]")
        raise typer.Exit(1)
    comp = compatibility_for_model(id, root)
    if json_out:
        console.print(json.dumps({"entry": {"model_id": m.model_id, "backend_family": m.backend_family, "capability_classes": m.capability_classes, "task_families": m.task_families, "context_size": m.context_size, "production_safe": m.production_safe, "fallback_model_id": m.fallback_model_id}, "compatibility": comp}, indent=2))
        return
    console.print("[bold]" + m.model_id + "[/bold]  backend=" + m.backend_family + "  production_safe=" + str(m.production_safe))
    console.print("  task_families=" + str(m.task_families) + "  capability_classes=" + str(m.capability_classes))
    console.print("  fallback=" + (m.fallback_model_id or "—") + "  " + comp.get("message", ""))


@models_benchmark_group.command("route")
def models_route_cmd(
    task: str = typer.Option(..., "--task", "-t", help="Task family: planning, summarization, review, suggestion, vertical_workflow, evaluation, council, adaptation_comparison"),
    trust: str = typer.Option("production", "--trust", help="production | experimental"),
    vertical: str = typer.Option("", "--vertical", "-v", help="Vertical runtime profile: default, document_workflow, codebase, council_eval"),
    policy: str = typer.Option("", "--policy", "-p", help="Routing policy: conservative, balanced, eval_heavy, production_safe"),
    explain: bool = typer.Option(False, "--explain", "-e"),
    repo: str = typer.Option("", "--repo", "-r"),
    json_out: bool = typer.Option(False, "--json"),
) -> None:
    """Route task family to primary model/backend and fallback. M42B. M42D.1: --vertical, --policy, route_outcome/reason_why."""
    from workflow_dataset.runtime_mesh.routing import route_for_task, explain_route
    root = Path(repo).resolve() if repo else None
    out = explain_route(task, trust_posture=trust, vertical_id=vertical, routing_policy_id=policy, repo_root=root) if explain else route_for_task(task, trust_posture=trust, vertical_id=vertical, routing_policy_id=policy, repo_root=root)
    if json_out:
        console.print(json.dumps(out, indent=2))
        return
    console.print("[bold]Route[/bold]  task_family=" + task + ("  vertical=" + vertical if vertical else "") + ("  policy=" + policy if policy else ""))
    console.print("  primary_model=" + str(out.get("primary_model_id") or "—") + "  primary_backend=" + str(out.get("primary_backend_id") or "—") + "  status=" + str(out.get("backend_status", "")))
    console.print("  fallback_chain=" + str(out.get("fallback_chain", [])) + "  is_degraded=" + str(out.get("is_degraded", False)))
    if out.get("route_outcome"):
        console.print("  outcome=" + str(out.get("route_outcome")) + "  reason=" + str(out.get("reason_why", ""))[:120])
    if explain:
        console.print("  " + out.get("explanation", "")[:280])


