# ----- M26A–M26D Goal-to-plan compiler -----
@planner_group.command("compile")
def planner_compile(
    goal: str = typer.Option(..., "--goal", "-g", help="Operator goal or intent (e.g. 'Prepare weekly stakeholder update')"),
    repo_root: str = typer.Option("", "--repo-root"),
    mode: str = typer.Option("simulate", "--mode", "-m", help="simulate | real"),
) -> None:
    """Compile goal into an explicit work plan. Saves as latest plan; no execution."""
    from workflow_dataset.planner.compile import compile_goal_to_plan
    from workflow_dataset.planner.store import save_current_goal, save_latest_plan
    root = Path(repo_root).resolve() if repo_root else None
    plan = compile_goal_to_plan(goal, root, mode=mode)
    save_current_goal(goal, root)
    save_latest_plan(plan, root)
    console.print(f"[green]Plan {plan.plan_id}[/green]  steps={len(plan.steps)}  blocked={len(plan.blocked_conditions)}")
    console.print("[dim]Use: workflow-dataset planner preview --latest  or  planner explain --latest  or  planner graph --latest[/dim]")


@planner_group.command("preview")
def planner_preview(
    latest: bool = typer.Option(False, "--latest", "-l", help="Show latest compiled plan"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Show plan preview (steps, blocked, checkpoints, expected outputs). Use --latest for last compiled plan."""
    from workflow_dataset.planner.store import load_latest_plan
    from workflow_dataset.planner.preview import format_plan_preview
    root = Path(repo_root).resolve() if repo_root else None
    if not latest:
        console.print("[yellow]Use --latest to show the last compiled plan. Or run: workflow-dataset planner compile --goal \"your goal\"[/yellow]")
        return
    plan = load_latest_plan(root)
    if not plan:
        console.print("[red]No latest plan. Run: workflow-dataset planner compile --goal \"your goal\"[/red]")
        raise typer.Exit(1)
    console.print(format_plan_preview(plan))


@planner_group.command("explain")
def planner_explain(
    latest: bool = typer.Option(False, "--latest", "-l", help="Explain latest compiled plan"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Explain why this plan was chosen, sources, blocked, human approval, expected outputs. Use --latest for last compiled plan."""
    from workflow_dataset.planner.store import load_latest_plan
    from workflow_dataset.planner.explain import explain_plan
    root = Path(repo_root).resolve() if repo_root else None
    if not latest:
        console.print("[yellow]Use --latest to explain the last compiled plan.[/yellow]")
        return
    plan = load_latest_plan(root)
    if not plan:
        console.print("[red]No latest plan. Run: workflow-dataset planner compile --goal \"your goal\"[/red]")
        raise typer.Exit(1)
    console.print(explain_plan(plan))


@planner_group.command("graph")
def planner_graph(
    latest: bool = typer.Option(False, "--latest", "-l", help="Show dependency graph of latest plan"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Show plan dependency graph (steps and edges). Use --latest for last compiled plan."""
    from workflow_dataset.planner.store import load_latest_plan
