# ----- M29E–M29H Conversational command center -----
@app.command("ask")
def ask_cmd(
    phrase: str = typer.Argument(..., help="Natural language question or request (e.g. 'What should I do next?', 'Why is X blocked?')"),
    repo_root: str = typer.Option("", "--repo-root", help="Override repo root"),
    no_preview: bool = typer.Option(False, "--no-preview", help="Do not show action preview for action-like requests"),
    role: str = typer.Option("", "--role", "-r", help="Role for suggested commands: operator | reviewer"),
    json_out: bool = typer.Option(False, "--json", help="Output full response as JSON (answer, intent, preview, confidence, suggested_queries, etc.)"),
) -> None:
    """Conversational command center: ask in plain language; get grounded answers, suggested next questions, and optional guided dialogue. No execution from ask."""
    from workflow_dataset.conversational.ask import ask as ask_fn
    root = Path(repo_root).resolve() if repo_root else None
    result = ask_fn(phrase, repo_root=root, include_preview=not no_preview, role=role or None)
    if json_out:
        import json
        console.print(json.dumps(result, indent=2))
        return
    console.print(result["answer"])
    if result.get("preview"):
        console.print("")
        console.print("[bold]Preview[/bold]")
        console.print(result["preview"])
    if result.get("suggested_queries"):
        console.print("")
        console.print("[bold]Suggested next questions[/bold]")
        for q in result["suggested_queries"][:5]:
            console.print(f"  • ask \"{q}\"")
    if result.get("guided_dialogue"):
        gd = result["guided_dialogue"]
        console.print("")
        console.print("[bold]Guided flow: " + gd.get("title", "") + "[/bold]")
        for s in (gd.get("steps") or [])[:4]:
            console.print(f"  {s.get('step_index', 0) + 1}. {s.get('prompt', '')}")
            if s.get("suggested_command"):
                console.print(f"     [dim]{s['suggested_command']}[/dim]")
    if result.get("role_commands") and role:
        console.print("")
        console.print("[bold]Suggested commands (" + role + ")[/bold]")
        for c in result["role_commands"][:4]:
            console.print(f"  {c.get('label', '')}: [dim]{c.get('command', '')}[/dim]")


