@vertical_speed_group.command("fast-paths")
def vertical_speed_fast_paths(
    path_id: str = typer.Option("", "--path-id", "-p", help="Show single path by path_id"),
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Write JSON to file"),
) -> None:
    """List fast paths for repeated vertical workflows (compressed one/few-step paths)."""
    from workflow_dataset.vertical_speed import list_fast_paths, get_fast_path_by_path_id
    import json
    root = Path(repo_root) if repo_root else None
    if path_id:
        p = get_fast_path_by_path_id(path_id.strip())
        if not p:
            console.print(f"[red]No fast path for path_id={path_id}[/red]")
            raise SystemExit(1)
        data = p.to_dict()
        if output:
            Path(output).write_text(json.dumps(data, indent=2), encoding="utf-8")
            console.print(f"[green]Wrote: {output}[/green]")
        console.print(Panel(f"[bold]{p.label}[/bold]\n{p.description}\nSteps: {p.compressed_steps}\nCommand: {p.single_command}", title=p.path_id, border_style="green"))
    else:
        paths = list_fast_paths()
        data = [p.to_dict() for p in paths]
        if output:
            Path(output).write_text(json.dumps(data, indent=2), encoding="utf-8")
            console.print(f"[green]Wrote: {output}[/green]")
        for p in paths:
            console.print(f"  [bold]{p.path_id}[/bold]  {p.workflow_id}  {p.step_count_before}→{p.step_count_after} steps  {p.single_command or p.compressed_steps[0]}")


@vertical_speed_group.command("common-loop-bundles")
def vertical_speed_common_loop_bundles(
    bundle_id: str = typer.Option("", "--bundle-id", "-b", help="Show single bundle by bundle_id"),
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Write JSON to file"),
) -> None:
    """List common-loop bundles (groups of repeated flows)."""
    from workflow_dataset.vertical_speed import list_common_loop_bundles, get_common_loop_bundle
    import json
    root = Path(repo_root) if repo_root else None
    if bundle_id:
        b = get_common_loop_bundle(bundle_id.strip())
        if not b:
            console.print(f"[red]No bundle for bundle_id={bundle_id}[/red]")
            raise SystemExit(1)
        data = b.to_dict()
        if output:
            Path(output).write_text(json.dumps(data, indent=2), encoding="utf-8")
            console.print(f"[green]Wrote: {output}[/green]")
        console.print(Panel(f"[bold]{b.label}[/bold]\n{b.description}\nWorkflows: {b.workflow_ids}\nEntry: {b.single_entry_command or '—'}", title=b.bundle_id, border_style="cyan"))
    else:
        bundles = list_common_loop_bundles()
        data = [b.to_dict() for b in bundles]
        if output:
            Path(output).write_text(json.dumps(data, indent=2), encoding="utf-8")
            console.print(f"[green]Wrote: {output}[/green]")
        for b in bundles:
            console.print(f"  [bold]{b.bundle_id}[/bold]  {b.label}  workflows={b.workflow_ids}")


@vertical_speed_group.command("compression-report")
def vertical_speed_compression_report(
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Write JSON to file"),
) -> None:
    """Report which repeated flows are compressed (have fast path) vs still need work."""
    from workflow_dataset.vertical_speed import build_compression_report
    import json
    root = Path(repo_root) if repo_root else None
    data = build_compression_report(repo_root=root)
    if output:
        Path(output).write_text(json.dumps(data, indent=2), encoding="utf-8")
        console.print(f"[green]Wrote: {output}[/green]")
    console.print("[bold]Compressed[/bold] (have fast path): " + str(data.get("compressed_count", 0)) + "  " + str(data.get("compressed_workflow_ids", [])))
    console.print("[bold]Still need work[/bold]: " + str(data.get("still_needs_work_count", 0)) + "  " + str(data.get("still_needs_work_workflow_ids", [])))
    for e in data.get("workflow_entries", []):
        status = "[green]compressed[/green]" if e.get("compressed") else "[yellow]still need work[/yellow]"
        console.print(f"  {e.get('workflow_id')}  {e.get('label')}  {status}  → {e.get('recommendation', '')}")


# ----- M31I–M31L Personal adaptation (preferences, style candidates, apply, explain) -----
personal_group = typer.Typer(
    help="Personal adaptation: preference/style candidates from work and feedback, apply accepted, explain.",
)
app.add_typer(personal_group, name="personal")


@personal_group.command("preferences")
def personal_preferences(
    repo_root: str = typer.Option("", "--repo-root"),
    refresh: bool = typer.Option(False, "--refresh", "-r", help="Generate candidates from corrections/routines and save before listing"),
    status: str = typer.Option("", "--status", help="Filter by review_status: pending | accepted | dismissed"),
    output: str = typer.Option("", "--output", "-o", help="Write to file"),
) -> None:
    """List preference candidates. Use --refresh to generate from corrections and routines, then list."""
    from workflow_dataset.personal_adaptation import generate_preference_candidates, list_candidates, save_candidate
    root = Path(repo_root) if repo_root else None
    if refresh:
        for c in generate_preference_candidates(repo_root=root):
            save_candidate(c, repo_root=root)
    items = list_candidates(repo_root=root, kind="preference", review_status=status.strip() or None, limit=30)
    if not items:
        console.print("[dim]No preference candidates. Run with --refresh to generate from corrections and routines.[/dim]")
        raise typer.Exit(0)
    lines = ["# Preference candidates", ""]
    for u in items:
        lines.append(f"  {u.get('candidate_id', '')}  key={u.get('key', '')}  confidence={u.get('confidence', 0):.2f}  status={u.get('review_status', '')}  surface={u.get('affected_surface', '')}")
    text = "\n".join(lines)
    if output:
        Path(output).write_text(text, encoding="utf-8")
        console.print(f"[green]Wrote: {output}[/green]")
    console.print(text)


