@personal_group.command("apply-preference")
def personal_apply_preference(
    id_arg: str = typer.Option(..., "--id", "-i", help="Candidate id to accept and apply"),
    repo_root: str = typer.Option("", "--repo-root"),
    dry_run: bool = typer.Option(False, "--dry-run", help="Show behavior deltas only; do not accept or apply"),
) -> None:
    """Accept a preference/style candidate and apply it to the affected surface. Use --dry-run to review deltas first."""
    from workflow_dataset.personal_adaptation import (
        accept_candidate,
        apply_accepted_preference,
        build_behavior_delta_for_candidate,
        format_behavior_delta_output,
    )
    root = Path(repo_root) if repo_root else None
    if dry_run:
        deltas = build_behavior_delta_for_candidate(id_arg.strip(), repo_root=root)
        if not deltas:
            console.print(f"[yellow]No deltas (candidate not found or no changes): {id_arg}[/yellow]")
            raise typer.Exit(0)
        text = format_behavior_delta_output(deltas, candidate_id=id_arg)
        console.print(Panel(text, title="Behavior delta (dry-run)", border_style="yellow"))
        console.print("[dim]Run without --dry-run to accept and apply.[/dim]")
        return
    update = accept_candidate(id_arg.strip(), repo_root=root)
    if not update:
        console.print(f"[red]Candidate not found or could not accept: {id_arg}[/red]")
        raise typer.Exit(1)
    result = apply_accepted_preference(update.update_id, repo_root=root)
    if result.get("applied"):
        console.print(f"[green]Applied: {result.get('message', '')}[/green]  surface={result.get('surface', '')}")
    else:
        console.print(f"[yellow]{result.get('message', '')}[/yellow]")


@personal_group.command("behavior-delta")
def personal_behavior_delta(
    id_arg: str = typer.Option(..., "--id", "-i", help="Candidate id to preview"),
    preset_id: str = typer.Option("", "--preset", "-p", help="Preset id instead of candidate (show deltas for all in preset)"),
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Write to file"),
) -> None:
    """Show before/after behavior deltas for a candidate or preset. Safer review of what will change in packs, workspace, recommendations."""
    from workflow_dataset.personal_adaptation import (
        build_behavior_delta_for_candidate,
        build_behavior_delta_for_preset,
        format_behavior_delta_output,
    )
    root = Path(repo_root) if repo_root else None
    if preset_id.strip():
        deltas = build_behavior_delta_for_preset(preset_id.strip(), repo_root=root)
        text = format_behavior_delta_output(deltas, candidate_id="") + "\n\nPreset: " + preset_id
    else:
        deltas = build_behavior_delta_for_candidate(id_arg.strip(), repo_root=root)
        text = format_behavior_delta_output(deltas, candidate_id=id_arg)
    if not deltas:
        console.print("[yellow]No deltas (candidate/preset not found or no changes).[/yellow]")
        raise typer.Exit(0)
    if output:
        Path(output).write_text(text, encoding="utf-8")
        console.print(f"[green]Wrote: {output}[/green]")
    console.print(Panel(text, title="Behavior delta", border_style="cyan"))


