@review_domains_group.command("list")
def review_domains_list_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """List all review domains (built-in and custom from data/local/review_domains)."""
    from workflow_dataset.review_domains.registry import list_domains
    root = Path(repo_root).resolve() if repo_root else None
    domains = list_domains(root)
    for d in domains:
        console.print(f"  {d.domain_id}  {d.name}")
        console.print(f"    {d.description[:80]}..." if len(d.description) > 80 else f"    {d.description}")


@review_domains_group.command("show")
def review_domains_show_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Domain id (e.g. sensitive_gate, operator_routine)"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Show one review domain by id."""
    from workflow_dataset.review_domains.registry import get_domain
    root = Path(repo_root).resolve() if repo_root else None
    d = get_domain(id, root)
    if not d:
        console.print(f"[red]Review domain not found: {id}[/red]")
        raise SystemExit(1)
    console.print(Panel.fit(f"[bold]{d.name}[/bold]\n{d.description}", title=d.domain_id))
    console.print("Scope:", d.scope_note)
    console.print("Self-approve blocked:", d.self_approve_blocked)
    console.print("Allowed roles:")
    for r in d.allowed_roles:
        console.print(f"  - {r.role_id}: {r.capabilities}")
    if d.escalation_routes:
        console.print("Escalation routes:")
        for e in d.escalation_routes:
            console.print(f"  - -> {e.target_role_id}: {e.description}")


@review_domains_group.command("check")
def review_domains_check_cmd(
    role: str = typer.Option(..., "--role", "-r", help="Role id (e.g. operator, reviewer, approver)"),
    domain: str = typer.Option(..., "--domain", "-d", help="Domain id (e.g. sensitive_gate)"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Check whether a role may review/approve in a domain; show escalation if required."""
    from workflow_dataset.review_domains.registry import get_domain
    from workflow_dataset.review_domains.boundaries import check_role_in_domain, escalation_required
    from workflow_dataset.review_domains.models import ParticipantCapability
    root = Path(repo_root).resolve() if repo_root else None
    d = get_domain(domain, root)
    if not d:
        console.print(f"[red]Domain not found: {domain}[/red]")
        raise SystemExit(1)
    can_review = check_role_in_domain(domain, role, ParticipantCapability.REVIEW.value, root)
    can_approve = check_role_in_domain(domain, role, ParticipantCapability.APPROVE.value, root)
    console.print(f"Role: {role}  Domain: {domain}")
    console.print("  May review:", can_review)
    console.print("  May approve:", can_approve)
    req, desc = escalation_required(domain, role, root)
    if req:
        console.print(f"  [yellow]Escalation required: {desc}[/yellow]")


@review_domains_group.command("explain")
def review_domains_explain_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Domain id to explain (who may review/approve, why blocked)"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Explain who may review, who may approve, and why a chain may be blocked or escalation required."""
    from workflow_dataset.review_domains.registry import get_domain
    from workflow_dataset.review_domains.explain import who_may_review, who_may_approve, why_escalation_required
    root = Path(repo_root).resolve() if repo_root else None
    d = get_domain(id, root)
    if not d:
        console.print(f"[red]Review domain not found: {id}[/red]")
        raise SystemExit(1)
    console.print(Panel.fit(f"[bold]{d.name}[/bold] — {d.domain_id}", title="Review domain"))
    reviewers = who_may_review(id, root)
    console.print("Who may review:")
    for r in reviewers:
        console.print(f"  - {r['role_id']}: {r.get('display_name', '')} — {r.get('description', '')}")
    approvers = who_may_approve(id, repo_root=root)
    console.print("Who may approve:", ", ".join(approvers) or "(none)")
    console.print("Self-approve blocked:", d.self_approve_blocked)
    for r in d.allowed_roles:
        reason = why_escalation_required(id, r.role_id, root)
        if reason:
            console.print(f"  Role {r.role_id} must escalate: {reason}")


@review_domains_group.command("policy")
def review_domains_policy_cmd(
    id: str = typer.Option(..., "--id", "-i", help="Domain id to show policy for (e.g. sensitive_gate)"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Show review-domain policy: separation of duties, initiator cannot approve, rationale."""
    from workflow_dataset.review_domains.policies import get_domain_policy
    root = Path(repo_root).resolve() if repo_root else None
    p = get_domain_policy(id, root)
    if not p:
        console.print(f"[yellow]No policy found for domain: {id}[/yellow]")
        return
    console.print(Panel.fit(f"[bold]{p.name}[/bold]\n{p.description}", title=p.policy_id))
    console.print("Separation of duties required:", p.separation_of_duties_required)
    console.print("Initiator cannot approve:", p.initiator_cannot_approve)
    console.print("Min distinct approvers:", p.min_distinct_approvers)
    console.print("Scope:", p.scope_note)
    console.print("Rationale:", p.policy_rationale)


