@trust_group.command("explain")
def trust_explain_cmd(
    routine: str = typer.Option(..., "--routine", "-r", help="Routine id to explain"),
    project: str = typer.Option("", "--project", "-p"),
    pack: str = typer.Option("", "--pack"),
    workflow: str = typer.Option("", "--workflow"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Explain trust/contract status for a routine: effective contract, tier, permitted/excluded, blocked."""
    from workflow_dataset.trust.explain_contract import explain_routine
    root = Path(repo_root).resolve() if repo_root else None
    context = {}
    if project:
        context["project_id"] = project
    if pack:
        context["pack_id"] = pack
    if workflow:
        context["workflow_id"] = workflow
    out = explain_routine(routine, context=context, repo_root=root)
    console.print(f"routine_id: {out['routine_id']}")
    console.print(f"contract_id: {out.get('contract_id') or '—'}")
    console.print(f"authority_tier_id: {out.get('authority_tier_id') or '—'}")
    console.print(f"blocked: {out.get('blocked', True)}")
    console.print(f"permitted: {out.get('permitted_action_classes', [])}")
    console.print(f"excluded: {out.get('excluded_action_classes', [])}")
    console.print(f"required_approvals: {out.get('required_approvals', [])}")
    console.print(f"explanation: {out.get('explanation', '')}")


