@deploy_group.command("bundle")
def deploy_bundle(
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Write bundle JSON to path (default: data/local/distribution/bundles/)"),
) -> None:
    """Define installable local product bundle from current profile; write to data/local/distribution/bundles/."""
    from workflow_dataset.distribution.bundle import build_install_bundle, write_install_bundle
    root = Path(repo_root) if repo_root else None
    bundle = build_install_bundle(repo_root=root)
    path = write_install_bundle(bundle, repo_root=root)
    if output:
        Path(output).write_text(path.read_text(encoding="utf-8"), encoding="utf-8")
        console.print(f"[green]Bundle written: {output}[/green]")
    else:
        console.print(f"[green]Bundle: {path}[/green]")
    console.print(f"  bundle_id={bundle.bundle_id}  version={bundle.version}")


@deploy_group.command("install-profile")
def deploy_install_profile(
    pack: str = typer.Option("", "--pack", "-p", help="Pack id (e.g. founder_ops_starter); default prints all pack ids"),
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Write profile/report to path"),
) -> None:
    """Generate pack-aware install profile or field deployment profile. Use --pack for one pack."""
    from workflow_dataset.distribution.install_profile import build_field_deployment_profile
    from workflow_dataset.distribution.checklists import list_checklist_packs
    root = Path(repo_root) if repo_root else None
    if not pack:
        console.print("[bold]Available packs:[/bold]", ", ".join(list_checklist_packs()))
        return
    profile = build_field_deployment_profile(pack, repo_root=root)
    text = f"Pack: {profile.pack_id}  Name: {profile.pack_name}\n"
    text += f"Runtime prereqs: {profile.runtime_prerequisites}\n"
    text += f"Pack provisioning: {profile.pack_provisioning_prerequisites}\n"
    text += f"Trust checks: {profile.trust_readiness_checks}\n"
    text += f"First-value run: {profile.first_value_run_command}\n"
    if output:
        Path(output).write_text(text, encoding="utf-8")
        console.print(f"[green]Wrote: {output}[/green]")
    else:
        console.print(text)


@deploy_group.command("update-plan")
def deploy_update_plan(
    repo_root: str = typer.Option("", "--repo-root"),
    desired: str = typer.Option("", "--desired", help="Path to desired state JSON (optional); default compares current to current"),
    output: str = typer.Option("", "--output", "-o", help="Write update plan to path"),
) -> None:
    """Compare current install state vs desired; show staged update plan (no execution)."""
    from workflow_dataset.distribution.update_planner import build_update_plan, format_update_plan
    root = Path(repo_root) if repo_root else None
    desired_state = None
    if desired and Path(desired).exists():
        import json
        desired_state = json.loads(Path(desired).read_text(encoding="utf-8"))
    plan = build_update_plan(repo_root=root, desired_state=desired_state)
    report = format_update_plan(plan)
    if output:
        Path(output).write_text(report, encoding="utf-8")
        console.print(f"[green]Wrote: {output}[/green]")
    else:
        console.print(report)


