@session_group.command("close")
def session_close(
    session_id: str = typer.Option("", "--id", "-i", help="Session id to close (default: current)"),
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """Close and archive a session. If --id omitted, closes current session."""
    from workflow_dataset.session import get_current_session, load_current_session_id, close_session
    root = Path(repo_root) if repo_root else None
    sid = session_id or load_current_session_id(root)
    if not sid:
        console.print("[yellow]No session id given and no current session.[/yellow]")
        raise typer.Exit(1)
    ok, errors = close_session(sid, repo_root=root)
    if errors:
        for e in errors:
            console.print(f"[red]{e}[/red]")
        raise typer.Exit(1)
    console.print(f"[green]Session closed: {sid}[/green]")


@session_group.command("list")
def session_list(
    repo_root: str = typer.Option("", "--repo-root"),
    limit: int = typer.Option(20, "--limit", "-n"),
    state: str = typer.Option("", "--state", help="Filter: open, closed, archived"),
) -> None:
    """List sessions (most recent first)."""
    from workflow_dataset.session.storage import list_sessions
    root = Path(repo_root) if repo_root else None
    sessions = list_sessions(root, limit=limit, state_filter=state or None)
    if not sessions:
        console.print("[dim]No sessions.[/dim]")
        return
    for s in sessions:
        cur = " (current)" if s.get("is_current") else ""
        console.print(f"  {s.get('session_id')}  pack={s.get('value_pack_id')}  state={s.get('state')}{cur}")


@session_group.command("templates")
def session_templates_list() -> None:
    """List session templates (morning_review, analyst_deep_work, founder_ops_session, developer_focus, document_review)."""
    from workflow_dataset.session.templates import list_session_templates, get_session_template
    ids = list_session_templates()
    for tid in ids:
        t = get_session_template(tid)
        name = t.name if t else tid
        pack = f"  pack={t.value_pack_id}" if t else ""
        console.print(f"  {tid}  {name}{pack}")


@session_group.command("cadence")
def session_cadence_cmd(
    cadence_id: str = typer.Argument("", help="Cadence id to show; if omitted, list all"),
) -> None:
    """List daily cadence flows, or show one: session cadence [daily_founder|daily_analyst|...]."""
    from workflow_dataset.session.cadence import list_cadence_flows, get_cadence_flow
    if not cadence_id:
        for cid in list_cadence_flows():
            c = get_cadence_flow(cid)
            console.print(f"  {cid}  {c.name if c else ''}")
        return
    c = get_cadence_flow(cadence_id)
    if not c:
        console.print(f"[yellow]Cadence not found: {cadence_id}[/yellow]")
        return
    console.print(f"[bold]{c.cadence_id}[/bold]  {c.name}")
    console.print(f"  {c.description}")
    for i, step in enumerate(c.steps, 1):
        console.print(f"  {i}. {step.label or step.template_id}  (template={step.template_id})")


