@runtime_group.command("summary")
def runtime_summary_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Write report to file"),
) -> None:
    """Summarize available backends and which product surfaces (task classes) depend on them."""
    from workflow_dataset.runtime_mesh.summary import build_runtime_summary, format_runtime_summary
    root = Path(repo_root) if repo_root else None
    summary = build_runtime_summary(root)
    report = format_runtime_summary(summary=summary)
    if output:
        Path(output).write_text(report, encoding="utf-8")
        console.print(f"[green]Wrote: {output}[/green]")
    else:
        console.print(report)


@runtime_group.command("validate")
def runtime_validate_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
    output: str = typer.Option("", "--output", "-o", help="Write report to file"),
    skip_models: bool = typer.Option(False, "--skip-models", help="Only validate task classes, not per-model"),
) -> None:
    """Validate model/runtime compatibility (task classes and optional per-model)."""
    from workflow_dataset.runtime_mesh.validate import run_runtime_validate, format_validation_report
    root = Path(repo_root) if repo_root else None
    result = run_runtime_validate(root, include_models=not skip_models)
    report = format_validation_report(result)
    if output:
        Path(output).write_text(report, encoding="utf-8")
        console.print(f"[green]Wrote: {output}[/green]")
    else:
        console.print(report)
    if not result.get("passed"):
        raise typer.Exit(1)


@runtime_group.command("profiles")
def runtime_profiles_cmd(
    repo_root: str = typer.Option("", "--repo-root"),
) -> None:
    """List backend profiles with status and install prerequisites (backend assumptions visible)."""
    from workflow_dataset.runtime_mesh.backend_registry import list_backend_profiles
    from workflow_dataset.runtime_mesh.policy import TASK_CLASS_POLICY
    root = Path(repo_root) if repo_root else None
    profiles = list_backend_profiles(root)
    console.print("[bold]Runtime backend profiles[/bold]")
    for p in profiles:
        console.print(f"  {p.backend_id}  family={p.backend_family}  status={p.status}  local={p.local}")
        for pr in (p.install_prerequisites or [])[:3]:
            console.print(f"    prereq: {pr}")
        if p.notes:
            console.print(f"    notes: {p.notes[:80]}...")
    task_prefs = {tc: pol.get("backend_preference") for tc, pol in TASK_CLASS_POLICY.items()}
    console.print("[bold]Task class → backend preference[/bold]")
    for tc, prefs in list(task_prefs.items())[:8]:
        console.print(f"  {tc}: {prefs}")


